\textbf{【方針】}
\text{分数を避けて平方完成する。}
\textbf{【解法】}
\text{両辺を4倍すると、}
\begin{aligned}
4x^2+4xy+8y^2 &= 44 \\
\Leftrightarrow (2x+y)^2+7y^2 &= 44
\end{aligned}
\text{ }(2x+y)^2 = 44 - 7y^2\text{ より }44-7y^2\ge0\Leftrightarrow |y|\le2
\text{※} (2x+y)^2 \text{は平方数なので、}y=2, -2 \text{のときを調べる。)}y=0\text{のときは、}44-0 =44, y=1\text{のときは} 44-7=37 \text{なので、平方数ではない。}

\textbf{【解法】}
\text{部分積分を用いる。}
\begin{aligned}
\int_0^{\pi} x \cos x \, dx &= \int_0^{\pi} x \cdot (\sin x)' \, dx \\
&= \left[x \sin x\right]_0^{\pi} - \int_0^{\pi} \sin x \, dx \\
&= \pi \cdot 0 - 0 - \left[-\cos x\right]_0^{\pi} \\
&= 0 - (-\cos \pi + \cos 0) \\
&= -(1 + 1) \\
&= -2
\end{aligned}

\textcolor{brown}{\large{【力学】}}
\text{• 力学の空気抵抗を受ける質点の速度減衰は} v^{\prime}(t) + \displaystyle \frac{k}{m}v(t) = 0 \text{ でモデル化される。速度は指数関数的に減少する。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• RC放電。コンデンサの電荷の指数関数的減少。}
\text{• 電磁気学のRC回路においては、キルヒホッフの第二法則より、}
      RI(t) + \displaystyle \frac{Q(t)}{C} = 0 \text{が成り立ち、これを}R\text{で割って両辺微分すると、}
      I^{\prime}(t) + \displaystyle \frac{1}{RC}I(t) = 0 \text{ を得る。これはRC回路の放電過程の回路に流れる電流の時間変化を表す。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{空気抵抗下での質点の運動:} \ v^{\prime}(t) + \displaystyle \frac{k}{m}v(t) = 0
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } 2 \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } f_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RC回路の放電:} \ I^{\prime}(t) + \displaystyle \frac{1}{RC}I(t) = 0
\text{• } f(t) \leftrightarrow I(t) \text{（電流）}
\text{• } 2 \leftrightarrow \displaystyle \frac{1}{RC} \text{（時定数の逆数）}
\text{• } f_0 \leftrightarrow I_0 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t) + 2f(t) = 0
\text{両辺に}e^{2t}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{2t}f^{\prime}(t) + 2e^{2t}f(t) = 0
\text{積の微分より}
\Leftrightarrow (e^{2t}f(t))' = 0
\text{両辺を }0 \text{ から }t \text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t (e^{2s}f(s))'\,ds = \int_0^t 0\,ds\\[5pt]
&\Leftrightarrow [e^{2s}f(s)]_{0}^{t} = 0\\[5pt]
&\Leftrightarrow \ e^{2t}f(t) - e^0 f(0) = 0\\[5pt]
&\Leftrightarrow \ e^{2t}f(t) = f(0)
\end{aligned}
\text{初期条件より} f(0) = f_0 \text{なので、}
\Leftrightarrow \ e^{2t}f(t) = f_0
\Leftrightarrow \ f(t) = f_0e^{-2t}
\text{この解は指数減衰関数で、減衰定数 }2\text{ で指数関数的に減少する。}

\textcolor{brown}{\large{【電磁気学】}}
\text{• RLC直列交流回路について、キルヒホッフの第二法則を用いると }
  LQ^{\prime\prime}(t) + RQ^{\prime}(t) + \displaystyle \frac{Q(t)}{C} = V_0\sin(\omega t) \text{が成り立つ。}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RLC直列交流回路の過渡応答:} \ LQ^{\prime\prime}(t) + RQ^{\prime}(t) + \displaystyle \frac{Q(t)}{C} = V_0\sin(\omega t)
\text{• } f(t) \leftrightarrow Q(t) \text{（コンデンサに蓄えられた電荷）}
\text{• } f^{\prime}(t) \leftrightarrow Q^{\prime}(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow Q^{\prime\prime}(t) \text{（電流変化率）}
\text{• } \alpha \leftrightarrow L \text{（インダクタンス）}
\text{• } 2\beta \leftrightarrow R \text{（抵抗）}
\text{• } \gamma \leftrightarrow \displaystyle \frac{1}{C} \text{（静電容量の逆数）}
\text{• } \frac{\gamma}{\alpha} \leftrightarrow \frac{1}{LC} = \omega_0^2 \text{（固有角周波数の2乗）}
\text{• } \sqrt{\frac{\gamma}{\alpha} - \frac{\beta^2}{\alpha^2}} \leftrightarrow \sqrt{\displaystyle \frac{1}{LC} - \left(\displaystyle \frac{R}{2L}\right)^2} \text{（減衰角周波数）}
\text{• } F \leftrightarrow \displaystyle V_0 \text{（電圧振幅}
\text{• } \omega \leftrightarrow \omega \text{交流電圧周波数}
\text{• 定常状態の }f^{\prime}(t)\text{ の振幅と }F\text{ との比(インピーダンス)：} \textcolor{blue}{\displaystyle \frac{F}{f'_{max}} = \sqrt{\left(\frac {\gamma}{\omega} -\alpha\omega\right)^2+4\beta^2} \leftrightarrow  |Z| = \frac {V_0}{I_{max}} = {\sqrt{\left(\frac{1}{\omega C} - \omega L \right) ^2 + R^2}}}
\text{• 定常状態の }f^{\prime}(t)\text{ と右辺の }F\sin(\omega t)\text{ との位相差：}\tan \phi = \frac{\omega\alpha- \frac {\gamma}{\omega}}{2\beta} \leftrightarrow \tan \phi = \frac{\omega L -\frac{1}{\omega C}}{R} \text{（電流と電圧の位相差）}
\text{• } f_0 = 0 \leftrightarrow Q_0 = 0 \text{（コンデンサの初期電荷）}
\text{• } v_0 = 0 \leftrightarrow I_0 = 0 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
\textbf{【方針】}
\text{未定係数法で特解を求めて、それを引いた関数を新たに定義し、下記の右辺0(同次方程式)の場合の公式を適用して解く。}
\textcolor{blue}{微分方程式 } \textcolor{blue}{\alpha f^{\prime\prime}(t) + 2\beta f^{\prime}(t) + \gamma f(t) = 0} \textcolor{blue}{ に対する初期値問題} \textcolor{blue}{f(0) = f_0,\quad f^{\prime}(0) = v_0} \textcolor{blue}{の解は下記のように表される。(問題12)}
\textcolor{blue}{f(t) = e^{-\frac{\beta}{\alpha} t}\left(f_0\cos\left(\sqrt{\frac{\gamma}{\alpha} - \frac{\beta^2}{\alpha^2}}\ \,t\right) + \frac{v_0 + \frac{\beta}{\alpha} f_0}{\sqrt{\frac{\gamma}{\alpha} - \frac{\beta^2}{\alpha^2}}}\sin\left(\sqrt{\frac{\gamma}{\alpha} - \frac{\beta^2}{\alpha^2}}\ \,t\right)\right)}
\textcolor{green}{1.\ } \textcolor{green}{\frac{F}{\sqrt{(\gamma-\alpha\omega^2)^2+4\beta^2\omega^2}}\sin(\omega t + \theta)} \textcolor{green}{ は本問の微分方程式を満たす。ただし、} \textcolor{green}{\tan \theta =\frac{2\beta\omega}{\gamma-\alpha\omega^2}}
\textcolor{purple}{【証明】}
\text{右辺の形 }F\sin(\omega t)\text{ を参考に、方程式を満たす1つの解(特解)を}
f_p(t) = A\sin(\omega t) + B\cos(\omega t) \text{の形で推定する。ただし、}A, B \text{は時間によらない定数である。}
\text{まず、}f_p(t)\text{ を微分する：}
\begin{aligned}
  \begin{cases}
  f_p^{\prime}(t) = \omega A\cos(\omega t) - \omega B\sin(\omega t) \\[5pt]
  f_p^{\prime\prime}(t) = -\omega^2 A\sin(\omega t) - \omega^2 B\cos(\omega t)
  \end{cases}
  \end{aligned}
\text{これを }\alpha f_p^{\prime\prime}(t) + 2\beta f_p^{\prime}(t) + \gamma f_p(t) = F\sin(\omega t)\cdots (1)
\text{ に代入してsin,cosの係数を比較すると、}
\text{cosの係数：}2\beta\omega A + (\gamma - \alpha\omega^2)B = 0
\text{sinの係数：}(\gamma - \alpha\omega^2)A - 2\beta\omega B = F
\text{となる。(※ (1)はtについての恒等式なので両辺のsinの係数とcosの係数を比較したら良い。)}
\text{sinの係数比較の式より }B = -\frac{2\beta\omega A}{\gamma - \alpha\omega^2}\text{ を第1式に代入して、A,Bを求めると下記のようになる。}
\begin{aligned}
  &\ \ \ \ \ \ (\gamma - \alpha\omega^2)A - 2\beta\omega \cdot \left(-\frac{2\beta\omega A}{\gamma - \alpha\omega^2}\right) = F \\[5pt]
  &\Leftrightarrow \ \frac{(\gamma - \alpha\omega^2)^2 + 4\beta^2\omega^2}{\gamma - \alpha\omega^2}A = F \\[5pt]
  &\Leftrightarrow \ A = \frac{F(\gamma - \alpha\omega^2)}{(\gamma - \alpha\omega^2)^2 + 4\beta^2\omega^2} \\[5pt]
  &\text{よって、}\  B = -\frac{2\beta\omega F}{(\gamma - \alpha\omega^2)^2 + 4\beta^2\omega^2}\end{aligned}
\text{ゆえに特解は、}
f_p(t) = \dfrac{F(\gamma - \alpha\omega^2)}{(\gamma - \alpha\omega^2)^2 + 4\beta^2\omega^2}\sin(\omega t) - \frac{2\beta\omega F}{(\gamma - \alpha\omega^2)^2 + 4\beta^2\omega^2}\cos(\omega t)
\textcolor{purple}{(i)\ \omega = \sqrt{\frac{\gamma}{\alpha}}} \textcolor{purple}{の場合}
\text{sinの部分は係数が0になるので、}
\textcolor{red}{\begin{aligned}
  f_p(t) &= - \frac{2\beta\omega F}{4\beta^2\omega^2}\cos(\omega t)\\[5pt]
  &= - \frac{F}{2\beta \omega}\cos(\omega t) \\[5pt]
  &= - \frac{F}{2\beta \omega}\sin(\omega t + \frac{\pi}{2})\\[5pt]
  &= \frac{F}{2\beta \omega}\sin\left(\omega t - \frac{\pi}{2}\right)
  \end{aligned}}
\textcolor{purple}{(ii)\  \omega \neq \sqrt{\frac{\gamma}{\alpha}}} \textcolor{purple}{の場合}
\text{三角関数の合成をして、}
\text{振幅：} \sqrt{\left(\frac{F(\gamma-\alpha\omega^2)}{(\gamma-\alpha\omega^2)^2+4\beta^2\omega^2}\right)^2 + \left(\frac{2\beta\omega F}{(\gamma-\alpha\omega^2)^2+4\beta^2\omega^2}\right)^2} = \frac{F}{\sqrt{(\gamma-\alpha\omega^2)^2+4\beta^2\omega^2}}
\text{位相角：}\theta \ ;\ \left( \tan \theta =\frac{2\beta\omega}{\gamma-\alpha\omega^2}\right) \text{ を用いて、整理すると、下記の解を得られる。}
\textcolor{blue}{f_p(t) = \frac{F}{\sqrt{(\gamma-\alpha\omega^2)^2+4\beta^2\omega^2}}\sin(\omega t + \theta)}
\textcolor{green}{3.} \textcolor{green}{f(t)} \textcolor{green}{を平行移動した関数} \textcolor{green}{g(t) = f(t) - f_p(t)} \textcolor{green}{を置く}
f_p(t) \text{は微分方程式の解なので、} \alpha f_p^{\prime\prime}(t) + 2\beta f_p^{\prime}(t) + \gamma f_p(t) = F\sin(\omega t)\text{ を満たす。この式を本問の微分方程式と連立して引き算を行う。}
\text{これらを引き算すると、}
\begin{aligned}
  &\quad \alpha f^{\prime\prime}(t) + 2\beta f^{\prime}(t) + \gamma f(t) = F\sin(\omega t) \\
  -&\quad \alpha f_p^{\prime\prime}(t) + 2\beta f_p^{\prime}(t) + \gamma f_p(t) = F\sin(\omega t) \\[5pt]
  \hline \\
  &\quad \alpha(f^{\prime\prime}(t) - f_p^{\prime\prime}(t)) + 2\beta(f^{\prime}(t) - f_p^{\prime}(t)) + \gamma(f(t) - f_p(t)) = 0
  \end{aligned}
\text{平行移動：} g(t) = f(t) - f_p(t) \text{ とおくと、} \alpha g^{\prime\prime}(t) + 2\beta g^{\prime}(t) + \gamma g(t
