\textbf{【方針】}
\text{恒等式 } a^3 + b^3 = (a+b)^3 - 3ab(a+b) \text{ を2回使う。}
\textbf{【途中式変形】}
\text{1回目： } x^3 + y^3 = (x+y)^3 - 3xy(x+y) \text{ より、}
\begin{aligned}
&\ \ \ \ x^3 + y^3 + z^3 - 3xyz \\
&= (x + y)^3 - 3xy(x + y) + z^3 - 3xyz \\
&= (x + y)^3 + z^3 - 3xy(x + y + z)
\end{aligned}
\text{2回目： } x + y = A \text{ と置くと、}
\begin{aligned}
&\ \ \ \ A^3 + z^3 - 3xy(A + z) \\
&= (A + z)^3 - 3Az(A + z) - 3xy(A + z) \\
&= (A + z)\{(A + z)^2 - 3Az - 3xy\} \\
&= (A + z)(A^2 + 2Az + z^2 - 3Az - 3xy) \\
&= (A + z)(A^2 - Az + z^2 - 3xy)
\end{aligned}
\text{ } A = x + y \text{ に戻すと、}
\begin{aligned}
&= (x + y + z)\{(x + y)^2 - (x + y)z + z^2 - 3xy\} \\
&= (x + y + z)(x^2 + 2xy + y^2 - xz - yz + z^2 - 3xy) \\
&= (x + y + z)(x^2 + y^2 + z^2 - xy - yz - zx)
\end{aligned}

\textbf{【方針】 } \displaystyle \sum_{k=1}^{n}k^{2}=\dfrac{n(n+1)(2n+1)}{6}\ を用いる
\begin{aligned}
        \frac{1}{n^{3}}\displaystyle \sum_{k=1}^{n}k^{2}
        &= \frac{1}{n^{3}}\cdot \frac{n(n+1)(2n+1)}{6} \\[6pt]
        &= \frac{1}{6}\cdot \frac{(n+1)(2n+1)}{n^{2}} \\[6pt]
        &= \frac{1}{6}\cdot \frac{2n^{2}+3n+1}{n^{2}} \\[6pt]
        &= \frac{1}{6}\left(2+\frac{3}{n}+\frac{1}{n^{2}}\right) \\[6pt]
        &\underset{n\to\infty}{\longrightarrow}\  \displaystyle \frac{1}{6} \cdot 2 = \frac{1}{3}
      \end{aligned}

\textbf{【方針】}
\text{右辺が1次式なので解の一つを1次関数}  An + B \text{ の形で求め、これを使ってただの等比数列の式に帰着させる。}
\textbf{【解法】}
\text{解の形を} An + B \text{と仮定して、元の漸化式に代入すると、}
\begin{aligned}
    \ \ \ \ \ A(n+1) + B &= 2(An + B) + n + 1 \\
    \Leftrightarrow An + A + B &= 2An + 2B + n + 1 \\
    \Leftrightarrow An + A + B &= (2A + 1)n + 2B + 1
    \end{aligned}
\text{係数を比較すると、} A = 2A + 1, \ A + B = 2B + 1 \text{ より、} A = -1, \ B = -2 \text{ である。}
\text{よって、解の一つは } -n - 2 \text{ である。}
\text{求まった解を元の漸化式に代入すると、} -(n+1) - 2 = 2(-n - 2) + n + 1 \cdots (1) \text{ である。}
\text{ここで、元の漸化式から(1)を引いて、新たな数列}b_n = a_n + n + 2\text{ を定義すると、等比数列の形に帰着させることができる。実際、}
\begin{aligned}
      a_{n+1} &= 2a_n + n + 1 \\
      -(n+1) - 2 &= 2(-n - 2) + n + 1 \\
      \hline
      \ \ \ \ \ a_{n+1} - (-(n+1) - 2) &= 2a_n + n + 1 - (2(-n - 2) + n + 1) \\
      \Leftrightarrow a_{n+1} + (n+1) + 2 &= 2a_n + n + 1 - 2(-n - 2) - n - 1 \\
      \Leftrightarrow a_{n+1} + (n+1) + 2 &= 2(a_n + n + 2)
      \end{aligned}
\text{ } b_n = a_n + n + 2 \text{ とおくと、} b_{n+1} = 2b_n \text{ である。}
\text{ } a_1 = 1 \text{ より、} b_1 = a_1 + 1 + 2 = 1 + 1 + 2 = 4 \text{ だから、}
\begin{aligned}
    \begin{cases}
    \ b_{n+1} = 2b_n \\
    \ b_1 = 4
    \end{cases}
    \end{aligned}
\text{上の漸化式は等比数列の形で、} b_n = 4 \cdot 2^{n-1} = 2^{n+1} \text{ なので、}
\begin{aligned}
    &\ \ \ \ \ a_n = b_n - n - 2 \\
    &\Leftrightarrow a_n = 2^{n+1} - n - 2
    \end{aligned}

\textbf{【方針】}
\text{三角置換 } x = 2\tan\theta \text{ を用いて、被積分関数を簡略化する。}
\textbf{【解説】}
\text{ } x = 2\tan\theta \text{ とおくと、}
\begin{aligned}
x = 0 &\Rightarrow 0 = 2\tan\theta \Rightarrow \theta = 0\\[5pt]
x = 2 &\Rightarrow 2 = 2\tan\theta \Rightarrow \tan\theta = 1 \Rightarrow \theta = \frac{\pi}{4}
\end{aligned}
\text{また、}
\begin{aligned}\begin{cases}
dx = 2(\tan\theta)' \, d\theta = 2 \cdot \frac{1}{\cos^2\theta} \, d\theta = 2(1+\tan^2\theta) \, d\theta\\[5pt]
(4+x^2)^{\frac{3}{2}} = [4(1+\tan^2\theta)]^{\frac{3}{2}} = 8(1+\tan^2\theta)^{\frac{3}{2}}
\end{cases}\end{aligned}
\text{したがって、}
\begin{aligned}
\int_{0}^{2} \frac{dx}{(4+x^2)^{\frac{3}{2}}}
&= \int_{\theta=0}^{\theta=\frac{\pi}{4}} \frac{2(1+\tan^2\theta)\,d\theta}{8(1+\tan^2\theta)^{\frac{3}{2}}}\\[5pt]
&= \int_{0}^{\frac{\pi}{4}} \frac{1+\tan^2\theta}{4(1+\tan^2\theta)^{\frac{3}{2}}} \, d\theta\\[5pt]
&= \frac{1}{4}\int_{0}^{\frac{\pi}{4}} \frac{1}{(1+\tan^2\theta)^{\frac{1}{2}}} \, d\theta
\end{aligned}
\text{ここで、} 1+\tan^2\theta = \frac{1}{\cos^2\theta} \text{ より、} (1+\tan^2\theta)^{\frac{1}{2}} = \frac{1}{|\cos\theta|} = \frac{1}{\cos\theta} \text{（} 0 \leq \theta \leq \frac{\pi}{4} \text{ では } \cos\theta > 0 \text{）}
\begin{aligned}
\frac{1}{4}\int_{0}^{\frac{\pi}{4}} \frac{1}{(1+\tan^2\theta)^{\frac{1}{2}}} \, d\theta
&= \frac{1}{4}\int_{0}^{\frac{\pi}{4}} \cos\theta \, d\theta\\[5pt]
&= \frac{1}{4}\left[\sin\theta\right]_{0}^{\frac{\pi}{4}}\\[5pt]
&= \frac{1}{4}\left(\sin\frac{\pi}{4} - \sin 0\right)\\[5pt]
&= \frac{1}{4} \cdot \frac{\sqrt{2}}{2}\\[5pt]
&= \frac{\sqrt{2}}{8}
\end{aligned}

