\textbf{【方針】}
\text{互除法を用いて } 842x + 495y = 1 \text{ を満たす解を1つ求める。}
\textbf{【解法】}
\text{互除法により、}
\begin{aligned}
842 &= 495 \cdot 1 + 347 \\
495 &= 347 \cdot 1 + 148 \\
347 &= 148 \cdot 2 + 51 \\
148 &= 51 \cdot 2 + 46 \\
51 &= 46 \cdot 1 + 5 \\
46 &= 5 \cdot 9 + 1 \\
5 &= 1 \cdot 5 + 0
\end{aligned}
\text{逆算すると、}
\begin{aligned}
1 &= 46 - 5 \cdot 9 \\
&= 46 - (51 - 46) \cdot 9 \\
&= 46 \cdot 10 - 51 \cdot 9 \\
&= (148 - 51 \cdot 2) \cdot 10 - 51 \cdot 9 \\
&= 148 \cdot 10 - 51 \cdot 29 \\
&= 148 \cdot 10 - (347 - 148 \cdot 2) \cdot 29 \\
&= 148 \cdot 68 - 347 \cdot 29 \\
&= (495 - 347) \cdot 68 - 347 \cdot 29 \\
&= 495 \cdot 68 - 347 \cdot 97 \\
&= 495 \cdot 68 - (842 - 495) \cdot 97 \\
&= 842 \cdot (-97) + 495 \cdot 165
\end{aligned}
\text{よって、 } 842 \cdot (-97) + 495 \cdot 165 = 1 \text{ であるから、}
\text{1つの解は } (x_0, y_0) = (-97, 165) \text{ である。}
\text{よって} 842\cdot (-97) + 495\cdot 165 = 1
\text{ここで、元の式} 842x + 495y = 1 \text{から} 842\cdot (-97) + 495\cdot 165 = 1 \text{を引くと、}
\begin{aligned}
      842x + 495y = 1 \\
      842 \cdot (-97) + 495 \cdot 165 = 1 \\
      \hline
      842(x + 97) + 495(y - 165) = 0 
      \end{aligned}
842,495 \text{は互いに素なので} x+97 = 495k \text{ と } y-165 = -842k \text{となる整数} k \text{が存在する。よって、}
\begin{aligned}
      &\ \ \ \ \  \begin{cases}
      x + 97 = 495k \\
      y - 165 = -842k
      \end{cases} \\
      &\Leftrightarrow \begin{cases}
      x = 495k - 97 \\
      y = -842k + 165
      \end{cases}
      \end{aligned} \quad (kは整数)

\textbf{【方針】}
\; x=\sin^{2}\theta \,\textbf{と置換する。}
\textbf{【解説】}
x=\sin^{2}\theta \text{と置くと、} x=\displaystyle \frac{1}{4}\rightarrow \displaystyle \frac{3}{4} \text{の時、} \sin^{2}\theta=\displaystyle \frac{1}{4}\rightarrow \displaystyle \frac{3}{4} \text{より、} \sin\theta=\displaystyle \frac{1}{2}\rightarrow \displaystyle \frac{\sqrt{3}}{2} \text{なので、} \theta=\displaystyle \frac{\pi}{6}\rightarrow \displaystyle \frac{\pi}{3} \text{と対応させる。}
\text{また、}
\begin{aligned}
      \sqrt{x(1-x)}=&\sqrt{\sin^{2}\theta(1-\sin^{2}\theta)} \\
      =& |\sin \theta \cos \theta|\\
      \underset{\frac{\pi}{6}\le \theta \le \frac{\pi}{3} }{=}&\sin \theta \cos \theta
      \end{aligned}
\text{さらに、}dx= \displaystyle \frac{dx}{d\theta}d\theta = 2\sin \theta \cos \theta d\theta \text{となるので、}
\begin{aligned}
\displaystyle \int_{\frac{1}{4}}^{\frac{3}{4}} \displaystyle \frac{dx}{\sqrt{x(1-x)}}
=&\displaystyle \int_{\frac{\pi}{6}}^{ \frac{\pi}{3}} \displaystyle \frac{2\sin\theta\cos\theta\,d\theta}{\sin\theta\cos\theta}\\
=&\displaystyle \int_{\frac{\pi}{6}}^{ \frac{\pi}{3}}2\,d\theta\\
=&\left.2\theta\right|_{\frac{\pi}{6}}^{ \frac{\pi}{3}}\\
=&2\left(\displaystyle \frac{\pi}{3}-\displaystyle \frac{\pi}{6}\right)\\
=&2 \cdot \displaystyle \frac{\pi}{6}\\
=&\displaystyle \frac{\pi}{3}
\end{aligned}
\textbf{【補足】}
\text{大学ではベータ関数}B\!\left(\displaystyle \frac{1}{2},\displaystyle \frac{1}{2}\right)=\pi \text{として登場する。}

\textbf{【ポイント】}
\log x = (x)'\log {x} \text{とみなして、部分積分の公式を用いる。}
\begin{aligned}
&\displaystyle \int \log x\,dx = \displaystyle \int (x)' \log x\,dx 
&= x\log x - \displaystyle \int x\cdot\displaystyle \frac{1}{x}\,dx \\
&\phantom{\displaystyle \int \log x\,dx } = x\log x - \displaystyle \int 1\,dx \\
&\phantom{\displaystyle \int \log x\,dx } = x\log x - x + C
\end{aligned}
\textbf{【計算】}
\begin{aligned}
\displaystyle \int_{1}^{e} \log x\,dx
&= \left[x\log x - x\right]_{x=1}^{x=e} \\
&= \left(e\cdot \log e - e\right) - \left(1\cdot \log 1 - 1\right) \\
&= \left(e\cdot 1 - e\right) - \left(1\cdot 0 - 1\right) \\
&= (e-e) - (0-1) \\
&= 1
\end{aligned}

\textbf{【方針】}
\; u=1+x^{2} \,\textbf{と置く。}
\textbf{【解説】}
du=2x\,dx \,\textbf{なので}
\text{積分範囲の変換：}
\begin{aligned}
\begin{cases}
x=0 \Leftrightarrow u=1+0^{2}=1,\\[5pt]
x=\sqrt{3} \Leftrightarrow u=1+(\sqrt{3})^{2}=1+3=4
\end{cases}
\end{aligned}
\begin{aligned}
\displaystyle \int_{0}^{\sqrt{3}} \displaystyle \frac{x}{\sqrt{1+x^{2}}}\,dx
=&\displaystyle \int_{0}^{\sqrt{3}} \displaystyle\frac1 2 \frac{2x}{\sqrt{1+x^{2}}}\,dx\\
=&\displaystyle \displaystyle \frac{1}{2} \int_{1}^{4} \displaystyle \frac{1}{\sqrt{u}}\cdot \,du\\
=&\displaystyle \frac{1}{2}\displaystyle \int_{1}^{4} u^{- \frac{1}{2}}\,du\\
=&\displaystyle \frac{1}{2}\left[\displaystyle \frac{u^{ \frac{1}{2}}}{\displaystyle \frac{1}{2}}\right]_{1}^{4}\\
=&\left[\sqrt{u}\right]_{1}^{4}\\
=&\sqrt{4}-\sqrt{1}\\
=&2-1\\
=&1
\end{aligned}

\textbf{【方針】}
\; \textbf{被積分関数は偶関数なので }\left[-1,1\right] を \left[0,1\right] の2倍にし、(1-x^2)^3 を展開して項別に積分する。
\textbf{【展開】}
\;(1-x^{2})^{3}=1-3x^{2}+3x^{4}-x^{6}
\textbf{【計算】}
\text{被積分関数は偶関数なので、}
\begin{aligned}
&\ \ \ \ \ \ \displaystyle \int_{-1}^{1}(1-x^{2})^{3}\,dx\\
&= 2\displaystyle \int_{0}^{1}(1-x^{2})^{3}\,dx\\[4pt]
&= 2\displaystyle \int_{0}^{1}\bigl(1-3x^{2}+3x^{4}-x^{6}\bigr)\,dx\\[4pt]
&= 2\left(\displaystyle \int_{0}^{1}1\,dx
-3\displaystyle \int_{0}^{1}x^{2}\,dx
+3\displaystyle \int_{0}^{1}x^{4}\,dx
-\displaystyle \int_{0}^{1}x^{6}\,dx\right)
\end{aligned}
\begin{alignedat}{2}
    &\displaystyle \int_{0}^{1}1\,dx &&= 1\\[4pt]
    &\displaystyle \int_{0}^{1}x^{2}\,dx &&= \dfrac{1}{3}\\[4pt]
    &\displaystyle \int_{0}^{1}x^{4}\,dx &&= \dfrac{1}{5}\\[4pt]
    &\displaystyle \int_{0}^{1}x^{6}\,dx &&= \dfrac{1}{7}
\end{alignedat}\text{　なので、}
\begin{aligned}
\displaystyle \int_{-1}^{1}(1-x^{2})^{3}\,dx
&= 2\left(1 -3\cdot \dfrac{1}{3} +3\cdot \dfrac{1}{5} - \dfrac{1}{7}\right)\\[6pt]
&= 2\left(1-1+\dfrac{3}{5}-\dfrac{1}{7}\right)\\[6pt]
&= 2\left(\dfrac{3}{5}-\dfrac{1}{7}\right)\\[6pt]
&= 2\cdot \dfrac{3\cdot7-1\cdot5}{35}\\[6pt]
&= 2\cdot \dfrac{21-5}{35}\\[6pt]
&= 2\cdot \dfrac{16}{35}\\[6pt]
&= \dfrac{32}{35}
\end{aligned}
\textbf{【補足(ガンマ関数)】}
大学で習うガンマ関数を用いると、一般に
// \displaystyle \int_{-1}^{1}(1-x^{2})^{\frac{n}{2}}\,dx
// =\sqrt{\pi}\,\dfrac{\Gamma\!\left(\dfrac{n+2}{2}\right)}{\Gamma\!\left(\dfrac{n+3}{2}\right)}.
//
// \(n=6\) \text{を代入すると}
// \[
// \sqrt{\pi}\,\dfrac{\Gamma(4)}{\Gamma\!\left(\frac{9}{2}\right)}
// =\sqrt{\pi}\,\dfrac{3!}{\dfrac{105}{16}\sqrt{\pi}}
// =\dfrac{6\cdot16}{105}
// =\dfrac{96}{105}
// =\dfrac{32}{35},
// \]
// となり、上の多項式展開による結果と一致する。

\textbf{【方針】}
f(x) = x^4 + 9x^3 + 16x^2 - x - 3\text{とおいて、まずは、因数定理を用い、候補（±1, ±3）を代入して、1次式の因数を持たないことを認識したら、その後、2次式×2次式の形で係数比較を行うのが自然。}
\textbf{【途中式変形】}
\text{因数定理の候補を代入すると、}
\begin{aligned}
f(1) &= 1 + 9 + 16 - 1 - 3 = 22 \neq 0 \\
f(-1) &= 1 - 9 + 16 + 1 - 3 = 6 \neq 0 \\
f(3) &= 81 + 243 + 144 - 3 - 3 = 462 \neq 0 \\
f(-3) &= 81 - 243 + 144 + 3 - 3 = -18 \neq 0
\end{aligned}
\text{よって、1次式の因数を持たない。よって2次式×2次式の因数分解を探す。}
\text{整数係数で } f(x) = (x^2 + ax + b)(x^2 + cx + d) \text{ とおく。}
\textcolor{red}{実は計算すると、下記のように計算できる。}
\textcolor{red}{a = 2,\ b = -1,\ c = 7,\ d = 3}
\textcolor{red}{以下ではこの証明を行う。}
\textbf{【証明】}
\text{ここで } x^4 + 9x^3 + 16x^2 - x - 3 \text{ の定数項が } -3 \text{ であることから、 } (b, d) = (1, -3), (-1, 3) \text{ の場合に分けて解を探す。}
\textcolor{blue}{1. } \textcolor{blue}{(b, d) = (1, -3)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax + 1)(x^2 + cx - 3) \text{ とおくと、}
\begin{aligned}
x^4 + 9x^3 + 16x^2 - x - 3 &= (x^2 + ax + 1)(x^2 + cx - 3) \\
&= x^4 + (a+c)x^3 + (ac - 2)x^2 + (-3a + c)x - 3
\end{aligned}
\text{係数比較より、}
\begin{aligned}
&\text{3次: } a + c = 9\ \cdots (1) \\[2pt]
&\text{2次: } ac - 2 = 16\ \ \cdots (2) \\[2pt]
&\text{1次: } -3a + c = -1\ \ \cdots (3)
\end{aligned}
\text{(2),(1) より } ac = 18, a + c = 9 \text{ であるから、}
\text{ } (a = 6, c = 3) \text{ または } (a = 3, c = 6) \text{ を得る。}
\text{これを(3)に代入すると、}
-3a + c = -3 \cdot 6 + 3 = -15
-3a + c = -3 \cdot 3 + 6 = -3
\textcolor{red}{よって、これらはいずれも -1 にならず、(3)を満たさない。}
\textcolor{blue}{2. } \textcolor{blue}{(b, d) = (-1, 3)}\textcolor{blue}{ の場合}
\text{ } f(x) = (x^2 + ax - 1)(x^2 + cx + 3) \text{ とおくと、}
\begin{aligned}
x^4 + 9x^3 + 16x^2 - x - 3 &= (x^2 + ax - 1)(x^2 + cx + 3) \\
&= x^4 + (a+c)x^3 + (ac + 2)x^2 + (3a - c)x - 3
\end{aligned}
\text{係数比較より、}
\begin{aligned}
&\text{3次: } a + c = 9\ \cdots (1) \\[2pt]
&\text{2次: } ac + 2 = 16\ \ \cdots (2) \\[2pt]
&\text{1次: } 3a - c = -1\ \ \cdots (3)
\end{aligned}
\text{(2),(1) より } ac = 14, a + c = 9 \text{ であるから、}
\text{ } (a = 7, c = 2) \text{ または } (a = 2, c = 7) \text{ を得る。}
\text{これを(3)に代入すると、}
3a - c = 3 \cdot 7 - 2 = 19
3a - c = 3 \cdot 2 - 7 = -1
\text{よって、1つ目は 19 になり -1 にならず、(3)を満たさない。2つ目は -1 になり、(3)を満たす。}
\textcolor{green}{したがって、 }(a, b, c, d) = (2, -1, 7, 3)\text{である。}
\textcolor{green}{\begin{aligned}
x^4 + 9x^3 + 16x^2 - x - 3 &= (x^2 + 2x - 1)(x^2 + 7x + 3)
\end{aligned}}

\textcolor{brown}{\large{【電磁気学】}}
\text{• RLC直列回路について、キルヒホッフの第二法則を用いると }
  LQ^{\prime\prime}(t) + RQ^{\prime}(t) + \displaystyle \frac{Q(t)}{C} = 0 \text{が成り立つ。}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RLC直列回路の過渡応答:} \ LQ^{\prime\prime}(t) + RQ^{\prime}(t) + \displaystyle \frac{Q(t)}{C} = 0
\text{• } f(t) \leftrightarrow Q(t) \text{（コンデンサに蓄えられた電荷）}
\text{• } f^{\prime}(t) \leftrightarrow Q^{\prime}(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow Q^{\prime\prime}(t) \text{（電流変化率）}
\text{• } \dfrac {6} {2 \cdot 1} = 3 \leftrightarrow \displaystyle \frac{R}{2L} \text{（減衰定数）}
\text{• } \dfrac {1}{\sqrt{1 \cdot \frac {1} {10}}} = \sqrt{10} \leftrightarrow \displaystyle \frac{1}{\sqrt{LC}} \text{（減衰定数が0の場合の固有角周波数）}
\text{• } \sqrt{\frac {1} {1 \cdot \frac {1} {10}} -  \left(\frac {6} {2 \cdot 1}\right) ^2} = 1 \leftrightarrow \sqrt{\displaystyle \frac{1}{LC} - \left(\displaystyle \frac{R}{2L}\right)^2} \text{（減衰角周波数）}
\text{• } 1 \leftrightarrow Q_0 \text{（初期電荷）}
\text{• } 2 \leftrightarrow I_0 \text{（初期電流）}
\textcolor{brown}{\large{【物理的意味】}}
\text{• 包絡線: } e^{-\frac {6} {2 \cdot 1} t} = e^{-3t} \text{ で指数的に減衰しながら振動}
\text{• 振動周波数: } \sqrt{10 -  \left(\frac {6} {2 \cdot 1}\right) ^2} = 1 \text{ （自然周波数}\sqrt{10}\text{より低い）}
\text{• 条件 }\sqrt{10} > \dfrac {6} {2 \cdot 1} = 3 \text{ により減衰振動}
\textcolor{brown}{\large{【解法】}}
\textcolor{green}{f'の係数 Rが0の場合の公式}
\text{微分方程式 } f^{\prime\prime}(t) = -\omega^2 f(t) \text{ に対する初期値問題}
f(0) = A_0,\quad f^{\prime}(0) = v_0 \text{の解は}
f(t) = A_0\cos(\omega t) + \displaystyle \frac{v_0}{\omega}\sin(\omega t) \text{である。}
\textcolor{blue}{この公式を用いて、本問を解く。}
\textcolor{green}{1.\ } \textcolor{green}{変数変換で1階微分を消す}
\text{元の微分方程式 }f^{\prime\prime}(t) + 6f^{\prime}(t) + 10f(t) = 0\text{ の両辺に、}e^{3t}\text{を掛けると}
\Leftrightarrow \textcolor{red}{e^{3t}f^{\prime\prime}(t)} + \textcolor{red}{6e^{3t} f^{\prime}(t)} +  10e^{3t} f(t) = 0 \cdots (1)
\text{ここで、積の微分公式より、}
\left(e^{3t}f(t)\right)''(t) = e^{3t}f^{\prime\prime}(t) + 6e^{3t} f^{\prime}(t) + 9e^{3t} f(t)
\text{が成り立つ。ゆえに、}
\textcolor{red}{e^{3t}f^{\prime\prime}(t)} + \textcolor{red}{6e^{3t} f^{\prime}(t)} = \textcolor{blue}{\left(e^{3t}f(t)\right)''(t) - 9e^{3t}f(t)}
\text{これを用いて置き換えると、}(1) \text{ は}
\quad \ \textcolor{blue}{\left(e^{3t}f(t)\right)'' - 9e^{3t}f(t)} + 10e^{3t}f(t) = 0
\Leftrightarrow \left(e^{3t}f(t)\right)'' + e^{3t}f(t) = 0
\text{ここで、} g(t) = e^{3t} f(t) \text{ とおくと}
g^{\prime\prime}(t) + g(t) = 0\ \ \cdots (2)
\textcolor{green}{2.\ } \textcolor{green}{公式を適用し} \textcolor{green}{g} \textcolor{green}{を求める}
\text{(2)は単振動の方程式なので、冒頭の公式を適用すると（}\omega = 1\text{）}
g(t) = g(0)\cos(t) + \displaystyle \frac{g^{\prime}(0)}{1}\sin(t) = g(0)\cos(t) + g^{\prime}(0)\sin(t)
\textcolor{green}{3.\ } \textcolor{green}{g} \textcolor{green}{の初期条件を求める}
\text{ } g(t) = e^{3t} f(t) \text{ より}
\begin{aligned}
  g(0) &= e^{0} f(0) = 1\\[6pt]
  g^{\prime}(0) &= 3e^{0} f(0) + e^{0} f^{\prime}(0) = 3 \cdot 1 + 2 = 5
  \end{aligned}
\textcolor{green}{4.\ } \textcolor{green}{g} \textcolor{green}{を求める}
\text{公式に代入すると}
g(t) = 1 \cdot \cos(t) + 5 \cdot \sin(t) = \cos(t) + 5\sin(t)
\textcolor{green}{5.\ } \textcolor{green}{g} \textcolor{green}{から} \textcolor{green}{f} \textcolor{green}{を求める}
\text{ } g(t) = e^{3t} f(t) \text{ より、} f(t) = e^{-3t} g(t)
\text{よって}
f(t) = e^{-3t}\left(\cos(t) + 5\sin(t)\right)

\text{【力学】}
\text{• 力学の空気抵抗下での強制振動は} mv^{\prime}(t) + kv(t) = F_0\cos(\omega t) \text{ でモデル化される。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• RL交流回路について、キルヒホッフの第二法則を用いると }
      LI^{\prime}(t) + RI(t) = V_0\cos(\omega t) \text{が成り立つ。}
\text{【問題の記号と力学における記号の対応】}
\text{空気抵抗下での強制振動:} \ mv^{\prime}(t) + kv(t) = F_0\cos(\omega t)
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } a \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } F \leftrightarrow \displaystyle \frac{F_0}{m} \text{（外力振幅 ÷ 質量）}
\text{• } \omega \leftrightarrow \omega \text{（角周波数）}
\text{• } f_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RL交流回路:} \ LI^{\prime}(t) + RI(t) = V_0\cos(\omega t)
\text{• } f(t) \leftrightarrow I(t) \text{（電流）}
\text{• } a \leftrightarrow \displaystyle \frac{R}{L} \text{（時定数の逆数）}
\text{• } F \leftrightarrow \displaystyle \frac{V_0}{L} \text{（電圧振幅 ÷ インダクタンス）}
\text{• } \omega \leftrightarrow \omega \text{（角周波数）}
\text{• } f_0 \leftrightarrow I_0 \text{（初期電流）}
\text{• } |Z| = \sqrt{a^2+\omega^2} \leftrightarrow \sqrt{R^2+(\omega L)^2} \text{（インピーダンスの大きさ）}
\text{• } \displaystyle \frac{F}{\sqrt{a^2+\omega^2}} \leftrightarrow \displaystyle \frac{V_0}{\sqrt{R^2+(\omega L)^2}} = \displaystyle \frac{V_0}{|Z|} \text{（定常電流の振幅）}
\text{• } \tan\alpha = \displaystyle \frac{\omega}{a} \leftrightarrow \displaystyle \frac{\omega L}{R} \text{（位相遅れ角）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t) + af(t) = F\cos(\omega t)
\text{両辺に}e^{at}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{at}f^{\prime}(t) + ae^{at}f(t) = Fe^{at}\cos(\omega t)
\text{積の微分より}
\Leftrightarrow (e^{at}f(t))' = Fe^{at}\cos(\omega t)
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\Leftrightarrow \int_0^t (e^{as}f(s))'\,ds = \int_0^t Fe^{as}\cos(\omega s)\,ds
\Leftrightarrow [e^{as}f(s)]_{0}^{t} = F\int_0^t e^{as}\cos(\omega s)\,ds
\Leftrightarrow \ e^{at}f(t) - f_0 = F\int_0^t e^{as}\cos(\omega s)\,ds
\textcolor{green}{ここで右辺は積分公式より、不定積分は}
\textcolor{green}{\int e^{as}\cos(\omega s)\,ds = \displaystyle \frac{e^{as}}{a^2+\omega^2}\big(a\cos(\omega s)+\omega\sin(\omega s)\big) + C}
\textcolor{green}{したがって、定積分は}
\textcolor{green}{\int_0^t e^{as}\cos(\omega s)\,ds = \left[\displaystyle \frac{e^{as}}{a^2+\omega^2}\big(a\cos(\omega s)+\omega\sin(\omega s)\big)\right]_{0}^{t}}
\textcolor{green}{= \displaystyle \frac{e^{at}}{a^2+\omega^2}\big(a\cos(\omega t)+\omega\sin(\omega t)\big) - \displaystyle \frac{e^{0}}{a^2+\omega^2}\big(a\cos(0)+\omega\sin(0)\big)}
\textcolor{green}{= \displaystyle \frac{e^{at}}{a^2+\omega^2}\big(a\cos(\omega t)+\omega\sin(\omega t)\big) - \displaystyle \frac{a}{a^2+\omega^2}}
\text{よって、}
\Leftrightarrow \ e^{at}f(t) - f_0 = F\left(\displaystyle \frac{e^{at}}{a^2+\omega^2}\big(a\cos(\omega t)+\omega\sin(\omega t)\big) - \displaystyle \frac{a}{a^2+\omega^2}\right)
\Leftrightarrow \ e^{at}f(t) = \displaystyle \frac{Fe^{at}}{a^2+\omega^2}\big(a\cos(\omega t)+\omega\sin(\omega t)\big) - \displaystyle \frac{Fa}{a^2+\omega^2} + f_0
\Leftrightarrow \ f(t) = \displaystyle \frac{F}{a^2+\omega^2}(a\cos(\omega t) + \omega\sin(\omega t)) + \left(f_0 - \displaystyle \frac{Fa}{a^2+\omega^2}\right)e^{-at}
\text{強制振動項を} \sqrt{a^2+\omega^2} \text{で括ると、}
\Leftrightarrow \ f(t) = \displaystyle \frac{F}{\sqrt{a^2+\omega^2}} \cdot \displaystyle \frac{a\cos(\omega t) + \omega\sin(\omega t)}{\sqrt{a^2+\omega^2}} + \left(f_0 - \displaystyle \frac{Fa}{a^2+\omega^2}\right)e^{-at}
\text{三角関数の合成により、}
\Leftrightarrow \ f(t) = \displaystyle \frac{F}{\sqrt{a^2+\omega^2}}\cos(\omega t - \alpha) + \left(f_0 - \displaystyle \frac{Fa}{a^2+\omega^2}\right)e^{-at}
\text{ただし、} \tan\alpha = \displaystyle \frac{\omega}{a}
\text{ここで、} t \to \infty \text{ のとき、 } e^{-at} \to 0 \text{ となるため、}
f(t) = \displaystyle \frac{F}{\sqrt{a^2+\omega^2}}\cos(\omega t - \alpha) \text{に収束する。}
\text{すなわち、右辺の三角関数の位相} \omega t \text{に比べて、解の関数の位相は} \alpha \text{遅れる。}
