\textbf{【方針】}
\text{ } (1+2h)^{\frac{1}{h}} = \left((1+2h)^{\frac{1}{2h}}\right)^{2} \text{ と変形し、中身の部分が定義より } e \text{ になることを用いる。}
\textbf{【解答】}
\begin{aligned}
      \lim_{h\to 0}(1+2h)^{\frac{1}{h}} &= \lim_{h\to 0}\left((1+2h)^{\frac{1}{2h}}\right)^{2} \\[6pt]
      &= \left(\lim_{h\to 0}(1+2h)^{\frac{1}{2h}}\right)^{2}
      \end{aligned}
\text{ここで、} h\to 0 \text{ のとき } 2h\to 0 \text{ であるから、定義 } e = \lim_{h\to 0}(1+h)^{\frac{1}{h}} \text{ より、} \lim_{h\to 0}(1+2h)^{\frac{1}{2h}} = e \text{したがって、}
\begin{aligned}
      \lim_{h\to 0}(1+2h)^{\frac{1}{h}} &= e^{2}
      \end{aligned}

\textbf{【方針】}
\text{比の評価により、}\displaystyle \lim_{n \to \infty} \frac {a_{n+1}} {a_n} = \frac 1 2 \text{を示す。この事実から、} N < n \text{ならば、} \displaystyle a_{n+1} \leq \frac{3}{4}a_n  \text{となるような}N \text{を導けることが予測できるので、これを使ってはさみうちを行う。（ここでは} \displaystyle \frac  3 4 \text{という値を用いたが、}1\text{未満で取ってこれればとくに何でも良い。）}
\textbf{【解答】}
\displaystyle a_n = \frac{n^2}{2^n} \text{に対して、}
\begin{aligned}
      \frac{a_{n+1}}{a_n} &= \frac{\frac{(n+1)^2}{2^{n+1}}}{\frac{n^2}{2^n}} \\[6pt]
      &= \displaystyle \frac{1}{2}\frac{(n+1)^2}{n^2} \\[6pt]
      &= \frac{1}{2}\left(1+\frac{1}{n}\right)^2 \\[6pt]
      &= \frac{1}{2} + \frac{1}{n} + \frac{1}{2n^2} \\[6pt]
      &\underset{n \to \infty}{\longrightarrow}\  \frac{1}{2} \quad \text{(単調減少で収束)}
      \end{aligned}
\text{よって数列}a_n \text{は} n\text{が十分大きければ、1つ番号が進む度におよそ} \displaystyle \frac 1 2 \text{倍されていきどんどん小さくなっていくことが分かる。}
\text{具体的に}N <n\text{ならば常に、} \displaystyle \frac{a_{n+1}}{a_n} \leq \frac{3}{4} \text{を満たすような} N \text{ を求める。}
\begin{aligned}
      & \frac{1}{2} + \frac{1}{n} + \frac{1}{2n^2} \leq \frac{3}{4} \\[6pt]
      \Longleftrightarrow \ & \  n^2 - 4n - 2 \geq 0 \\[6pt]
      \Longleftrightarrow \ & \  n \geq 2 + \sqrt{6} \; (\fallingdotseq 4.45)
      \end{aligned}
\text{したがって整数 } n \geq 5 \text{ で常に、}
\begin{aligned}
      &\displaystyle \frac{a_{n+1}}{a_n} \leq \frac{3}{4} \Longleftrightarrow \boxed{a_{n+1} \leq \frac{3}{4}a_n}
      \end{aligned}
\text{よって}
\displaystyle 0 \leq a_n \leq \frac{3}{4} a_{n-1}  \leq \cdots \leq a_5\left(\frac{3}{4}\right)^{n-5} \ \  (n > 5)
\text{また、}\displaystyle a_5  =\frac {5^2}{2^5}= \frac{25}{32}\text{である。}
\displaystyle \lim_{n\to\infty} a_5 \left(\frac{3}{4}\right)^{n-5} = 0 \text{なので、はさみうちより、} \lim_{n\to\infty} a_n =\lim_{n\to\infty}\displaystyle \frac{n^2}{2^n} = 0

\textbf{【方針】}
\text{ } x^2 = t \text{ と置いて、2次式として因数分解して、それから} x \text{ の式に戻す。 }
\textbf{【途中式変形】}
\text{ } x^2 = t \text{ と置くと、}
\begin{aligned}
x^4 + x^2 - 2 &= t^2 + t - 2 \\
&= (t + 2)(t - 1)
\end{aligned}
\text{ } t = x^2 \text{ に戻すと、}
\begin{aligned}
&= (x^2 + 2)(x^2 - 1) \\
&= (x^2 + 2)(x - 1)(x + 1)
\end{aligned}

\textbf{【方針】}
\text{両辺に } 2 \cdot 3^x \text{ をかけて整理し、} 3^x = t \text{ とおいて2次方程式に帰着させる。}
\textbf{【解説】}
\text{元の方程式の両辺に } 2 \cdot 3^x \text{ をかけると、}
\begin{aligned}
&\ \ \ \ \ \displaystyle\frac{3^x - 3^{-x}}{2} = 5 \\
&\Leftrightarrow 3^x - 3^{-x} = 10 \\
&\Leftrightarrow 3^x - \displaystyle\frac{1}{3^x} = 10 \\
&\Leftrightarrow (3^x)^2 - 1 = 10 \cdot 3^x \\
&\Leftrightarrow (3^x)^2 - 10 \cdot 3^x - 1 = 0
\end{aligned}
\text{ここで、} 3^x = t \text{ とおくと、} t > 0 \text{ であり、}
\begin{aligned}
&\ \ \ \ \ t^2 - 10t - 1 = 0
\end{aligned}
\text{2次方程式の解の公式より、}
\begin{aligned}
t &= \displaystyle\frac{10 \pm \sqrt{10^2 - 4 \cdot 1 \cdot (-1)}}{2 \cdot 1} \\
&= \displaystyle\frac{10 \pm \sqrt{100 + 4}}{2} \\
&= \displaystyle\frac{10 \pm \sqrt{104}}{2} \\
&= \displaystyle\frac{10 \pm 2\sqrt{26}}{2} \\
&= 5 \pm \sqrt{26}
\end{aligned}
\text{ここで、} t = 3^x > 0 \text{ なので、} t = 5 + \sqrt{26} \text{ である。}
\text{したがって、}
\begin{aligned}
&\ \ \ \ \ t = 5 + \sqrt{26} \\
&\Leftrightarrow 3^x = 5 + \sqrt{26} \\
&\Leftrightarrow x = \log_3(5 + \sqrt{26})
\end{aligned}
\textbf{【補足】}
\text{この問題は、底 } 3 \text{ を自然対数の底 } e = 2.718\ldots \text{ に変えると、双曲線関数 } \sinh x = \displaystyle\frac{e^x - e^{-x}}{2} \text{ に対する方程式となる。}
\text{また、} \sinh x \text{ は } \displaystyle\int \frac{1}{\sqrt{x^2+1}} dx \text{ などの置換積分に関連して登場する関数である。}

\textbf{【方針】}
f(x) = x^5 - x^4 - 1\text{とおいて、まずは、因数定理を用い、候補（±1）を代入して、1次式の因数を持たないことを認識したら、その後、2次式×3次式の形で係数比較を行うのが自然。}
\textbf{【途中式変形】}
\text{因数定理の候補を代入すると、}
\begin{aligned}
f(1) &= 1 - 1 - 1 = -1 \neq 0 \\
f(-1) &= -1 - 1 - 1 = -3 \neq 0
\end{aligned}
\text{よって、1次式の因数を持たない。よって2次式×3次式の因数分解を探す。}
\text{整数係数で } f(x) = (x^2 + ax + \alpha)(x^3 + bx^2 + cx + \beta) \text{ とおく。}
\textcolor{red}{実は計算すると、下記のように計算できる。}
\textcolor{red}{a = -1,\ b = 0,\ c = -1,\ \alpha = 1,\ \beta = -1}
\textcolor{red}{以下ではこの証明を行う。}
\textbf{【証明】}
\text{ここで } x^5 - x^4 - 1 \text{ の定数項が } -1 \text{ であることから、 } \alpha\beta = -1 \text{ であるため、 } (\alpha, \beta) = (1, -1), (-1, 1) \text{ の場合に分けて解を探す。}
\textcolor{blue}{1. } \textcolor{blue}{(\alpha, \beta) = (1, -1)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax + 1)(x^3 + bx^2 + cx - 1) \text{ とおくと、}
\begin{aligned}
&\ \ \ \ x^5 - x^4 - 1 \\
&= (x^2 + ax + 1)(x^3 + bx^2 + cx - 1) \\
&= x^5 + (a+b)x^4 + (ab + c + 1)x^3 + (ac + b - 1)x^2 + (- a + c)x - 1
\end{aligned}
\text{係数比較より、}
\begin{aligned}
&\text{4次: } a + b = -1\ \cdots (1) \\[2pt]
&\text{3次: } ab + c + 1 = 0\ \ \cdots (2) \\[2pt]
&\text{2次: } ac + b - 1 = 0\ \ \cdots (3) \\[2pt]
&\text{1次: } -a + c = 0\ \ \cdots (4)
\end{aligned}
\text{(4),(1) より } c = a , b = -1 - a \text{これを(2)に代入して、}
a(-1 - a) + a + 1 = -a - a^2 + a + 1 = -a^2 + 1 = 0 \text{、すなわち } a^2 = 1
\text{これより } a = 1 \text{ または } a = -1 \text{ を得る。}
\textcolor{blue}{(i) } \textcolor{blue}{a = 1 のとき}
\text{ } b = -2, c = 1 \text{、このとき (3) より、}
\begin{aligned}
ac + b - 1 &= 1 \cdot 1 + (-2) - 1 = -2 \neq 0
\end{aligned}
\textcolor{red}{したがってこの場合は(3)を満たさない。}
\textcolor{blue}{(ii) } \textcolor{blue}{a = -1 のとき}
\text{ } b = 0, c = -1 \text{、このとき (3) より、}
\begin{aligned}
ac + b - 1 &= (-1) \cdot (-1) + 0 - 1 = 0
\end{aligned}
\textcolor{green}{であるので、(3)を満たし、(1),(2),(3),(4)の連立方程式の解は}
\textcolor{green}{a = -1, \quad b = 0, \quad c = -1}
\textcolor{green}{したがって、}\textcolor{green}{ (a, b, c, \alpha, \beta) = (-1, 0, -1, 1, -1)}\textcolor{green}{となり、答えは}
\textcolor{green}{ x^5 - x^4 - 1 = (x^2 - x + 1)(x^3 - x - 1)}
\textcolor{brown}{\large{これで答えは得られたが、一応、}}
\textcolor{brown}{\large{他に解がないことを下記で確認しておく。}}
\textcolor{blue}{2. } \textcolor{blue}{(\alpha, \beta) = (-1, 1)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax - 1)(x^3 + bx^2 + cx + 1) \text{ とおくと、}
\begin{aligned}
&\ \ \ \ x^5 - x^4 - 1 \\
&= (x^2 + ax - 1)(x^3 + bx^2 + cx + 1) \\
&= x^5 + (a+b)x^4 + (ab + c - 1)x^3 + (ac - b + 1)x^2 + (a - c)x - 1
\end{aligned}
\text{係数比較より、}
\begin{aligned}
&\text{4次: } a + b = -1\ \cdots (1) \\[2pt]
&\text{3次: } ab + c - 1 = 0\ \ \cdots (2) \\[2pt]
&\text{2次: } ac - b + 1 = 0\ \ \cdots (3) \\[2pt]
&\text{1次: } a - c = 0\ \ \cdots (4)
\end{aligned}
\text{(4),(1) より } c = a , b = -1 - a \text{これを(2)に代入して、}
a(-1 - a) + a - 1 = -a - a^2 + a - 1 = -a^2 - 1 = 0 \text{、すなわち } a^2 = -1
\textcolor{red}{これは実数解を持たない。}

\textbf{【方針】}
\displaystyle \frac{1}{e^x} = e^{-x} \text{ と見て、部分積分を実行する。}
\textbf{【解法】}
\text{部分積分を用いる。}
\begin{aligned}
\int_0^{\log 2} (x+1)e^{-x} \, dx &= \int_0^{\log 2} (x+1) \cdot (-e^{-x})' \, dx \\
&= \left[-(x+1)e^{-x}\right]_0^{\log 2} + \int_0^{\log 2} e^{-x} \, dx \\
&= -(\log 2 + 1)e^{-\log 2} + 0 \cdot e^0 + \left[-e^{-x}\right]_0^{\log 2} \\
&= -\frac{\log 2 + 1}{2} + \left(-e^{-\log 2} + e^0\right) \\
&= -\frac{\log 2 + 1}{2} + \left(-\frac{1}{2} + 1\right) \\
&= -\frac{\log 2 + 1}{2} + \frac{1}{2} \\
&= -\frac{\log 2}{2} + 1
\end{aligned}

\textbf{【方針】}
\text{右極限と左極限を比較する。}
\textbf{【解答】}
\begin{aligned}
    \lim_{x\to +0}\frac{|\sin x|}{x} & =\lim_{x\to +0}\frac{\sin x}{x} =1 \\[8pt]
    \lim_{x\to -0}\frac{|\sin x|}{x} & =\lim_{x\to -0}\frac{-\sin x}{x} =-1
    \end{aligned}
\text{よって、右極限と左極限が一致しないため、極限は存在しない。}

