\textcolor{brown}{\large{【力学】}}
\text{• 力学においては、} mx^{\prime\prime}(t) + kx(t) = F \text{ の形でよく登場する。}F=mg\text{の場合は、重力下のばね-質量系の運動を表す。重力による平衡位置シフトが起きる。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• 電磁気学においては、} LQ^{\prime\prime}(t) + \displaystyle \frac{Q(t)}{C} = V \text{ の形でよく登場する。これは直流電圧が印加されたLC回路を表す。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{重力下のばねの運動:} \ mx^{\prime\prime}(t) + kx(t) = F
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } 4 \leftrightarrow \displaystyle \frac{k}{m} \text{（ばね定数 ÷ 質量）}
\text{• } 2 \leftrightarrow \displaystyle \frac{F}{m} \text{（外力 ÷ 質量）}
\text{• } f(0)=0 \leftrightarrow x_0=0 \text{（初期位置）}
\text{• } f^{\prime}(0)=0 \leftrightarrow v_0=0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{LC直流回路:} \ LQ^{\prime\prime}(t) + \displaystyle \frac{Q(t)}{C} = V
\text{• } f(t) \leftrightarrow Q(t) \text{（コンデンサに蓄えられた電荷）}
\text{• } f^{\prime}(t) \leftrightarrow I(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow I' \text{（電流変化率）}
\text{• } 4 \leftrightarrow \displaystyle \frac{1}{LC} \text{（固有角周波数の2乗）}
\text{• } 2 \leftrightarrow \displaystyle \frac{V}{L} \text{（電圧 ÷ インダクタンス）}
\text{• } f(0)=0 \leftrightarrow Q_0=0 \text{コンデンサに蓄えられた初期電荷）}
\text{• } f^{\prime}(0)=0 \leftrightarrow I_0=0 \text{（初期電流）}
\textbf{【方針】}
\text{定数解を求めて平行移動し、外力がない場合の微分方程式の解の式を利用する。}
\textcolor{brown}{\large{【解法】}}
\textcolor{green}{同次の場合の公式}
\text{微分方程式 } f^{\prime\prime}(t) = -\omega^2 f(t) \text{ に対する初期値問題}
f(0) = A_0,\quad f^{\prime}(0) = v_0
\text{の解は}
f(t) = A_0\cos(\omega t) + \displaystyle \frac{v_0}{\omega}\sin(\omega t)
\text{である。（問題6で導出済み）}
\textcolor{blue}{この公式を用いて、本問を解く。}
f^{\prime\prime}(t) = -4f(t) + 2
\textcolor{green}{1.\ } \textcolor{green}{定数解を探す}
\text{定数解}f_s\text{を求める。}f_s'' = 0\text{より}
0 = -4 f_s + 2 \quad \Leftrightarrow \quad f_s = \displaystyle \frac{2}{4} = \displaystyle \frac{1}{2}
\textcolor{green}{2.\ } \textcolor{green}{平行移動で新たな関数} \textcolor{green}{g} \textcolor{green}{を置いて同次化(バネのみの力による単振動の式にする)}
\text{平行移動：}g(t) = f(t) - f_s \text{ とおく。}
\begin{aligned}
      g^{\prime\prime}(t) &= f^{\prime\prime}(t) = -4 f(t) + 2 \\[5pt]
      &= -4(g(t) + f_s) + 2 \\[5pt]
      &= -4 g(t) - 4 \cdot \displaystyle \frac{1}{2} + 2 \\[5pt]
      &= -4 g(t)
      \end{aligned}
\text{よって }g^{\prime\prime}(t) = -4 g(t) \text{（同次化完了）}
\textcolor{green}{3.\ } \textcolor{green}{g} \textcolor{green}{の初期条件を求める}
\begin{aligned}
      g(0) &= f(0) - f_s = 0 - \displaystyle \frac{1}{2} = -\displaystyle \frac{1}{2} \\[5pt]
      g^{\prime}(0) &= f^{\prime}(0) = 0
      \end{aligned}
\textcolor{green}{4.\ } \textcolor{green}{公式を適用し} \textcolor{green}{g} \textcolor{green}{を求める}
g^{\prime\prime}(t) = -4 g(t) \text{で、}g(0) = -\displaystyle \frac{1}{2},\ g^{\prime}(0) = 0
\text{公式より（}\omega = 2\text{）}
\begin{aligned}
      g(t) &= g(0)\cos(2t) + \displaystyle \frac{g^{\prime}(0)}{2}\sin(2t) \\[5pt]
      &= -\displaystyle \frac{1}{2}\cos(2t)
      \end{aligned}
\textcolor{green}{5.\ } \textcolor{green}{g} \textcolor{green}{から} \textcolor{green}{f} \textcolor{green}{を求める}
f(t) = g(t) + f_s = -\displaystyle \frac{1}{2}\cos(2t) + \displaystyle \frac{1}{2}
\quad = \displaystyle \frac{1}{2}\big(1 - \cos(2t)\big)

\textbf{【方針】}
\displaystyle 1-\cos x=2\sin^{2}\!\left(\frac{x}{2}\right)\text{ を用いる}
\textbf{【解答】}
\begin{aligned}
      \displaystyle & \lim_{x\to 0}\frac{1-\cos x}{x^{2}} \\[6pt]
      \displaystyle =& \lim_{x\to 0}\frac{2\sin^{2}\!\left(\frac{x}{2}\right)}{x^{2}} \\[6pt]
      \displaystyle =& \lim_{x\to 0}\frac{2\sin^{2}\!\left(\frac{x}{2}\right)}{4\cdot \left(\frac x 2 \right)^{2}} \\[6pt]
      =&\displaystyle \lim_{x\to 0} \frac 1 2 \left(\frac{\sin(\frac{x}{2})}{\frac{x}{2}}\right)^{2} \\[6pt]
      =&\displaystyle \frac{1}{2} \cdot 1^2 \\[6pt]
      =&\displaystyle \frac{1}{2}
      \end{aligned}

\textbf{【方針】}
\text{積和公式を用いて、三角関数の1次式に帰着する。}
\textbf{【解説】}
\text{積和公式 } \sin A\cos B = \displaystyle\frac{1}{2}\left(\sin(A+B)+\sin(A-B)\right) \text{ を用いると、}
\begin{aligned}
\displaystyle &\int_0^{2\pi}\sin(2x)\cos(3x)\,dx\\[5pt]
=& \displaystyle\frac{1}{2}\displaystyle \int_0^{2\pi}\left(\sin((2+3)x)+\sin((2-3)x)\right)dx\\[5pt]
=& \displaystyle\frac{1}{2}\displaystyle \int_0^{2\pi}\left(\sin(5x)+\sin(-x)\right)dx\\[5pt]
=& \displaystyle\frac{1}{2}\displaystyle \int_0^{2\pi}\left(\sin(5x)-\sin x\right)dx\\[5pt]
=& \displaystyle\frac{1}{2}\left[-\displaystyle\frac{\cos(5x)}{5}+\cos x\right]_0^{2\pi}\\[5pt]
=& \displaystyle\frac{1}{2}\left((-\displaystyle\frac{\cos(10\pi)}{5}+\cos(2\pi))-(-\displaystyle\frac{\cos 0}{5}+\cos 0)\right)\\[5pt]
=& \displaystyle\frac{1}{2}\left((-\displaystyle\frac{1}{5}+1)-(-\displaystyle\frac{1}{5}+1)\right)\\[5pt]
=& \displaystyle\frac{1}{2}(0)\\[5pt]
=& 0
\end{aligned}
\textbf{【補足】}
\text{この結果はフーリエ級数という数学に登場し、一般に下記が成立する。}
\displaystyle \int_0^{2\pi}\sin(mx)\cos(nx)\,dx = 0

