\textbf{【方針】}
I_n=\displaystyle \int_{0}^{\frac{\pi}{4}} \tan^n x\,dx \text{とおき、漸化式を導出して使う。}
\textcolor{green}{【命題】}
-\displaystyle\frac{\pi}{2}<a<b<\displaystyle\frac{\pi}{2} \text{を満たす任意の}a,b\text{に対して、} I_n=\displaystyle\int_{a}^{b} \tan^n x\,dx \text{とおくとき、}
n\ge 2 \text{に対して} \textcolor{green}{\ I_n=\displaystyle\frac{1}{n-1}\left[\tan^{n-1}x\right]_{a}^{b}-I_{n-2}\ }\text{が成り立つ。}
\textbf{【証明】}
\textbf{恒等式 } \tan^2 x=\displaystyle\frac{1}{\cos^2 x}-1 \textbf{ を用いて、}
\begin{aligned}
I_n
&=\displaystyle \int_{a}^{b} \tan^n x\,dx\\[6pt]
&=\displaystyle \int_{a}^{b} \tan^{n-2}x\cdot\tan^2 x\,dx\\[6pt]
&=\displaystyle \int_{a}^{b} \tan^{n-2}x\cdot\left(\displaystyle \frac{1}{\cos^2 x}-1\right)\,dx\\[6pt]
&=\displaystyle \int_{a}^{b} \tan^{n-2}x\cdot\displaystyle \frac{1}{\cos^2 x}\,dx-\displaystyle \int_{a}^{b} \tan^{n-2}x\,dx\cdots(1)
\end{aligned}
\textbf{第1項について、}
\begin{aligned}
\displaystyle \int \tan^{n-2}x\cdot\displaystyle \frac{1}{\cos^2 x}\,dx
&=\displaystyle\int \tan^{n-2}x\cdot\sec^2 x\,dx\\[6pt]
&=\displaystyle\frac{\tan^{n-1}x}{n-1}+C
\end{aligned}
\text{したがって、定積分として、}
\begin{aligned}
\displaystyle \int_{a}^{b} \tan^{n-2}x\cdot\displaystyle \frac{1}{\cos^2 x}\,dx
&=\left[\displaystyle\frac{\tan^{n-1}x}{n-1}\right]_{a}^{b}\\[6pt]
&=\displaystyle\frac{1}{n-1}\left[\tan^{n-1}x\right]_{a}^{b}
\end{aligned}
\text{したがって、(1)は} I_n=\displaystyle\frac{1}{n-1}\left[\tan^{n-1}x\right]_{a}^{b}-I_{n-2}\quad\text{Q.E.D}
\textbf{【$a=0$, $b=\displaystyle\frac{\pi}{4}$ の場合】}
\text{本問では } a=0, b=\displaystyle\frac{\pi}{4} \text{ であるから、}
\begin{aligned}
I_n
&=\displaystyle\frac{1}{n-1}\left[\tan^{n-1}x\right]_{0}^{\frac{\pi}{4}}-I_{n-2}\\[6pt]
&=\displaystyle\frac{1}{n-1}\left(\tan^{n-1}\left(\displaystyle\frac{\pi}{4}\right)-\tan^{n-1}(0)\right)-I_{n-2}\\[6pt]
&=\displaystyle\frac{1}{n-1}(1-0)-I_{n-2}\\[6pt]
&=\displaystyle\frac{1}{n-1}-I_{n-2}
\end{aligned}
\textbf{【$I_6$ の計算】}
\text{示した命題を用いて、定積分の状態で } I_6 \text{ を順次変形する。}
\begin{aligned}
I_6
&=\displaystyle\frac{1}{6-1}-I_{6-2}\\[6pt]
&=\displaystyle\frac{1}{5}-I_4\\[6pt]
&=\displaystyle\frac{1}{5}-\left(\displaystyle\frac{1}{4-1}-I_{4-2}\right)\\[6pt]
&=\displaystyle\frac{1}{5}-\left(\displaystyle\frac{1}{3}-I_2\right)\\[6pt]
&=\displaystyle\frac{1}{5}-\displaystyle\frac{1}{3}+I_2\\[6pt]
&=\displaystyle\frac{1}{5}-\displaystyle\frac{1}{3}+\left(\displaystyle\frac{1}{2-1}-I_{2-2}\right)\\[6pt]
&=\displaystyle\frac{1}{5}-\displaystyle\frac{1}{3}+(1-I_0)\\[6pt]
&=\displaystyle\frac{1}{5}-\displaystyle\frac{1}{3}+1-I_0\\[6pt]
&=\displaystyle\frac{3-5+15}{15}-I_0\\[6pt]
&=\displaystyle\frac{13}{15}-I_0\\[6pt]
&=\displaystyle\frac{13}{15}-\displaystyle\int_{0}^{\frac{\pi}{4}} \tan^0 x\,dx\\[6pt]
&=\displaystyle\frac{13}{15}-\displaystyle\int_{0}^{\frac{\pi}{4}} 1\,dx\\[6pt]
&=\displaystyle\frac{13}{15}-\displaystyle\frac{\pi}{4}
\end{aligned}

\textcolor{brown}{\large{【力学】}}
\text{• 自由落下運動の速度変化についての微分方程式。}
\text{• 力学においては、} v^{\prime}(t) = g \text{の形でよく登場する。これは重力を受ける質点の速度変化を表す。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{自由落下運動の速度変化}
v^{\prime}(t) = g
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } g \leftrightarrow g \text{（重力加速度）}
\text{• } f_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t) = g
\text{両辺を }0\text{ から }t\text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime}(s)\,ds = \int_0^t g\,ds\\[5pt]
&\Leftrightarrow [f(s)]_{0}^{t} = [gs]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f(t) - f(0) = g t - 0\\[5pt]
&\Leftrightarrow \ f(t) = g t + f(0)
\end{aligned}
\text{初期条件より} f(0) = f_0 \text{なので、}
\Leftrightarrow \ f(t) = g t + f_0

\textcolor{brown}{\large{【力学】}}
\text{• 力学の空気抵抗下での一定外力運動は} mx'' + kx' = mg \text{ でモデル化される。}
\text{• 速度は指数関数的に終端速度} \displaystyle \frac{mg}{k} \text{ に収束する。終端速度に近くになると、外力と抵抗力がつり合った、等速直線運動に近似できる。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{空気抵抗下での一定外力運動:} \ mx^{\prime\prime}(t) + kx^{\prime}(t) = mg
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } 3 \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } 2 \leftrightarrow \displaystyle \frac{mg}{m} = g \text{（重力加速度）}
\text{• } f(0)=1 \leftrightarrow x_0=1 \text{（初期位置）}
\text{• } f^{\prime}(0)=5 \leftrightarrow v_0=5 \text{（初期速度）}
\text{【問題の記号と電磁気学における記号の対応】}
\text{RL回路での電荷量変化}
Lq^{\prime\prime}(t) + Rq^{\prime}(t) = V
\text{• } f(t) \leftrightarrow q(t) \text{（電荷）}
\text{• } f^{\prime}(t) \leftrightarrow I(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow I' \text{（電流変化率）}
\text{• } 3 \leftrightarrow \displaystyle \frac{R}{L} \text{（抵抗 ÷ インダクタンス）}
\text{• } 2 \leftrightarrow \displaystyle \frac{V}{L} \text{（電圧 ÷ インダクタンス）}
\text{• } f(0)=1 \leftrightarrow q_0=1 \text{（初期電荷）}
\text{• } f^{\prime}(0)=5 \leftrightarrow I_0=5 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
f^{\prime\prime}(t) + 3f^{\prime}(t) = 2
\text{置換：}u(t) = f^{\prime}(t)\text{ とおくと、}
\Leftrightarrow \ u^{\prime}(t) + 3u(t) = 2
\text{両辺に}e^{3t}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{3t}u^{\prime}(t) + 3e^{3t}u(t) = 2e^{3t}
\text{積の微分より}
\Leftrightarrow (e^{3t}u(t))' = 2e^{3t}
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\begin{aligned}
&\Leftrightarrow \int_0^t (e^{3s}u(s))'\,ds = \int_0^t 2e^{3s}\,ds\\[5pt]
&\Leftrightarrow [e^{3s}u(s)]_{0}^{t} = \left[\displaystyle \frac{2}{3}e^{3s}\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ e^{3t}u(t) - e^0 u(0) = \displaystyle \frac{2}{3}e^{3t} - \displaystyle \frac{2}{3}e^0\\[5pt]
&\Leftrightarrow \ e^{3t}u(t) = u(0) + \displaystyle \frac{2}{3}(e^{3t}-1)
\end{aligned}
\text{初期条件より} u(0) = 5 \text{なので、}
\Leftrightarrow \ e^{3t}u(t) = 5 + \displaystyle \frac{2}{3}(e^{3t}-1)
\Leftrightarrow \ e^{3t}u(t) = \displaystyle \frac{2}{3}e^{3t} + 5 - \displaystyle \frac{2}{3}
\Leftrightarrow \ e^{3t}u(t) = \displaystyle \frac{2}{3}e^{3t} + \displaystyle \frac{13}{3}
\Leftrightarrow \ u(t) = \displaystyle \frac{2}{3} + \displaystyle \frac{13}{3}e^{-3t}
\text{元の変数に戻す：}f^{\prime}(t) = u(t)\text{ より}
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime}(s)\,ds = \int_0^t u(s)\,ds\\[5pt]
&\Leftrightarrow [f(s)]_{0}^{t} = \int_0^t \left[\displaystyle \frac{2}{3} + \displaystyle \frac{13}{3}e^{-3s}\right]ds\\[5pt]
&\Leftrightarrow \ f(t) - f(0) = \left[\displaystyle \frac{2}{3}s\right]_{0}^{t} + \displaystyle \frac{13}{3}\left[-\displaystyle \frac{1}{3}e^{-3s}\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f(t) = f(0) + \displaystyle \frac{2}{3}t - 0 + \displaystyle \frac{13}{3}\left(-\displaystyle \frac{1}{3}e^{-3t} + \displaystyle \frac{1}{3}e^0\right)
\end{aligned}
\text{初期条件より} f(0) = 1 \text{なので、}
\Leftrightarrow \ f(t) = 1 + \displaystyle \frac{2}{3}t + \displaystyle \frac{13}{3}\left(-\displaystyle \frac{1}{3}e^{-3t} + \displaystyle \frac{1}{3}\right)
\Leftrightarrow \ f(t) = 1 + \displaystyle \frac{2}{3}t - \displaystyle \frac{13}{9}e^{-3t} + \displaystyle \frac{13}{9}
\Leftrightarrow \ f(t) = \displaystyle \frac{22}{9} + \displaystyle \frac{2}{3}t - \displaystyle \frac{13}{9}e^{-3t}
\text{この解は直線＋指数関数の形で、減衰定数 }3\text{ で指数関数的に収束する。}

