\textcolor{red}{\textbf{指数関数×三角関数の積分公式：}}
\textcolor{red}{\displaystyle \int e^{a t}\cos(\omega t)\,dt=\displaystyle \frac{e^{a t}}{a^2+\omega^2}\big(a\cos(\omega t)+\omega\sin(\omega t)\big)}
\textcolor{brown}{\large{【解法】}}
\sqrt{3}f^{\prime}(t) + 2f(t) = 3\sqrt{3}\cos(2t)
\text{両辺を } \sqrt{3} \text{ で割って標準形に変形：}
\Leftrightarrow \ f^{\prime}(t) + \displaystyle \frac{2}{\sqrt{3}}f(t) = 3\cos(2t)
\text{両辺に}e^{ \frac{2}{\sqrt{3}}t}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{ \frac{2}{\sqrt{3}}t}f^{\prime}(t) + \displaystyle \frac{2}{\sqrt{3}}e^{ \frac{2}{\sqrt{3}}t}f(t) = 3e^{ \frac{2}{\sqrt{3}}t}\cos(2t)
\text{積の微分より}
\Leftrightarrow (e^{ \frac{2}{\sqrt{3}}t}f(t))' = 3e^{ \frac{2}{\sqrt{3}}t}\cos(2t)
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\Leftrightarrow \int_0^t \left(e^{ \frac{2}{\sqrt{3}}s}f(s)\right)'\,ds = \int_0^t 3e^{ \frac{2}{\sqrt{3}}s}\cos(2s)\,ds
\Leftrightarrow \left[e^{ \frac{2}{\sqrt{3}}s}f(s)\right]_{0}^{t} = 3\int_0^t e^{ \frac{2}{\sqrt{3}}s}\cos(2s)\,ds
\Leftrightarrow \ e^{ \frac{2}{\sqrt{3}}t}f(t) - e^0 f(0) = 3\int_0^t e^{ \frac{2}{\sqrt{3}}s}\cos(2s)\,ds
\Leftrightarrow \ e^{ \frac{2}{\sqrt{3}}t}f(t) = 3\int_0^t e^{ \frac{2}{\sqrt{3}}s}\cos(2s)\,ds
\Leftrightarrow \ f(t) = 3e^{ -\frac{2}{\sqrt{3}}t}\int_0^t e^{ \frac{2}{\sqrt{3}}s}\cos(2s)\,ds
\textcolor{red}{\textbf{ここで右辺は積分公式より、不定積分は}}
\textcolor{red}{\int e^{\frac{2}{\sqrt{3}}s}\cos(2s)\,ds = \displaystyle \frac{e^{\frac{2}{\sqrt{3}}s}}{\left(\frac{2}{\sqrt{3}}\right)^2+2^2}\left(\frac{2}{\sqrt{3}}\cos(2s)+2\sin(2s)\right) + C}
