\textcolor{brown}{\large{【力学】}}
\text{• 初期位置 }x_0=-1\text{、初期速度 }v_0=3\text{、加速度 }a=2\text{ の等加速度直線運動の位置についての微分方程式。}
\text{• 力学においては、} x^{\prime\prime}(t) = a \text{の形でよく登場する。これは一定の力を受ける質点の位置変化を表す。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{一定加速度運動の位置変化}
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } f(0)=-1 \leftrightarrow x_0=-1 \text{（初期位置）}
\text{• } f^{\prime}(0)=3 \leftrightarrow v_0=3 \text{（初期速度）}
\textcolor{brown}{\large{【解法】}}
f^{\prime\prime}(t) = 2
\text{両辺を }0\text{ から }t\text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime\prime}(s)\,ds = \int_0^t 2\,ds\\[5pt]
&\Leftrightarrow [f^{\prime}(s)]_{0}^{t} = [2s]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f^{\prime}(t) - f^{\prime}(0) = 2 t - 0\\[5pt]
&\Leftrightarrow \ f^{\prime}(t) = 2 t + f^{\prime}(0)
\end{aligned}
\text{初期条件より} f^{\prime}(0) = 3 \text{なので、}
\Leftrightarrow \ f^{\prime}(t) = 2 t + 3
\text{さらに両辺を }0\text{ から }t\text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime}(s)\,ds = \int_0^t (2 s + 3)\,ds\\[5pt]
&\Leftrightarrow [f(s)]_{0}^{t} = [s^2 + 3s]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f(t) - f(0) = t^2 + 3 t - 0\\[5pt]
&\Leftrightarrow \ f(t) = t^2 + 3 t + f(0)
\end{aligned}
\text{初期条件より} f(0) = -1 \text{なので、}
\Leftrightarrow \ f(t) = t^2 + 3 t - 1

