\textbf{【方針】}
\text{方程式を y の二次方程式と見て，判別式が平方数になる整数 x を探索する。}
\textbf{【解法】}
\text{方程式を y について整理すると、}
\begin{aligned}
    5x^2 + 2xy + y^2 - 12x + 4y + 11 &= 0 \\
    \Leftrightarrow y^2 + (2x+4)y + (5x^2-12x+11) &= 0
    \end{aligned}
\text{判別式を求めると、}
\begin{aligned}
    \Delta &= (2x+4)^2 - 4(5x^2-12x+11) \\
    &= 4x^2 + 16x + 16 - 20x^2 + 48x - 44 \\
    &= -16x^2 + 64x - 28 \\
    &= -16(x^2 - 4x) - 28 \\
    &= -16\{(x - 2)^2 - 4\} - 28 \\
    &= -16(x - 2)^2 + 64 - 28 \\
    &= -16(x - 2)^2 + 36
    \end{aligned}
x\text{が整数のとき、}\Delta\text{は、平方数であることが必要なので} -16(x - 2)^2 + 36 \ge 0 \text{ より、}
\begin{aligned}
    &\ \ \ \ \ -16(x - 2)^2 + 36 \ge 0 \\
    &\Leftrightarrow 16(x - 2)^2 \le 36 \\
    &\Leftrightarrow (x - 2)^2 \le \frac{9}{4} \\
    &\Leftrightarrow |x - 2| \le \frac{3}{2} \\
    &\Leftrightarrow \text{x は } 1, 2, 3 \text{ のいずれかである。}
    \end{aligned}
x\text{が3通りに絞り込めたので、各場合について } \Delta = -16(x - 2)^2 + 36 \text{ が平方数になるか調べればよい。。}
\textcolor{blue}{x = 1}\textcolor{blue}{ の場合}
\text{ }\Delta = -16(1 - 2)^2 + 36 = 20 \text{（平方数でない）}
\textcolor{blue}{x = 2}\textcolor{blue}{ の場合}
\text{ }\Delta = -16(2 - 2)^2 + 36 = 36 \text{（平方数）}
\text{このとき、方程式} 5x^2 + 2xy + y^2 - 12x + 4y + 11 = 0 \text{に}x =2\text{を代入すると}
\begin{aligned}
    5 \cdot 2^2 + 2 \cdot 2 \cdot y + y^2 - 12 \cdot 2 + 4y + 11 = 0 \\
    \Leftrightarrow 20 + 4y + y^2 - 24 + 4y + 11 = 0 \\
    \Leftrightarrow y^2 + 8y +7 = 0 \\
    \Leftrightarrow \textcolor{green} {y = -1, -7}
    \end{aligned}
\textcolor{blue}{x = 3}\textcolor{blue}{ の場合}
\text{ }\Delta = -16(3 - 2)^2 + 36  = 20 \text{（平方数でない）}
\text{よって、整数解は }(x,y)=(2,-1), (2,-7) \text{ である。}

\textbf{【方針】}
\text{置換 } u=e^x \text{ により有理式(多項式の分数関数)に帰着させ，さらに } 1+u=w \text{ とおいて積分を評価する．}
\textbf{【解説】}
\text{まず不定積分を求める。} u=e^x \text{ とおくと、} du=e^x\,dx \text{ より、}
\begin{aligned}
\displaystyle \int \displaystyle \frac{e^{2x}}{(1+e^x)^2}\,dx
&= \displaystyle \int \displaystyle \frac{e^x \cdot e^x}{(1+e^x)^2}\,dx\\
&= \displaystyle \int \displaystyle \frac{u}{(1+u)^2}\,du
\end{aligned}
\text{ここでさらに } w=1+u \ (dw=du)\text{ とおくと，} u=w-1 \text{ より、}
\begin{aligned}
\displaystyle \int \displaystyle \frac{u}{(1+u)^2}\,du
&= \displaystyle \int \displaystyle \frac{w-1}{w^2}\,dw\\
&= \displaystyle \int \left(\displaystyle \frac{1}{w} - \displaystyle \frac{1}{w^2}\right)\,dw\\
&= \log w + \displaystyle \frac{1}{w} + C\\
&= \log(1+u) + \displaystyle \frac{1}{1+u} + C\\
&= \log(1+e^x) + \displaystyle \frac{1}{1+e^x} + C
\end{aligned}
\text{したがって、定積分は、}
\begin{aligned}
&\ \ \ \displaystyle \int_{0}^{\log 2} \displaystyle \frac{e^{2x}}{(1+e^x)^2}\,dx \\ 
&= \left[\log(1+e^x) + \displaystyle \frac{1}{1+e^x}\right]_{0}^{\log 2}\\
&= \left(\log(1+e^{\log 2}) + \displaystyle \frac{1}{1+e^{\log 2}}\right) - \left(\log(1+e^0) + \displaystyle \frac{1}{1+e^0}\right)\\
&= \left(\log(1+2) + \displaystyle \frac{1}{1+2}\right) - \left(\log(1+1) + \displaystyle \frac{1}{1+1}\right)\\
&= \left(\log 3 + \displaystyle \frac{1}{3}\right) - \left(\log 2 + \displaystyle \frac{1}{2}\right)\\
&= \log\!\displaystyle \frac{3}{2} + \left(\displaystyle \frac{1}{3} - \displaystyle \frac{1}{2}\right)\\
&= \log\!\displaystyle \frac{3}{2} - \displaystyle \frac{1}{6}
\end{aligned}

