\textbf{【方針】}
\text{特性方程式 } r^2 - 4r + 4 = 0 \text{ の重根 } r \text{ を用い，} a_n = (A+Bn)r^{n-1} \text{ と書いて係数を決定する。(なぜこう置く事ができるかは解説の命題（重解版）を参照。)}
\textbf{【解法】}
\text{特性方程式 }
\begin{aligned}
    &\ \ \ \ \ r^2 - 4r + 4 = 0 \\
    &\Leftrightarrow (r - 2)^2 = 0 \\
    &\Leftrightarrow r = 2 \text{ （重根）}
    \end{aligned}
\text{よって命題（重解版）より、解は} a_n = (A + Bn) \cdot 2^{\,n-1}\text{と表す事ができる。}
\text{(2) 初期条件から } A,B \text{ を求める}
\text{初期条件 } a_1=1,\ a_2=6 \text{ より、}
\begin{aligned}
    \begin{cases}
      1 = A + B \\
      6 = (A + 2B) \cdot 2
    \end{cases}
    & \Leftrightarrow
    \begin{cases}
      A = -1 \\
      B = 2
    \end{cases}
    \end{aligned}
\textcolor{green}{したがって} \textcolor{green}{a_n = (-1 + 2n) \cdot 2^{\,n-1}}
\textbf{【命題（重解版）】}
\text{漸化式 } a_{n+2} + p a_{n+1} + q a_n = 0 \text{と、実数の初期条件} a_1,a_2\text{が与えられたとする。}
\text{この時、漸化式に対して定まる二次方程式} r^2 + p r + q = 0 \text{が重根 } r \text{を持つとき、一般項} a_n \textcolor{green}{はある実数} \textcolor{green}{A,B} \textcolor{green}{を用いて}
\textcolor{green}{a_n = (A + B n) r^{\,n-1}} \textcolor{green}{ と表す事ができる。}
\text{※ ただし、} A,B \text{ は初期条件}a_1, a_2\text{によって定まる実数。}
\textbf{【証明】}
\text{特性方程式が重根 } r \text{ を持つとき、解と係数の関係より } 2r = -p, r^2 = q \text{であるから、次の式が成り立つ：}
\begin{aligned}
  &a_{n+2}-r a_{n+1} = r\bigl(a_{n+1}-r a_n\bigr)
\end{aligned}
\text{ここで}
b_n := a_{n+1}-r a_n
\text{と置くと，上の恒等式から}
  b_{n+1}=r b_n
\text{が成り立つ。したがって初項}
  b_1 = a_2 - r a_1
\text{に対して、}
  b_n = b_1 r^{\,n-1} \quad\cdots(1)
\text{である。}

\text{一方，} b_n \text{の定義から}
\begin{aligned}
  a_{n+1} - r a_n &= b_1 r^{\,n-1}
\end{aligned}
\text{この両辺を } r^{n+1} \text{ で割ると（ } r \neq 0 \text{ を仮定）、}
\begin{aligned}
  \displaystyle \frac{a_{n+1}}{r^{n+1}} - \displaystyle \frac{a_n}{r^n} &= \displaystyle \frac{b_1}{r^2}
\end{aligned}
\text{ここで } u_n := \displaystyle \frac{a_n}{r^n} \text{ と置くと，}
\begin{aligned}
  u_{n+1} - u_n &= \displaystyle \frac{b_1}{r^2}
\end{aligned}
\text{従って } (u_n) \text{ は公差 } \displaystyle \frac{b_1}{r^2} \text{ の等差数列であり，初項 } u_1 = \displaystyle \frac{a_1}{r} \text{ を用いて}
  u_n = \displaystyle \frac{a_1}{r} + (n-1)\displaystyle \frac{b_1}{r^2}
\text{である。}

\text{元に戻すと（ } b_1 = a_2 - r a_1 \text{ ）}
\begin{aligned}
  a_n &= u_n r^n \\
  &= \left(\displaystyle \frac{a_1}{r} + (n-1)\displaystyle \frac{b_1}{r^2}\right) r^{n} \\
  &= \left(a_1 + (n-1)\displaystyle \frac{a_2 - r a_1}{r}\right) r^{\,n-1} \\
  &= \left( \left(a_1 - \displaystyle \frac{a_2 - r a_1}{r}\right) + \left(\displaystyle \frac{a_2 - r a_1}{r}\right)n \right)r^{\,n-1} \\
  &= \left( \left(2a_1 - \displaystyle \frac{a_2}{r}\right) + \left(\displaystyle \frac{a_2}{r} - a_1\right)n \right)r^{\,n-1}
\end{aligned}
\text{右辺について，}
\begin{aligned}
  A = 2a_1 - \displaystyle \frac{a_2}{r} , \quad B = \displaystyle \frac{a_2}{r} - a_1
\end{aligned}
\text{とおくと明らかに}A,B\text{は実数で、}
  a_n = (A + B n) r^{n-1}
\text{の形で書ける。これで命題の主張が示された。Q.E.D}
\textbf{【注意】}
r_1 \neq r_2 \text{ の互いに異なる解の場合は上の議論は使えないため別扱いで，そのときは } a_n = A r_1^{n-1} + B r_2^{n-1} \text{ の形になる。}

\textbf{【方針】}
\text{13で割った余り(mod 13)を使う。}
\textbf{【解法】}
\text{mod 13で考えると、}
\begin{aligned}
    x^2 + 13y^2 &\equiv x^2 \pmod{13} \\
    413 &= 13 \times 31 + 10 \equiv 10 \pmod{13}
    \end{aligned}
\text{よって } x^2 \equiv 10 \pmod{13} \text{ が必要である。}
mod\ 13\text{での}x^2\text{の余りを調べると、}
\begin{aligned}
    0^2 &\equiv 0,\quad 1^2 \equiv 1,\quad 2^2 \equiv 4,\quad 3^2 \equiv 9 \\
    4^2 &\equiv 3,\quad 5^2 \equiv 12,\quad 6^2 \equiv 10,\quad 7^2 \equiv 10 \\
    8^2 &\equiv 12,\quad 9^2 \equiv 3,\quad 10^2 \equiv 9,\quad 11^2 \equiv 4,\quad 12^2 \equiv 1
    \end{aligned}
\text{したがって } x \equiv \pm 6 \pmod{13} \text{ または } x \equiv \pm 7 \pmod{13} \text{ である。}
\text{よって、 } x = 13k \pm 6 \text{ または } x = 13k \pm 7 \text{ と表せる。}
\text{ }x^2 \le 413 \text{ より } |x| \le 20 \text{ なので、候補は } x = \pm 6, \pm 7, \pm 19, \pm 20 \text{ である。}
\text{各場合について } y^2 = \frac{413 - x^2}{13} \text{ が平方数になるか調べる。}
\textcolor{blue}{x = \pm 20}\textcolor{blue}{ の場合}
\text{ }y^2 = \frac{413 - 400}{13} = \frac{13}{13} = 1 \text{ より } \textcolor{green}{y = \pm 1}
\textcolor{blue}{x = \pm 19}\textcolor{blue}{ の場合}
\text{ }y^2 = \frac{413 - 361}{13} = 4 \text{ より } \textcolor{green}{y = \pm 2}
\textcolor{red}{他の候補 } \textcolor{red}{6, \pm 7} \textcolor{red}{については、} \text{それぞれ} y^2 = \frac{413 - 6^2}{13} = \frac{377}{13} = 29 \text{ と } y^2 = \frac{413 - 7^2}{13} = \frac{364}{13} = 28 \text{ となり、}\textcolor{red}{平方数にならない。}
\text{よって、整数解は }(x,y)=(20,1),(20,-1),(-20,1),(-20,-1),(19,2),(19,-2),(-19,2),(-19,-2)\text{ である。}

\textbf{【方針】}
\text{最低次の変数 } c \text{ について整理する。(aについては3次,bについては2次,cについては1次)}
\textbf{【途中式変形】}
\text{ } c \text{ について整理すると、}
\begin{aligned}
&\ \ a^3 - a b^2 - b^2 c + a^2 c \\
&= c(a^2 - b^2) + a(a^2 - b^2) \\
&= (c+a)(a^2 - b^2) \\
&= (a+c)(a-b)(a+b)
\end{aligned}

\textbf{【方針】}
\; x=\tan\theta \,\textbf{ と置換する。}
\textbf{【解説】}
x=\tan\theta\text{とすると、}
dx =\displaystyle  \frac{dx}{d\theta} d\theta =\displaystyle \frac{1}{\cos ^2 \theta} d\theta
x = 0 \rightarrow 1 \text{の時、} \tan \theta =0\rightarrow \displaystyle \frac {\pi}{4}\text{より、}
\begin{aligned}
\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1+x^{2}}
=&\displaystyle \int_{0}^{ \frac{\pi}{4}}\displaystyle \frac{1}{1+\tan^{2}\theta} \frac{1}{\cos^{2}\theta} d\theta\\
=&\displaystyle \int_{0}^{ \frac{\pi}{4}}\displaystyle \frac{1}{1+\tan^{2}\theta} (1+\tan^{2}\theta) d\theta\\
=&\displaystyle \int_{0}^{ \frac{\pi}{4}}1\,d\theta\\
=&\left.\theta\right|_{0}^{ \frac{\pi}{4}}\\
=&\displaystyle \frac{\pi}{4}
\end{aligned}
\textbf{【補足】}
\; tan\text{の逆関数}\arctan \text{を用いると、} \displaystyle \int \displaystyle \frac{dx}{1+x^{2}}=\arctan x + C \text{であり、これを用いると早い。}

