\textbf{【方針】}
\text{因数定理を使う。}
\textbf{【途中式変形】}
\text{ } x = -1 \text{ を代入すると、}
\begin{aligned}
&(-1)^4 + 2(-1)^3 + 2(-1)^2 + 2(-1) + 1 \\
&= 1 - 2 + 2 - 2 + 1 \\
&= 0
\end{aligned}
\text{よって、} x^4 + 2x^3 + 2x^2 + 2x + 1 \text{は} x + 1 \text{ を因数にもつ。実際、} x^4 + 2x^3 + 2x^2 + 2x + 1 \text{を} x + 1 \text{で割ると、} x^3 + x^2 + x + 1 \text{ となる。ゆえに、}
\begin{aligned}
x^4 + 2x^3 + 2x^2 + 2x + 1 &= (x + 1)\textcolor{blue}{(x^3 + x^2 + x + 1)}\\[7pt]
\end{aligned}
\text{次に、 } x^3 + x^2 + x + 1 \text{ について、 } x = -1 \text{ を代入すると、}
\begin{aligned}
(-1)^3 + (-1)^2 + (-1) + 1 &= -1 + 1 - 1 + 1 \\
&= 0
\end{aligned}
\text{よって、} x^3 + x^2 + x + 1　\text{は} x + 1 \text{ を因数にもつ。実際、} x^3 + x^2 + x + 1 \text{を} x + 1 \text{で割ると、} x^2 + 1 \text{ となる。ゆえに、}
\textcolor{blue}{x^3 + x^2 + x + 1} = \textcolor{red}{(x + 1)(x^2 + 1)}
\text{したがって、}
\begin{aligned}
x^4 + 2x^3 + 2x^2 + 2x + 1 &= (x + 1)\textcolor{blue}{(x^3 + x^2 + x + 1)} \\
&= (x + 1)\textcolor{red}{(x + 1)}\textcolor{red}{(x^2 + 1)} \\
&= (x + 1)^2(x^2 + 1)
\end{aligned}

\color{black}\textbf{【解答】}
\color{black}\displaystyle \int_{0}^{x}t^{5}e^{-t}\,dt =\Bigl[-t^{5}e^{-t}\Bigr]_{0}^{x}+5\int_{0}^{x}t^{4}e^{-t}\,dt
\color{black}\text{ここで }t=0\text{ のとき }t^{5}e^{-t}=0\text{ なので}
\color{black} \ \ \ \ \ =-x^{5}e^{-x}+5\int_{0}^{x}t^{4}e^{-t}\,dt
\color{black}\textbf{【もう1度、部分積分】}
\color{black}\displaystyle \int_{0}^{x}t^{4}e^{-t}\,dt=\Bigl[-t^{4}e^{-t}\Bigr]_{0}^{x}+4\int_{0}^{x}t^{3}e^{-t}\,dt
\color{black}\text{ }t=0\text{ では }t^{4}e^{-t}=0\text{ なので}
\color{black}\ \ \ \ \ =-x^{4}e^{-x}+4\int_{0}^{x}t^{3}e^{-t}\,dt
\color{black}\text{よって、 }
\color{black}\begin{aligned}
 \int_{0}^{x}t^{5}e^{-t}\,dt
 &= -x^{5}e^{-x}+5\int_{0}^{x}t^{4}e^{-t}\,dt \\[4pt]
&= -x^{5}e^{-x}
+5\Bigl(-x^{4}e^{-x}
+4\int_{0}^{x}t^{3}e^{-t}\,dt\Bigr)\\[4pt]
&= -x^{5}e^{-x}-5x^{4}e^{-x}
+5\cdot4\int_{0}^{x}t^{3}e^{-t}\,dt
\end{aligned}
\color{black}\text{以後も同様にして、積分の次数を }5,4,3,2,1,0\text{ と下げていける。}
\color{black}\text{すると最終的に次の形になる。(第一項はすぐに後述するように、limを取ると消える)}
\color{black}\begin{aligned}
\int_{0}^{x}t^{5}e^{-t}\,dt
&= -e^{-x}\Bigl(x^{5}+5x^{4}+5\cdot4x^{3}+5\cdot4\cdot3x^{2}+5\cdot4\cdot3\cdot2x+5!\Bigr)\\[4pt]
&\quad +5!\int_{0}^{x}e^{-t}\,dt
\end{aligned}
\color{black}\textbf{【}x\to\infty\textbf{ とする】}
\color{black}\text{ }e^{-x}\text{ は非常に速く }0\text{ に近づくので、}e^{-x}\times(\text{多項式})\to0\text{より、}
\begin{aligned}
    \displaystyle \lim_{x\to \infty } \int_{0}^{x}t^{5}e^{-t}\,dt  &= 0 + 5!\int_{0}^{x}e^{-t}\,dt\\[5pt]
    &= 5!\int_{0}^{x}e^{-t}\,dt \\[5pt]
    &= 5!\lim_{x\to \infty } \Bigl[-e^{-t}\Bigr]_{0}^{x}\\[6pt]
    &= 5!\lim_{x\to \infty } (1-e^{-x}) \\[6pt]
    &= 5!(1-0)\\[6pt]
    &=\textcolor{green}{120}
    \end{aligned}
\color{black}\textbf{【補足：一般の }n\textbf{ とガンマ関数】}
\color{black}\text{自然数 }n\text{ に対して }\displaystyle I_n(x)=\int_{0}^{x}t^{n}e^{-t}\,dt\text{ とおく。}
\color{black}\text{ 部分積分より}
\begin{aligned}
    I_n(x)&=\Bigl[-t^{n}e^{-t}\Bigr]_{0}^{x}+n\int_{0}^{x}t^{n-1}e^{-t}\,dt\\[6pt]
    &=-x^{n}e^{-x}+nI_{n-1}(x)
    \end{aligned}
\color{black}\text{この関係を繰り返し用いて }x\to\infty\text{ とすると、}\lim_{x\to\infty}I_n(x)=n!\text{ が得られる。}
\color{black}\text{ガンマ関数は }\Gamma(s)=\displaystyle \int_{0}^{\infty}t^{s-1}e^{-t}\,dt\ (s>0)\text{ と定義され、}
\color{black}\text{自然数 }n\text{ に対して }\Gamma(n+1)=n!\text{ が成り立つ。}

