\textbf{【方針】}
\text{右辺が定数なので解の一つを定数列} A \text{ の形で求め、これを使ってただの等比数列の式に帰着させる。}
\textbf{【解法】}
\text{解の形を定数列}A \text{と仮定して、元の漸化式に代入すると、} A = 2A + 3 \text{ である。}
\begin{aligned}
    &\ \ \ \ \ A = 2A + 3 \\
    &\Leftrightarrow A = -3
    \end{aligned}
\text{解 } A = -3 \text{ を元の漸化式に代入すると、} -3 = 2 \cdot (-3) + 3 \cdots (1) \text{ である。}
\text{ここで、元の漸化式から(1)を引いて、新たな数列}b_n = a_n + 3\text{ を定義すると、等比数列の形に帰着させることができる。実際、}
\begin{aligned}
      a_{n+1} &= 2a_n + 3 \\
      -3 &= 2 \cdot (-3) + 3 \\
      \hline
      \ \ \ \ \ a_{n+1} - (-3) &= 2a_n + 3 - (2 \cdot (-3) + 3) \\
      \Leftrightarrow a_{n+1} + 3 &= 2a_n + 3 - (-6 + 3) \\
      \Leftrightarrow a_{n+1} + 3 &= 2(a_n + 3)
      \end{aligned}
\text{よって、 } b_n  = a_n + 3 \text{ とおくと、}
\begin{aligned}
      \begin{cases}
    \ b_{n+1} = 2b_n \\
    \ b_1 = a_1 + 3 = 4
    \end{cases}
    \end{aligned}
\text{上の漸化式は等比数列の形で、} b_n = 4 \cdot 2^{n-1} = 2^{n+1} \text{ なので、}
\begin{aligned}
    &\ \ \ \ \ a_n = b_n - 3 \\
    &\Leftrightarrow a_n = 2^{n+1} - 3
    \end{aligned}

