\textcolor{brown}{\large{【電磁気学】}}
\text{• コンデンサのみの回路に交流をかけた時、キルヒホッフ第二法則を適用すると、} \displaystyle \frac{Q(t)}{C} = V_0\sin(\omega t) \text{という微分方程式が出てくる。}
\text{• 電圧 }V_0\sin(\omega t)\text{ の位相}\omega t \text{よりも、電流 }I(t)\text{ の位相は}\displaystyle \frac{\pi}{2}\text{進む。}
\text{• 電流 }I(t)\text{ の振幅は電圧振幅の} \omega C \text{倍}  (容量性リアクタンス)
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{コンデンサのみ交流回路:} \ \displaystyle \frac{Q(t)}{C} = V_0\sin(\omega t)
\text{• } f(t) \leftrightarrow I(t) \text{（電流）}
\text{• } 0.2 \leftrightarrow C \text{（静電容量）}
\text{• } 8 \leftrightarrow V_0 \text{（電圧振幅）}
\text{• } 10 \leftrightarrow \omega \text{（角周波数）}
\text{• } f(0)=0 \leftrightarrow I_0=0 \text{（初期電流）}
\text{• }\displaystyle \frac{1}{10 \times 0.2}  = \frac 1 2 \leftrightarrow X_C = \displaystyle \frac{1}{\omega C} \text{(容量性リアクタンス)}
\textcolor{brown}{\large{【解法】}}
\displaystyle \frac{\int_0^t f(s) \, ds}{0.2} = 8\sin(10t)
\text{両辺を}0.2\text{で掛ける：}
\Leftrightarrow \ \int_0^t f(s) \, ds = 1.6\sin(10t)
\text{両辺を微分：}
\Leftrightarrow \ f(t) = 1.6 \times 10\cos(10t)
\Leftrightarrow \ f(t) = 16\cos(10t)
\text{位相差を明確にするため、三角関数の変換公式で変形：}
\Leftrightarrow \ f(t) = 16\sin\left(10t + \displaystyle \frac{\pi}{2}\right)

\textbf{【方針】}
\; u=\log x \,\textbf{ と置くと、}\,
du= \frac{dx}{x} \textbf{を用いる。}
\textbf{【解説】}
\text{まず原始関数（不定積分）を求める。}
\begin{aligned}
\displaystyle \int \displaystyle \frac{dx}{x\log x}
&= \displaystyle \int \displaystyle \frac{1}{u}\,du\\
&= \log|u|+C\\
&= \log|\log x|+C
\end{aligned}
\text{したがって、定積分は、}
\text{積分範囲の変換：}
\begin{aligned}
\begin{cases}
x=e \Leftrightarrow u=\log e=1,\\[5pt]
x=e^{2} \Leftrightarrow u=\log(e^{2})=2
\end{cases}
\end{aligned}
\begin{aligned}
\displaystyle \int_{e}^{e^{2}} \displaystyle \frac{dx}{x\log x}
&= \int_{1}^{2} \displaystyle \frac{1}{u}\,du\\
&= \left[\log|u|\right]_{1}^{2}\\
&= \log 2 - \log 1\\
&= \log 2 - 0\\
&= \log 2
\end{aligned}
\textbf{【補足】}
\text{定義域 } x>1 \text{（} x>0 \text{で } \log x \text{が定義され、さらに } x>1 \text{で } \log x>0 \text{ となる）}

\textbf{【方針】 }
x^{5}-1=(x-1)\bigl(x^{4}+x^{3}+x^{2}+x+1\bigr)
と因数分解してから、x\to 1 の極限をとる。
\begin{aligned}
    \frac{x^{5}-1}{x-1}
    =&x^{4}+x^{3}+x^{2}+x+1
    \end{aligned}
\begin{aligned}
    \ \therefore\  & \lim_{x\to 1}\frac{x^{5}-1}{x-1} \\[6pt]
    =&\lim_{x\to 1} \left( x^{4}+x^{3}+x^{2}+x+1 \right)\\[6pt]
    =&1+1+1+1+1 \\[5pt]
    =&\displaystyle 5
    \end{aligned}

\textbf{【方針】}
f(x) = x^5+x^4 +1\text{とおいて、まずは、因数定理を用い、候補（±1）を代入して、1次式の因数を持たないことを認識したら、その後、2次式×3次式の形で係数比較を行うのが自然。}
\textbf{【途中式変形】}
\text{因数定理の候補を代入すると、}
\begin{aligned}
 f(1) &= 1 + 1 + 1 = 3 \neq 0 \\
 f(-1) &= -1 + 1 + 1 = 1 \neq 0
 \end{aligned}
\text{よって、1次式の因数を持たない。よって2次式×3次式の因数分解を探す。}
\text{整数係数で } f(x) = (x^2 + ax + \alpha)(x^3 + bx^2 + cx + \beta) \text{ とおく。}
\textcolor{red}{実は計算すると、下記のように計算できる。}
\textcolor{red}{a = 1,\ b = 0,\ c = -1,\ \alpha = 1,\ \beta = 1}
\textcolor{red}{以下ではこの証明を行う。}
\textbf{【証明】}
\text{ここで } x^5 + x^4 + 1 \text{ の定数項が } 1 \text{ であることから、 } \alpha\beta = 1 \text{ であるため、 } (\alpha, \beta) = (1, 1), (-1, -1) \text{ の場合に分けて解を探す。}
\textcolor{blue}{1. } \textcolor{blue}{(\alpha, \beta) = (1, 1)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax + 1)(x^3 + bx^2 + cx + 1) \text{ とおくと、}
\begin{aligned}
 &\ \ \ \ x^5 + x^4 + 1 \\
 &= (x^2 + ax + 1)(x^3 + bx^2 + cx + 1) \\
 &= x^5 + (a+b)x^4 + (ab + c + 1)x^3 + (ac + b + 1)x^2 + (a + c)x + 1
 \end{aligned}
\text{係数比較より、}
\begin{aligned}
 &\text{4次: } a + b = 1\ \cdots (1) \\[2pt]
 &\text{3次: } ab + c + 1 = 0\ \ \cdots (2) \\[2pt]
 &\text{2次: } ac + b + 1 = 0\ \ \cdots (3) \\[2pt]
 &\text{1次: } a + c = 0\ \ \cdots (4)
 \end{aligned}
\text{(4),(1) より } c = -a, b = 1 - a \text{これを(2)に代入して、}
a(1 - a) - a + 1 = a - a^2 - a + 1 = -a^2 + 1 = 0 \text{、すなわち } a^2 = 1
\text{これより } a = 1 \text{ または } a = -1 \text{ を得る。}
\textcolor{blue}{(i) } \textcolor{blue}{a = 1 のとき}
\text{ } b = 0, c = -1 \text{、このとき (3) より、}
\begin{aligned}
 ac + b + 1 &= 1 \cdot (-1) + 0 + 1 = 0
 \end{aligned}
\text{であるので、(3)を満たし、(1),(2),(3),(4)の連立方程式の解は}
\textcolor{green}{\begin{aligned}
 a = 1, \quad b = 0, \quad c = -1
 \end{aligned}}
\textcolor{green}{したがって、} \textcolor{green}{(a, b, c, \alpha, \beta) = (1, 0, -1, 1, 1)}\textcolor{green}{となり、答えは}
\textcolor{green}{ x^5 + x^4 + 1 = (x^2 + x + 1)(x^3 - x + 1) }
\textcolor{brown}{\large{これで答えは得られたが、一応、}}
\textcolor{brown}{\large{他に解がないことを下記で確認しておく。}}
\textcolor{blue}{(ii) } \textcolor{blue}{a = -1 のとき}
\text{ } b = 2, c = 1 \text{、このとき (3) より、}
\begin{aligned}
 ac + b + 1 &= (-1) \cdot 1 + 2 + 1 = 2 \neq 0
 \end{aligned}
\textcolor{red}{したがってこの場合は(3)を満たさない。}
\textcolor{blue}{2. } \textcolor{blue}{(\alpha, \beta) = (-1, -1)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax - 1)(x^3 + bx^2 + cx - 1) \text{ とおくと、}
\begin{aligned}
 &\ \ \ \ x^5 + x^4 + 1 \\
 &= (x^2 + ax - 1)(x^3 + bx^2 + cx - 1) \\
 &= x^5 + (a+b)x^4 + (ab + c - 1)x^3 + (ac - b - 1)x^2 + (a + c)x + 1
 \end{aligned}
\text{係数比較より、}
\begin{aligned}
 &\text{4次: } a + b = 1\ \cdots (1) \\[2pt]
 &\text{3次: } ab + c - 1 = 0\ \ \cdots (2) \\[2pt]
 &\text{2次: } ac - b - 1 = 0\ \ \cdots (3) \\[2pt]
 &\text{1次: } a + c = 0\ \ \cdots (4)
 \end{aligned}
\text{(4),(1) より } c = -a, b = 1 - a \text{これを(2)に代入して、}
\text{(2) より } a(1 - a) - a - 1 = a - a^2 - a - 1 = -a^2 - 1 = 0 \text{、すなわち } a^2 = -1
\textcolor{red}{これは実数解を持たない。}

\textbf{【方針】}
\text{連立漸化式の一方を用いて他方を消去し，}a_n\text{ のみの３項間漸化式に帰着させる。得られた漸化式の特性方程式が重根 } r=5 \text{ になるので，重解版の命題を適用して一般項を求める。}
\textbf{【解法】}
\text{(1) 第一式から } b_n = a_{n+1} - 6a_n \text{ と表せる。また、}n\text{を}n+1\text{とすると、} b_{n+1} =  a_{n+2} - 6a_{n+1}  \text{も成り立つ。これを第二式に代入すると、}
\begin{aligned}
&\ \ \ \ \ b_{n+1} = -a_n + 4b_n \\
&\Leftrightarrow a_{n+2} - 6a_{n+1} = -a_n + 4(a_{n+1}-6a_n) \\
&\Leftrightarrow a_{n+2} -10 a_{n+1} +25 a_n = 0
\end{aligned}
\text{これで、}a_n\text{についての3項間漸化式に帰着できた。}
\text{特性方程式 }
\begin{aligned}
    &\ \ \ \ \ r^2 - 10 r + 25 = 0 \\
    &\Leftrightarrow (r-5)^2 = 0 \\
    &\Leftrightarrow r = 5
    \end{aligned}
\text{よって補足命題（重解版）より、解は} a_n = (A + Bn) \cdot 5^{\,n-1}\text{と表す事ができる。}
\text{(2) 初期条件から } A,B \text{ を求める}
\text{初期条件 } a_1=1,\ b_1=2 \text{ より、} a_2 = 6a_1 + b_1 = 8 \text{ である。}
\text{したがって}
\begin{aligned}
    \begin{cases}
      1 = A + B \\
      8 = (A + 2B) \cdot 5
    \end{cases}
    & \Leftrightarrow
    \begin{cases}
      A = \displaystyle \frac{2}{5} \\[6pt]
      B = \displaystyle \frac{3}{5}
    \end{cases}
    \end{aligned}
\textcolor{green}{したがって} \textcolor{green}{ a_n = \left(\displaystyle \frac{2}{5} + \displaystyle \frac{3}{5}n\right)5^{\,n-1} = (2+3n)5^{\,n-2}}
\text{(3) } b_n \text{ を明示的に求める（第1式より）}
\text{第1式 } a_{n+1}=6a_n+b_n \text{ より } b_n = a_{n+1}-6a_n \text{。一般項 } a_n = (2+3n)5^{\,n-2} \text{ を用いて計算すると，}
\begin{aligned}
b_n
&= \bigl((2+3(n+1))5^{\,n-1}\bigr)
   -6\bigl((2+3n)5^{\,n-2}\bigr)\\[6pt]
&= (5+3n)5^{\,n-1} - (12+18n)5^{\,n-2}\\[6pt]
&= (5+3n) \cdot 5 \cdot 5^{\,n-2} - (12+18n)5^{\,n-2}\\[6pt]
&= (25+15n)5^{\,n-2} - (12+18n)5^{\,n-2}\\[6pt]
&= \textcolor{green}{(13 - 3n)5^{\,n-2}}
\end{aligned}
\textbf{【補足命題（重解版）】}
\text{漸化式 } a_{n+2} + p a_{n+1} + q a_n = 0 \text{と、実数の初期条件} a_1,a_2\text{が与えられたとする。}
\text{この時、漸化式に対して定まる二次方程式} r^2 + p r + q = 0 \text{が重根 } r \text{を持つとき、一般項} a_n \textcolor{green}{はある実数} \textcolor{green}{A,B} \textcolor{green}{を用いて}
\textcolor{green}{a_n = (A + B n) r^{\,n-1}} \textcolor{green}{ と表す事ができる。}
\text{※ ただし、} A,B \text{ は初期条件}a_1, a_2\text{によって定まる実数。}
\textbf{【証明】}
\text{特性方程式が重根 } r \text{ を持つとき、解と係数の関係より } 2r = -p, r^2 = q \text{であるから、次の式が成り立つ：}
\begin{aligned}
  &a_{n+2}-r a_{n+1} = r\bigl(a_{n+1}-r a_n\bigr)
\end{aligned}
\text{ここで}
b_n := a_{n+1}-r a_n
\text{と置くと，上の恒等式から}
  b_{n+1}=r b_n
\text{が成り立つ。したがって初項}
  b_1 = a_2 - r a_1
\text{に対して、}
  b_n = b_1 r^{\,n-1} \quad\cdots(1)
\text{である。}

\text{一方，} b_n \text{の定義から}
\begin{aligned}
  a_{n+1} - r a_n &= b_1 r^{\,n-1}
\end{aligned}
\text{この両辺を } r^{n+1} \text{ で割ると（ } r \neq 0 \text{ を仮定）、}
\begin{aligned}
  \displaystyle \frac{a_{n+1}}{r^{n+1}} - \displaystyle \frac{a_n}{r^n} &= \displaystyle \frac{b_1}{r^2}
\end{aligned}
\text{ここで } u_n := \displaystyle \frac{a_n}{r^n} \text{ と置くと，}
\begin{aligned}
  u_{n+1} - u_n &= \displaystyle \frac{b_1}{r^2}
\end{aligned}
\text{従って } (u_n) \text{ は公差 } \displaystyle \frac{b_1}{r^2} \text{ の等差数列であり，初項 } u_1 = \displaystyle \frac{a_1}{r} \text{ を用いて}
  u_n = \displaystyle \frac{a_1}{r} + (n-1)\displaystyle \frac{b_1}{r^2}
\text{である。}

b_1 = a_2 - r a_1 \text{を用いて元に戻すと、}
\begin{aligned}
  a_n &= u_n r^n \\
  &= \left(\displaystyle \frac{a_1}{r} + (n-1)\displaystyle \frac{b_1}{r^2}\right) r^{n} \\
  &= \left(a_1 + (n-1)\displaystyle \frac{a_2 - r a_1}{r}\right) r^{\,n-1} \\
  &= \left( \left(a_1 - \displaystyle \frac{a_2 - r a_1}{r}\right) + \left(\displaystyle \frac{a_2 - r a_1}{r}\right)n \right)r^{\,n-1} \\
  &= \left( \left(2a_1 - \displaystyle \frac{a_2}{r}\right) + \left(\displaystyle \frac{a_2}{r} - a_1\right)n \right)r^{\,n-1}
\end{aligned}
\text{右辺について，}
\begin{aligned}
  A = 2a_1 - \displaystyle \frac{a_2}{r} , \quad B = \displaystyle \frac{a_2}{r} - a_1
\end{aligned}
\text{とおくと明らかに}A,B\text{は実数で、}
  a_n = (A + B n) r^{n-1}
\text{の形で書ける。これで命題の主張が示された。Q.E.D}
\textbf{【注意】}
\text{命題中の議論は } r\neq0 \text{ を仮定している（ここは } r=5\neq0 \text{ なので問題ない）。}

\textbf{【途中式変形】}
\begin{aligned}
36x^2 - 25y^2 &= (6x)^2 - (5y)^2 \\
&= (6x - 5y)(6x + 5y)
\end{aligned}

\textbf{【ポイント】}
\text{因数定理を用いる。定数項が } -6 \text{ なので、} \pm 1, \pm 2, \pm 3, \pm 6 \text{が候補。}
\textbf{【解説】}
\begin{aligned}
f(-1) &= (-1)^3 + 2 \cdot (-1)^2 - 5 \cdot (-1) - 6 \\
&= -1 + 2 + 5 - 6 = 0
\end{aligned}
\text{よって、} x + 1 \text{ が因数。}
\text{ } x^3 + 2x^2 - 5x - 6 \text{ を } x + 1 \text{ で割ると、}
\begin{aligned}
x^3 + 2x^2 - 5x - 6 &= (x + 1)(x^2 + x - 6) \\
&= (x + 1)(x + 3)(x - 2)
\end{aligned}

\textbf{【解答】}
\text{分母分子に } $e^{x}$ \text{ を掛け、} $\displaystyle \lim_{u\to 0}\frac{e^{u}-1}{u}=1$ \text{ を用いる}
\begin{aligned}
  \lim_{x\to 0}\frac{e^{x}-e^{-x}}{2x} &= \lim_{x\to 0}\frac{e^{x}-e^{-x}}{2x}\cdot\frac{e^{x}}{e^{x}} \\[6pt]
  &= \lim_{x\to 0}\frac{e^{2x}-1}{2x}\cdot\frac{1}{e^{x}} \\[6pt]
  &= \left(\lim_{x\to 0}\frac{e^{2x}-1}{2x}\right)\cdot\left(\lim_{x\to 0}\frac{1}{e^{x}}\right) \\[6pt]
  &= 1 \cdot \frac{1}{1} \\[6pt]
  &= 1 \cdot 1 \\[6pt]
  &= 1
  \end{aligned}

\textbf{【方針】}
\text{因数定理を使う。}
\textbf{【途中式変形】}
\text{ } x = 1 \text{ を代入すると、}
\begin{aligned}
 &1^4 - 3 \cdot 1^3 + 3 \cdot 1^2 - 3 \cdot 1 + 2 \\
 &= 1 - 3 + 3 - 3 + 2 \\
 &= 0
 \end{aligned}
\text{よって、} x^4 - 3x^3 + 3x^2 - 3x + 2 \text{は} x - 1 \text{ を因数にもつ。実際、} x^4 - 3x^3 + 3x^2 - 3x + 2 \text{を} x - 1 \text{で割ると、} x^3 - 2x^2 + x - 2 \text{ となる。ゆえに、}
\begin{aligned}
 x^4 - 3x^3 + 3x^2 - 3x + 2 &= (x - 1)\textcolor{blue}{(x^3 - 2x^2 + x - 2)}\\[7pt]
 \end{aligned}
\text{次に、 } x^3 - 2x^2 + x - 2 \text{ について、 } x = 2 \text{ を代入すると、}
\begin{aligned}
 2^3 - 2 \cdot 2^2 + 2 - 2 &= 8 - 8 + 2 - 2 \\
 &= 0
 \end{aligned}
\text{よって、} x^3 - 2x^2 + x - 2　\text{は} x - 2 \text{ を因数にもつ。実際、} x^3 - 2x^2 + x - 2 \text{を} x - 2 \text{で割ると、} x^2 + 1 \text{ となる。ゆえに、}
\textcolor{blue}{x^3 - 2x^2 + x - 2} = \textcolor{red}{(x - 2)(x^2 + 1)}
\text{したがって、}
\begin{aligned}
 x^4 - 3x^3 + 3x^2 - 3x + 2 &= (x - 1)\textcolor{blue}{(x^3 - 2x^2 + x - 2)} \\
 &= (x - 1)\textcolor{red}{(x - 2)}\textcolor{red}{(x^2 + 1)} \\
 &= (x - 1)(x - 2)(x^2 + 1)
 \end{aligned}

\textbf{【方針】}
\text{定数解を } A \text{ の形で求め、これを使ってただの等比数列の式に帰着させる。}
\textbf{【解法】}
\text{解の形を}A \text{と仮定して、元の漸化式に代入すると、} A = \displaystyle \frac{4A + 3}{A + 2} \text{ である。}
\begin{aligned}
    &\ \ \ \ \ \ A(A + 2) = 4A + 3 \\
    &\Leftrightarrow A^2 + 2A = 4A + 3 \\
    &\Leftrightarrow A^2 - 2A - 3 = 0 \\
    &\Leftrightarrow (A - 3)(A + 1) = 0
    \end{aligned}
\text{よって、定数解は } A = 3 \text{ または } A = -1 \text{ である。}
\text{一つの解 } A = 3 \text{ を選んで、元の漸化式に代入すると、} 3 = \displaystyle \frac{4 \cdot 3 + 3}{3 + 2} \cdots (1) \text{ である。}
\text{ここで命題1より、新たな数列}b_n = a_n - 3 \text{ を定義すると、分子の定数をなくした形に帰着させられる事が分かる。実際、元の漸化式から(1)を引いて、}
\begin{aligned}
      a_{n+1} &= \displaystyle \frac{4a_n + 3}{a_n + 2}  \\
      3 &= \displaystyle \frac{4 \cdot 3 + 3}{3 + 2} \cdots (1) \\
      \hline
      \ \ \ \ \ a_{n+1} - 3 &= \displaystyle \frac{4a_n + 3}{a_n + 2} - \displaystyle \frac{4 \cdot 3 + 3}{3 + 2} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{4a_n + 3}{a_n + 2} - 3 \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{4a_n + 3 - 3(a_n + 2)}{a_n + 2} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{4a_n + 3 - 3a_n - 6}{a_n + 2} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{a_n - 3}{a_n + 2}
      \end{aligned}
\text{ } b_n = a_n - 3 \text{ とおくと、} b_1 = a_1 - 3 = 2 - 3 = -1,\text{であり、}a_n = b_n + 3 \text{ である。これを代入すると、}
\begin{aligned}
    b_{n+1} &= \displaystyle \frac{b_n + 3 - 3}{b_n + 3 + 2} \\
    &= \displaystyle \frac{b_n}{b_n + 5}
    \end{aligned}
\text{両辺の逆数を取ると、}
\begin{aligned}
    &\ \ \ \ \ \displaystyle \frac{1}{b_{n+1}} = \displaystyle \frac{b_n + 5}{b_n} \\
    &\Leftrightarrow \displaystyle \frac{1}{b_{n+1}} = 1 + \displaystyle \frac{5}{b_n}
    \end{aligned}
\text{ } c_n = \displaystyle \frac{1}{b_n} \text{ とおくと、} c_{n+1} = 1 + 5c_n, c_1 = \frac 1 {b_1} = \frac 1 {-1} = -1  \text{ である。これを解くと、} c_n = -\displaystyle \frac{3 \cdot 5^{n-1} + 1}{4}
\text{よって、}
\begin{aligned}
    &\ \ \ \ \ b_n = \displaystyle \frac{1}{c_n} \\
    &\Leftrightarrow b_n = -\displaystyle \frac{4}{3 \cdot 5^{n-1} + 1}
    \end{aligned}
\text{ここから、} a_n = b_n + 3 \text{ より、}a_n\text{を求めると、}
\begin{aligned}
    &\ \ \ \ \ a_n = b_n + 3 \\
    &\Leftrightarrow a_n = 3 - \displaystyle \frac{4}{3 \cdot 5^{n-1} + 1}
    \end{aligned}
\textbf{【命題1】}
\text{分数型の漸化式 } a_{n+1} = \displaystyle \frac{pa_n + q}{ra_n + s} \text{ が与えられたとき、定数解 } A \text{ を } A = \displaystyle \frac{pA + q}{rA + s} \text{ を満たすものとする。}
\text{このとき、} b_n = a_n - A \text{ とおくと、} b_{n+1} = \displaystyle \frac{(p - rA)b_n}{rb_n + rA + s} \text{ となり、分子の定数項がない漸化式に帰着する。}
\textbf{【証明】}
\text{定数解 } A \text{ は } A = \displaystyle \frac{pA + q}{rA + s} \text{ を満たすとする。両辺に } rA + s \text{ をかけると、}
\begin{aligned}
    &\ \ \ \ \ A(rA + s) = pA + q \\
    &\Leftrightarrow rA^2 + sA = pA + q \\
    &\Leftrightarrow rA^2 + (s - p)A - q = 0 \\
    &\Leftrightarrow rA^2 + (s - p)A - q = 0 \cdots (1)
    \end{aligned}
\text{ここで、} b_n = a_n - A \text{ とおくと、} a_n = b_n + A \text{ である。これを元の漸化式に代入すると、}
\begin{aligned}
    b_{n+1} + A &= \displaystyle \frac{p(b_n + A) + q}{r(b_n + A) + s} \\
    &= \displaystyle \frac{pb_n + pA + q}{rb_n + rA + s}
    \end{aligned}
\begin{aligned}
    b_{n+1} &= \displaystyle \frac{pb_n + pA + q}{rb_n + rA + s} - A \\
    &= \displaystyle \frac{pb_n + pA + q - A(rb_n + rA + s)}{rb_n + rA + s} \\
    &= \displaystyle \frac{pb_n  - rAb_n - (rA^2 + (s-p)A - q) }{rb_n + rA + s} \\
    \end{aligned}
\text{ここで、} A\text{は、(1)を満たし、分子の}rA^2 + (s-p)A - q\text{は0であるから、}
\begin{aligned}
      &=\displaystyle \frac{pb_n  - rAb_n}{rb_n + rA + s} \\
      &= \displaystyle \frac{(p - rA)b_n}{rb_n + rA + s} \\
    \end{aligned}
\text{よって、} b_{n+1} = \displaystyle \frac{(p - rA)b_n}{rb_n + rA + s} \text{ となり、分子の定数項がない漸化式に帰着し、命題が示された。}

\textbf{【方針】}
x^2-4=(x-2)(x+2) \text{に因数分解して部分分数分解を行う。}
\textbf{【部分分数分解】}
\text{分母を因数分解すると、} x^2-4=(x-2)(x+2) \text{である。}
\text{部分分数分解の形を設定する：}
\displaystyle \frac{1}{x^2-4}=\displaystyle \frac{A}{x-2}+\displaystyle \frac{B}{x+2}
\text{両辺に } (x-2)(x+2) \text{ を掛けると、}
1=A(x+2)+B(x-2)
\text{右辺を展開すると、}
1=(A+B)x+(2A-2B)
\text{係数比較により、}
\begin{cases}
A+B=0\\
2A-2B=1
\end{cases}
\text{これを解くと、} A=\displaystyle \frac{1}{4}, B=-\displaystyle \frac{1}{4}
\text{したがって、}
\displaystyle \frac{1}{x^2-4}=\displaystyle \frac{1}{4}\cdot\displaystyle \frac{1}{x-2}-\displaystyle \frac{1}{4}\cdot\displaystyle \frac{1}{x+2}
\textbf{【積分の計算】}
\text{不定積分を求める：}
\begin{aligned}
\displaystyle \int\displaystyle \frac{1}{x^{2}-4}\,dx
&=\displaystyle \int\left(\displaystyle \frac{1}{4}\cdot\displaystyle \frac{1}{x-2}-\displaystyle \frac{1}{4}\cdot\displaystyle \frac{1}{x+2}\right)dx\\[6pt]
&=\displaystyle \frac{1}{4}\int\displaystyle \frac{1}{x-2}\,dx-\displaystyle \frac{1}{4}\int\displaystyle \frac{1}{x+2}\,dx\\[6pt]
&=\displaystyle \frac{1}{4}\log|x-2|-\displaystyle \frac{1}{4}\log|x+2|+C\\[6pt]
&=\displaystyle \frac{1}{4}\log\left|\displaystyle \frac{x-2}{x+2}\right|+C
\end{aligned}
\textbf{【定積分の評価】}
\text{積分範囲が } [3,6] \text{ なので、} x-2>0, x+2>0 \text{ より絶対値は不要である。}
\begin{aligned}
\displaystyle \int_{3}^{6}\displaystyle \frac{1}{x^{2}-4}\,dx
&=\left[\displaystyle \frac{1}{4}\log\displaystyle \frac{x-2}{x+2}\right]_{3}^{6}\\[6pt]
&=\displaystyle \frac{1}{4}\left(\log\displaystyle \frac{6-2}{6+2}-\log\displaystyle \frac{3-2}{3+2}\right)\\[6pt]
&=\displaystyle \frac{1}{4}\left(\log\displaystyle \frac{4}{8}-\log\displaystyle \frac{1}{5}\right)\\[6pt]
&=\displaystyle \frac{1}{4}\left(\log\displaystyle \frac{1}{2}-\log\displaystyle \frac{1}{5}\right)\\[6pt]
&=\displaystyle \frac{1}{4}\log\displaystyle \frac{\frac 1 2}{\frac 1 5}\\[6pt]
&=\displaystyle \frac{1}{4}\log\displaystyle \frac{5}{2}
\end{aligned}

\textbf{【方針】}
\text{対数を取って } \displaystyle\frac{\log(1+h)}{h}\text{ の極限を調べ、指数関数の連続性で元に戻す。}
\textbf{【計算】}
\lim_{h\to\infty}(1+h)^{\frac{1}{h}} \text{の対数を取ると、}
\begin{aligned}
      \log\left(\lim_{h\to\infty}(1+h)^{\frac{1}{h}}\right)
      &=\lim_{h\to\infty}\log\left((1+h)^{\frac{1}{h}}\right) \\[6pt]
      &=\textcolor{blue}{\lim_{h\to\infty}\frac{\log(1+h)}{h}\cdots(1)}
      \end{aligned}
\text{ここで、} \displaystyle \frac{\log(1+h)}{h} = \frac{\log(1+h)}{1+h}\cdot\frac{1+h}{h}
\text{とすると、既知の極限 } \displaystyle\lim_{h\to\infty}\frac{\log(1+h)}{1+h}=0,\ \lim_{h\to\infty}\frac{1+h}{h}=1 \text{ より、}\textcolor{blue}{(1)は}\textcolor{blue}{\displaystyle \lim_{h\to\infty}\frac{\log(1+h)}{h}} =  0 \cdot 1= 0
\text{したがって、} \displaystyle \log\left(\lim_{h\to\infty}(1+h)^{\frac{1}{h}}\right) = 0 \text{ より、} \displaystyle \lim_{h\to\infty}(1+h)^{\frac{1}{h}} = 1

\textbf{【ポイント】}
\text{共通因数 } xy \text{ をくくり出す。}
\textbf{【途中式変形】}
\begin{aligned}
 4x^3y - 9xy^3 &= xy(4x^2 - 9y^2) \\
 &= xy(2x-3y)(2x+3y)
 \end{aligned}

\textbf{【方針】}
\text{零点} x=\pm \displaystyle \frac{1}{2}\text{ で区間を}
        \left[-1,-\displaystyle \frac{1}{2}\right],\left[-\displaystyle \frac{1}{2},\displaystyle \frac{1}{2}\right],\left[\displaystyle \frac{1}{2},1\right]\text{ に分割して計算する。}
\textbf{【ポイント】}
\cdot\  x^2-\displaystyle \frac{1}{4}=0 \Leftrightarrow x=\pm\displaystyle \frac{1}{2}
        \text{で符号が変わる。}
\cdot \text{中央区間では }\displaystyle \frac{1}{4}-x^2\text{，外側区間では }x^2-\displaystyle \frac{1}{4}\text{を積分する。}
\cdot \text{偶関数なので積分区間を}\displaystyle 0 \rightarrow 1 \text{に変換すると楽。}
\textbf{【解説】}
\begin{aligned}
\displaystyle \int_{-1}^{1}\left|x^2-\displaystyle \frac{1}{4}\right|\,dx
&= 2\displaystyle \int_{0}^{1}\left|x^2-\displaystyle \frac{1}{4}\right|\,dx\\
&= 2\left(\displaystyle \int_{0}^{ \frac{1}{2}}\left(\displaystyle \frac{1}{4}-x^2\right)dx
    + \displaystyle \int_{ \frac{1}{2}}^{1}\left(x^2-\displaystyle \frac{1}{4}\right)dx\right)\\
&= 2\left(\left[\displaystyle \frac{x}{4}-\displaystyle \frac{x^3}{3}\right]_{0}^{ \frac{1}{2}}
    + \left[\displaystyle \frac{x^3}{3}-\displaystyle \frac{x}{4}\right]_{ \frac{1}{2}}^{1}\right)\\
&= 2\left(\left(\displaystyle \frac{1}{8}-\displaystyle \frac{1}{24}\right)-0
    + \left(\left(\displaystyle \frac{1}{3}-\displaystyle \frac{1}{4}\right)-\left(\displaystyle \frac{1}{24}-\displaystyle \frac{1}{8}\right)\right)\right)\\
&= 2\left(\displaystyle \frac{1}{8}-\displaystyle \frac{1}{24} + \displaystyle \frac{1}{3}-\displaystyle \frac{1}{4} -\displaystyle \frac{1}{24} +\displaystyle \frac{1}{8}\right)\\
&= 2\left(\displaystyle \frac{1}{8}+\displaystyle \frac{1}{8} -\displaystyle \frac{1}{24}-\displaystyle \frac{1}{24} +\displaystyle \frac{1}{3}-\displaystyle \frac{1}{4}\right)\\
&= 2\left(\displaystyle \frac{2}{8} -\displaystyle \frac{2}{24} +\displaystyle \frac{1}{12}\right)\\
&= 2\left(\displaystyle \frac{1}{4} -\displaystyle \frac{1}{12} +\displaystyle \frac{1}{12}\right)\\
&= 2\left(\displaystyle \frac{1}{4}\right)\\
&= \displaystyle \frac{1}{2}
\end{aligned}

\textbf{【方針】}
\text{右辺が2次式なので解の一つを} An^2 + Bn + C \text{ の形で求め、これを使ってただの等比数列の式に帰着させる。}
\textbf{【解法】}
\text{解の形を} An^2 + Bn + C \text{と仮定して、元の漸化式に代入すると、}
\begin{aligned}
    &\ \ \ \ \ A(n+1)^2 + B(n+1) + C = 2(An^2 + Bn + C) + n^2 + 1 \\
    &\Leftrightarrow A(n^2 + 2n + 1) + Bn + B + C = 2An^2 + 2Bn + 2C + n^2 + 1 \\
    &\Leftrightarrow An^2 + 2An + A + Bn + B + C = (2A + 1)n^2 + 2Bn + 2C + 1
    \end{aligned}
\text{係数を比較すると、}
\begin{aligned}
    &\begin{cases}
    A = 2A + 1 \\
    2A + B = 2B \\
    A + B + C = 2C + 1
    \end{cases} \\
    &\Leftrightarrow \begin{cases}
    A = -1 \\
    B = -2 \\
    C = -4
    \end{cases}
    \end{aligned}
\text{よって、解の一つは} \textcolor{green}{-n^2 - 2n - 4} \text{である。}
\text{求まった解を元の漸化式に代入すると、} -(n+1)^2 - 2(n+1) - 4 = 2(-n^2 - 2n - 4) + n^2 + 1 \cdots (1) \text{ である。}
\text{ここで、元の漸化式から(1)を引いて、新たな数列}b_n = a_n + n^2 + 2n + 4\text{ を定義すると、等比数列の形に帰着させることができる。実際、}
\begin{aligned}
      a_{n+1} &= 2a_n + n^2 + 1 \\
      -(n+1)^2 - 2(n+1) - 4 &= 2(-n^2 - 2n - 4) + n^2 + 1 \\
      \hline
      \ \ \ \ \ a_{n+1} - (-(n+1)^2 - 2(n+1) - 4) &= 2a_n + n^2 + 1 - (2(-n^2 - 2n - 4) + n^2 + 1) \\
      \Leftrightarrow a_{n+1} + (n+1)^2 + 2(n+1) + 4 &= 2a_n + n^2 + 1 - 2(-n^2 - 2n - 4) - n^2 - 1 \\
      \Leftrightarrow a_{n+1} + (n+1)^2 + 2(n+1) + 4 &= 2(a_n + n^2 + 2n + 4)
      \end{aligned}
\text{ } b_n = a_n + n^2 + 2n + 4 \text{ とおくと、} b_{n+1} = 2b_n \text{ である。}
\text{ } a_1 = 1 \text{ より、} b_1 = a_1 + 1^2 + 2 \cdot 1 + 4 = 1 + 1 + 2 + 4 = 8 \text{ だから、}
\begin{aligned}
    \begin{cases}
    \ b_{n+1} = 2b_n \\
    \ b_1 = 8
    \end{cases}
    \end{aligned}
\text{上の漸化式は等比数列の形で、} b_n = 8 \cdot 2^{n-1} = 2^{n+2} \text{ なので、}
\begin{aligned}
    &\ \ \ \ \ a_n = b_n - n^2 - 2n - 4 \\
    &\Leftrightarrow a_n = 2^{n+2} - n^2 - 2n - 4 \\
    \end{aligned}

\textbf{【方針】}
\text{部分和 }\displaystyle S_N=\displaystyle \sum_{k=1}^{N}\frac{1}{2^{k}}\sin\!\left(\frac{2k\pi}{3}\right)\text{ を考え、}
N=3M,3M+1,3M+2\text{ の3通りで同じ極限に収束することを示す。}
\textbf{【解答】}
\sin\!\left(\frac{2k\pi}{3}\right)=
\begin{cases}
\frac{\sqrt3}{2} & (k\equiv 1\!\!\!\pmod 3)\\[6pt]
-\frac{\sqrt3}{2} & (k\equiv 2\!\!\!\pmod 3)\\[6pt]
0 & (k\equiv 0\!\!\!\pmod 3)
\end{cases}
\textcolor{green}{まず } \textcolor{green}{N=3M} \textcolor{green}{ のとき}
\begin{aligned}
S_{3M}
&=\displaystyle \sum_{m=0}^{M-1}\left(
\frac{1}{2^{3m+1}}\sin\!\left(\frac{2(3m+1)\pi}{3}\right)
+\frac{1}{2^{3m+2}}\sin\!\left(\frac{2(3m+2)\pi}{3}\right)
+\frac{1}{2^{3m+3}}\sin\!\left(\frac{2(3m+3)\pi}{3}\right)
\right)\\
&=\displaystyle \sum_{m=0}^{M-1}\left(
\frac{1}{2^{3m+1}}\cdot\frac{\sqrt3}{2}
+\frac{1}{2^{3m+2}}\cdot\left(-\frac{\sqrt3}{2}\right)
+\frac{1}{2^{3m+3}}\cdot 0
\right)\\
&=\frac{\sqrt3}{2}\displaystyle \sum_{m=0}^{M-1}\left(\frac{1}{2^{3m+1}}-\frac{1}{2^{3m+2}}\right)
\end{aligned}
\text{ここで } \displaystyle \frac{1}{2^{3m+1}}-\frac{1}{2^{3m+2}}=\frac{1}{2^{3m+2}}\text{ なので}
\begin{aligned}
S_{3M}
&=\frac{\sqrt3}{2}\displaystyle \sum_{m=0}^{M-1}\frac{1}{2^{3m+2}}
=\frac{\sqrt3}{2}\cdot\frac{1}{4}\displaystyle \sum_{m=0}^{M-1}\left(\frac{1}{8}\right)^m
\end{aligned}
\text{等比数列の和より}
\begin{aligned}
S_{3M}&=\frac{\sqrt3}{8}\cdot\frac{1-(\frac18)^M}{1-\frac18}\\[5pt]
&=\frac{\sqrt3}{8}\cdot\frac{1-(\frac18)^M}{\frac78}\\[5pt]
&=\frac{\sqrt3}{7}\left(1-\left(\frac18\right)^M\right)
\end{aligned}
\text{したがって } \displaystyle \lim_{M\to\infty}S_{3M}=\frac{\sqrt3}{7}
\textcolor{green}{次に } \textcolor{green}{N=3M+1} \textcolor{green}{ のとき}
\begin{aligned}
S_{3M+1}
&=S_{3M}+\frac{1}{2^{3M+1}}\sin\!\left(\frac{2(3M+1)\pi}{3}\right)\\[5pt]
&=S_{3M}+\frac{1}{2^{3M+1}}\cdot\frac{\sqrt3}{2}\\[5pt]
&= S_{3M}+\frac{\sqrt3}{2^{3M+2}}
\end{aligned}
\text{よって }
\begin{aligned}
\displaystyle \lim_{M\to\infty}S_{3M+1}
&=\lim_{M\to\infty}\left(S_{3M}+\frac{\sqrt3}{2^{3M+2}}\right)\\[5pt]
&=\displaystyle \frac{\sqrt3}{7}
\end{aligned}
\textcolor{green}{同様に } \textcolor{green}{N=3M+2} \textcolor{green}{ のとき}
\begin{aligned}
S_{3M+2}
&=S_{3M+1}+\frac{1}{2^{3M+2}}\sin\!\left(\frac{2(3M+2)\pi}{3}\right)\\
&=S_{3M+1}+\frac{1}{2^{3M+2}}\cdot\left(-\frac{\sqrt3}{2}\right)\\
&=S_{3M+1}-\frac{\sqrt3}{2^{3M+3}}
\end{aligned}
\text{したがって } 
\begin{aligned}
\displaystyle \lim_{M\to\infty}S_{3M+2}&=\lim_{M\to\infty}\left(S_{3M+1}-\frac{\sqrt3}{2^{3M+3}}
\right)\\[5pt]
&=\displaystyle \frac{\sqrt3}{7}
\end{aligned}
\text{以上より }S_{3M},S_{3M+1},S_{3M+2}\text{ はいずれも }\displaystyle \frac{\sqrt3}{7}\text{ に収束する。}
\boxed{\displaystyle \sum_{k=1}^{\infty}\frac{1}{2^{k}}\sin\!\left(\frac{2k\pi}{3}\right)=\frac{\sqrt3}{7}}

\textcolor{brown}{\large{【力学】}}
\text{• 一定加速度運動の速度変化についての微分方程式。}
\text{• 力学においては、} v^{\prime}(t) = a \text{の形でよく登場する。これは一定の力を受ける質点の速度変化を表す。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{一定加速度運動の速度変化}
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } 1 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t) = 2
\text{両辺を }0\text{ から }t\text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime}(s)\,ds = \int_0^t 2\,ds\\[5pt]
&\Leftrightarrow [f(s)]_{0}^{t} = [2s]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f(t) - f(0) = 2 t - 0\\[5pt]
&\Leftrightarrow \ f(t) = 2 t + f(0)
\end{aligned}
\text{初期条件より} f(0) = 1 \text{なので、}
\Leftrightarrow \ f(t) = 2 t + 1

\textbf{【方針】}
\text{半角公式を用いて }\sqrt{1+\sin x}\text{ を }\cos\text{ の形に変形し，} \text{絶対値の符号で区間分割して原始関数で評価する。}
\begin{aligned}
1+\sin x &= 1 + \cos\left(\displaystyle\frac{\pi}{2} - x\right)\\[5pt]
&= 2\cos^2\displaystyle\frac{\frac{\pi}{2} - x}{2}\\[5pt]
&= 2\cos^2\left(\displaystyle\frac{\pi}{4} - \displaystyle\frac{x}{2}\right)\\[5pt]
&= 2\cos^2\left(\displaystyle\frac{x}{2} - \displaystyle\frac{\pi}{4}\right)
\end{aligned}
\text{したがって、}
\begin{aligned}
\sqrt{1+\sin x} &= \sqrt{2\cos^2\left(\displaystyle\frac{x}{2}-\displaystyle\frac{\pi}{4}\right)}\\[5pt]
&= \sqrt{2}\left|\cos\left(\displaystyle\frac{x}{2}-\displaystyle\frac{\pi}{4}\right)\right|
\end{aligned}
\text{次に、絶対値での折り返し区間を求める。}
\begin{aligned}
&\cos\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right)=0
\iff x=\displaystyle \frac{3\pi}{2}+2k\pi
\end{aligned}
\text{積分区間 } \left[\displaystyle \frac{\pi}{2},\displaystyle \frac{5}{2}\pi\right] \text{ 内には零点 } x=\displaystyle \frac{3\pi}{2} \text{ が一つある。前後の関数の正負を考えると、}
\begin{aligned}
      \begin{cases}
      \left[\displaystyle \frac{\pi}{2},\displaystyle \frac{3\pi}{2}\right]\text{ では } \cos\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right) > 0\\
      \left[\displaystyle \frac{3\pi}{2},\displaystyle \frac{5}{2}\pi\right]\text{ では } \cos\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right) < 0
      \end{cases}
      \end{aligned}
\text{したがって、}
\begin{aligned}
      \displaystyle  
      &\ \ \ \int_{ \frac{\pi}{2}}^{ \frac{5}{2}\pi}\sqrt{1+\sin x}\,dx\\[5pt]
      &= \sqrt2\displaystyle \int_{ \frac{\pi}{2}}^{ \frac{3\pi}{2}}\cos\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right)\,dx 
-\sqrt2\displaystyle \int_{ \frac{3\pi}{2}}^{ \frac{5}{2}\pi}\cos\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right)\,dx\\[5pt]
      &= \sqrt2 \cdot 2\left[\sin\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right)\right]_{ \frac{\pi}{2}}^{ \frac{3\pi}{2}} 
-\sqrt2 \cdot 2\left[\sin\!\left(\displaystyle \frac{x}{2}-\displaystyle \frac{\pi}{4}\right)\right]_{ \frac{3\pi}{2}}^{ \frac{5}{2}\pi}\\[5pt]
      &=2\sqrt2\left(\textcolor{red}{\sin\!\left(\displaystyle \frac{3\pi}{2}\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)} - \textcolor{green}{\sin\!\left(\displaystyle \frac{\pi}{2}\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)}\right.\\[5pt]
      &\quad \left.-\textcolor{blue}{\sin\!\left(\displaystyle \frac{5}{2}\pi\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)} + \textcolor{orange}{\sin\!\left(\displaystyle \frac{3\pi}{2}\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)}\right) \cdots (\star)
\end{aligned}
\text{ここで、各項の値を計算すると、}
\begin{aligned}
\textcolor{red}{\sin\!\left(\displaystyle \frac{3\pi}{2}\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)} &= \sin\!\left(\displaystyle \frac{3\pi}{4}-\displaystyle \frac{\pi}{4}\right) = \sin\displaystyle \frac{\pi}{2} = \textcolor{red}{1}\\[4pt]
\textcolor{green}{\sin\!\left(\displaystyle \frac{\pi}{2}\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)} &= \sin\!\left(\displaystyle \frac{\pi}{4}-\displaystyle \frac{\pi}{4}\right) = \sin 0 = \textcolor{green}{0}\\[4pt]
\textcolor{blue}{\sin\!\left(\displaystyle \frac{5}{2}\pi\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)} &= \sin\!\left(\displaystyle \frac{5\pi}{4}-\displaystyle \frac{\pi}{4}\right) = \sin\pi = \textcolor{blue}{0}\\[4pt]
\textcolor{orange}{\sin\!\left(\displaystyle \frac{3\pi}{2}\cdot\displaystyle \frac{1}{2}-\displaystyle \frac{\pi}{4}\right)} &= \sin\!\left(\displaystyle \frac{3\pi}{4}-\displaystyle \frac{\pi}{4}\right) = \sin\displaystyle \frac{\pi}{2} = \textcolor{orange}{1}
\end{aligned}
\text{したがって、}(\star) \text{式より}
\begin{aligned}
&=2\sqrt2\left(\textcolor{red}{1} - \textcolor{green}{0} - \textcolor{blue}{0} + \textcolor{orange}{1}\right)\\
&=4\sqrt2
\end{aligned}
\textbf{【補足】}
\text{テクニカルだが}
\begin{aligned}
1+\sin x
=&\sin^2\displaystyle \frac{x}{2}+\cos^2\displaystyle \frac{x}{2}+2\sin\displaystyle \frac{x}{2}\cos\displaystyle \frac{x}{2}\\
=&\left(\sin\displaystyle \frac{x}{2}+\cos\displaystyle \frac{x}{2}\right)^2
\end{aligned}
\text{なので、下記のように根号を外してもOK}
\begin{aligned}
\sqrt{1+\sin x}=&\left|\sin\displaystyle \frac{x}{2}+\cos\displaystyle \frac{x}{2}\right|
=&\sqrt2\left|\sin\!\left(\displaystyle \frac{x}{2}+\displaystyle \frac{\pi}{4}\right)\right|
\end{aligned}

\color{black}\textbf{【方針】}
\color{black}\cos\text{ に平均値の定理を使う。}
\color{black}\textbf{【平均値の定理】}
\color{black}\text{関数 }f\text{ が区間 }[a,b]\text{ で連続、}a\text{ と }b\text{ の間で微分可能なら、}
\color{black}f(b)-f(a)=f^{\prime}(c)(b-a)\text{ となる実数 }c\text{ が }a\text{ と }b\text{ の間に存在する。}
\color{black}\textbf{【適用】}
\color{black}f(t)=\cos t\text{ とおくと }f^{\prime}(t)=-\sin t\text{。}
\color{black}\text{ }a=x^2,\ b=x\text{ として平均値の定理を用いる。}
\color{black}\text{すると }
\color{black}\cos x-\cos x^2 = (-\sin c)(x-x^2)\text{ となる実数 }c\text{ が }x\text{ と }x^2\text{ の間に存在する。}
\color{black}\textbf{【よって】}
\color{black}\frac{\cos x-\cos x^2}{x-x^2}=-\sin c
\color{black}\textbf{【左右からの確認】}
\color{black}\text{(1) }x>0\text{ のとき }x^2\text{ は }x\text{ より小さいので、}c\text{ は }x^2\text{ と }x\text{ の間にある。}
\color{black}\text{(2) }x<0\text{ のとき }x\text{ は }x^2\text{ より小さいので、}c\text{ は }x\text{ と }x^2\text{ の間にある。}
\color{black}\text{どちらの場合も }x\to0\text{ なら }x^2\to0\text{ なので、}c\text{ も }0\text{ に近づく。}
\color{black}\sin\text{ は連続だから }-\sin c\to-\sin0=0
\color{black}\boxed{\displaystyle \lim_{x\to0}\frac{\cos x-\cos x^2}{x-x^2}=0}

\textbf{【背景】}
\text{この積分は、サイクロイドの弧長を求める過程で現れる。}
\text{サイクロイド } x = t - \sin t, \; y = 1 - \cos t \text{ の弧長は、}
\begin{aligned}
x^{\prime}(t) &= 1 - \cos t\\
y^{\prime}(t) &= \sin t
\end{aligned}
\begin{aligned}
L &= \displaystyle \int_0^{2\pi} \sqrt{(x^{\prime}(t))^2 + (y^{\prime}(t))^2} \, dt\\
&= \displaystyle \int_0^{2\pi} \sqrt{(1-\cos t)^2 + (\sin t)^2} \, dt\\
&= \displaystyle \int_0^{2\pi} \sqrt{1 - 2\cos t + \cos^2 t + \sin^2 t} \, dt\\
&= \textcolor{red}{\displaystyle \int_0^{2\pi} \sqrt{2 - 2\cos t} \, dt}
\end{aligned}
\textbf{【計算】}
\text{半角の公式 } \sin^2 \dfrac{x}{2} = \dfrac{1 - \cos x}{2} \text{ より、} 1 - \cos x = 2\sin^2 \dfrac{x}{2} \text{ であるから、}
\begin{aligned}
\displaystyle \int_0^{2\pi} \sqrt{2 - 2\cos x} \, dx &= \displaystyle \int_0^{2\pi} \sqrt{2 \cdot 2\sin^2 \dfrac{x}{2}} \, dx\\
&= \displaystyle \int_0^{2\pi} \sqrt{4\sin^2 \dfrac{x}{2}} \, dx\\
&= \displaystyle \int_0^{2\pi} 2\left|\sin \dfrac{x}{2}\right| \, dx
\end{aligned}
\text{ここで、} 0 \le x \le 2\pi \text{ のとき } 0 \le \dfrac{x}{2} \le \pi \text{ であるから、} \sin \dfrac{x}{2} \ge 0 \text{ である。}
\begin{aligned}
\displaystyle \int_0^{2\pi} 2\left|\sin \dfrac{x}{2}\right| \, dx &= 2 \displaystyle \int_0^{2\pi} \sin \dfrac{x}{2} \, dx\\
&= 2 \cdot \left[-2\cos \dfrac{x}{2}\right]_0^{2\pi}\\
&= -4(\cos \pi - \cos 0)\\
&= -4(-1 - 1)\\
&= 8
\end{aligned}

\textbf{【方針】}
\text{右辺が指数関数なので解の一つを指数関数} A \cdot 3^{n} \text{ の形で求め、これを使ってただの等比数列の式に帰着させる。}
\textbf{【解法】}
\text{解の形を}A \cdot 3^n \text{と仮定して、元の漸化式に代入すると、} A \cdot 3^n = 2 \cdot A \cdot 3^{n-1} + 3^n \text{ である。}
\begin{aligned}
    &\ \ \ \ \ A \cdot 3^n = 2 \cdot A \cdot 3^{n-1} + 3^n \\
    &\Leftrightarrow A \cdot 3^n = \displaystyle \frac{2A}{3} \cdot 3^n + 3^n \\
    &\Leftrightarrow A = \displaystyle \frac{2A}{3} + 1 \\
    &\Leftrightarrow 3A = 2A + 3 \\
    &\Leftrightarrow A = 3
    \end{aligned}
\text{よって、一つの解は }  3 \cdot 3^{n-1} = 3^n \text{ である。}
\text{求まった解を元の漸化式に代入すると、} 3^{n+1} = 2 \cdot 3^n + 3^n \cdots (1) \text{ である。}
\text{ここで、元の漸化式から(1)を引いて、新たな数列}b_n = a_n - 3^n\text{ を定義すると、等比数列の形に帰着させることができる。実際、}
\begin{aligned}
      a_{n+1} &= 2a_n + 3^n \\
      3^{n+1} &= 2 \cdot 3^n + 3^n \\
      \hline
      \ \ \ \ \ a_{n+1} - 3^{n+1} &= 2a_n + 3^n - (2 \cdot 3^n + 3^n) \\
      \Leftrightarrow a_{n+1} - 3^{n+1} &= 2a_n + 3^n - 2 \cdot 3^n - 3^n \\
      \Leftrightarrow a_{n+1} - 3^{n+1} &= 2(a_n - 3^n)
      \end{aligned}
\text{ } b_n = a_n - 3^n \text{ とおくと、} b_{n+1} = 2b_n, \ b_1 = a_1 - 3^1 = 1 - 3 = -2 \text{ だから、}
\begin{aligned}
        \begin{cases}
         b_{n+1} = 2b_n \\
          b_1 = = -2 
          \end{cases}
          \end{aligned}
\text{上の漸化式は等比数列の形で、} b_n = -2 \cdot 2^{n-1} = -2^n \text{ なので、}
\begin{aligned}
    &\ \ \ \ \ a_n = b_n + 3^n \\
    &\Leftrightarrow a_n = -2^n + 3^n \\
    &\Leftrightarrow a_n = 3^n - 2^n
    \end{aligned}

\textbf{【方針】}
\text{すべての項を } 3^x \text{ で表し、} 3^x = t \text{ とおいて2次方程式に帰着させる。}
\textbf{【ポイント】}
\begin{aligned}
3^{x+1} &= 3 \cdot 3^x \\
9^x &= (3^2)^x = 3^{2x} = (3^x)^2
\end{aligned}
\textbf{【解説】}
\text{まず、各項を } 3^x \text{ で表すと、}
\begin{aligned}
3^x + 3^{x+1} &= 3^x + 3 \cdot 3^x \\
&= 3^x(1 + 3) \\
&= 4 \cdot 3^x
\end{aligned}
\text{また、}
\begin{aligned}
9^x = (3^2)^x = 3^{2x} = (3^x)^2
\end{aligned}
\text{したがって、元の方程式は、} 3^x = t\text{とおくと、}
\begin{aligned}
&\ \ \ \ \ 3^x + 3^{x+1} = 9^x\\
&\Leftrightarrow 4 \cdot 3^x = (3^x)^2 \\
&\Leftrightarrow 4t = t^2 \quad\\
&\Leftrightarrow t^2 - 4t = 0 \\
&\Leftrightarrow t(t - 4) = 0 \\
&\Leftrightarrow t = 0 \text{ または } t = 4
\end{aligned}
\text{ここで、} t = 3^x > 0 \text{ なので、} t = 4 \text{ である。}
\text{したがって、}
\begin{aligned}
&\ \ \ \ \ t = 4 \\
&\Leftrightarrow 3^x = 4 \\
&\Leftrightarrow x = \log_3 4
\end{aligned}
\text{さらに変形すると、}
\begin{aligned}
x &= \log_3 4 \\
&= \log_3 2^2 \\
&= 2\log_3 2
\end{aligned}

\textbf{【方針】}
\text{「 } \displaystyle \frac 1 {6} \text{ 公式」} \displaystyle \int_{\alpha}^{\beta}(x-\alpha)(\beta-x)\,dx  = \displaystyle \frac{(\beta-\alpha)^3}{6} \text{を使う。}
\textbf{【公式による計算】}
\begin{aligned}
      &\displaystyle \int_{2}^{5}(x-2)(5-x)\,dx\\
      =&(5-2)^3\cdot\displaystyle \frac{1}{6}\\
      =&3^3\cdot\displaystyle \frac{1}{6}\\
      =&\displaystyle \frac{27}{6}=\displaystyle \frac{9}{2}
\end{aligned}
\textbf{【命題】}
\displaystyle \int_{\alpha}^{\beta}(x-\alpha)(\beta-x)\,dx = \displaystyle \frac{(\beta-\alpha)^3}{6}
\textbf{【証明1：部分積分による証明】}
\begin{aligned}
&\displaystyle \int_{\alpha}^{\beta}(x-\alpha)(\beta-x)\,dx\\
=&\displaystyle \int_{\alpha}^{\beta}\left(\displaystyle \frac{(x-\alpha)^2}{2}\right)'(\beta-x)\,dx\\
=& \left[\displaystyle \frac{(x-\alpha)^2}{2}(\beta-x)\right]_{\alpha}^{\beta}
-\displaystyle \int_{\alpha}^{\beta}\displaystyle \frac{(x-\alpha)^2}{2}\,(-1)\,dx\\
=& \displaystyle \frac{1}{2}\displaystyle \int_{\alpha}^{\beta}(x-\alpha)^2\,dx\\
=& \displaystyle \frac{1}{2}\left[\displaystyle \frac{(x-\alpha)^3}{3}\right]_{\alpha}^{\beta}\\
=& \displaystyle \frac{(\beta-\alpha)^3}{6}
\end{aligned}
\textbf{【証明2：普通に展開して計算する証明】}
\begin{aligned}
&\displaystyle \int_{\alpha}^{\beta}(x-\alpha)(\beta-x)\,dx\\
=&\displaystyle \int_{\alpha}^{\beta}\left((x-\alpha)\beta-(x-\alpha)x\right)\,dx\\
=&\displaystyle \int_{\alpha}^{\beta}\left(\beta(x-\alpha)-x(x-\alpha)\right)\,dx\\
=&\displaystyle \int_{\alpha}^{\beta}\left(\beta(x-\alpha)-x^2+\alpha x\right)\,dx\\
=&\displaystyle \int_{\alpha}^{\beta}\left(\beta x-\alpha\beta-x^2+\alpha x\right)\,dx\\
=&\displaystyle \int_{\alpha}^{\beta}\left((\beta+\alpha)x-\alpha\beta-x^2\right)\,dx\\
=&\left[\displaystyle \frac{(\beta+\alpha)x^2}{2}-\alpha\beta x-\displaystyle \frac{x^3}{3}\right]_{\alpha}^{\beta}\\
=&\displaystyle \frac{(\beta+\alpha)\beta^2}{2}-\alpha\beta^2-\displaystyle \frac{\beta^3}{3}-\displaystyle \frac{(\beta+\alpha)\alpha^2}{2}+\alpha^2\beta+\displaystyle \frac{\alpha^3}{3}\\
=&\displaystyle \frac{(\beta+\alpha)(\beta^2-\alpha^2)}{2}-\alpha\beta(\beta-\alpha)-\displaystyle \frac{\beta^3-\alpha^3}{3}\\
=&\displaystyle \frac{(\beta+\alpha)(\beta-\alpha)(\beta+\alpha)}{2}-\alpha\beta(\beta-\alpha)-\displaystyle \frac{(\beta-\alpha)(\beta^2+\alpha\beta+\alpha^2)}{3}\\
=&(\beta-\alpha)\left[\displaystyle \frac{(\beta+\alpha)^2}{2}-\alpha\beta-\displaystyle \frac{\beta^2+\alpha\beta+\alpha^2}{3}\right]\\
=&(\beta-\alpha)\left[\displaystyle \frac{3(\beta+\alpha)^2-6\alpha\beta-2(\beta^2+\alpha\beta+\alpha^2)}{6}\right]\\
=&(\beta-\alpha)\left[\displaystyle \frac{3\beta^2+6\alpha\beta+3\alpha^2-6\alpha\beta-2\beta^2-2\alpha\beta-2\alpha^2}{6}\right]\\
=&(\beta-\alpha)\left[\displaystyle \frac{\beta^2-2\alpha\beta+\alpha^2}{6}\right]\\
=&(\beta-\alpha)\left[\displaystyle \frac{(\beta-\alpha)^2}{6}\right]\\
=&\displaystyle \frac{(\beta-\alpha)^3}{6}
\end{aligned}

\textbf{【方針】}
\; u=\tan x \,\textbf{と置換する。}
\textbf{【解説】}
du = \displaystyle \frac{d u}{dx} dx = \frac{dx}{\cos^2 x} = (1+\tan^2 x) dx \text{なので、}
\begin{aligned}
  &\displaystyle \int_{ \frac{\pi}{4}}^{\frac{\pi}{3}}\tan^{2}x\left(1 + \tan^{2}x\right)\,dx\\
  =&\displaystyle \int_{\tan\left(\frac{\pi}{4}\right)}^{\tan\left(\frac{\pi}{3}\right)} u^{2} \,du\\
  =&\displaystyle \int_{1}^{\sqrt{3}} u^{2} \,du\\
  =&\left[ \displaystyle \frac{u^{3}}{3}\right]_{1}^{\sqrt{3}}\\
  =&\displaystyle \frac{\sqrt{3}^3-1^3}{3}\\
  =&\displaystyle \sqrt{3}- \displaystyle \frac{1}{3}
  \end{aligned}

\textbf{【背景】}
\text{この積分は、放物線の弧長を求める過程で現れる。}
\text{放物線 } y = 1 + x^2 \text{ の弧長は、}
\begin{aligned}
L &= \displaystyle \int_0^1 \sqrt{1 + (y')^2} \, dx\\
&= \displaystyle \int_0^1 \sqrt{1 + (2x)^2} \, dx\\
&= \textcolor{red}{\displaystyle \int_0^1 \sqrt{1 + 4x^2} \, dx}
\end{aligned}
\textbf{【計算】}
\text{双曲線関数 } \sinh t = \dfrac{e^t - e^{-t}}{2}, \; \cosh t = \dfrac{e^t + e^{-t}}{2} \text{ を用いて置換する。}
\text{ここで、} 2x = \sinh t \text{ と双曲線関数で置換すると、} x =\displaystyle  \frac{\sinh t}{2}, \; dx = \displaystyle \frac{\cosh t}{2} \, dt \text{ であり、} x = 0 \rightarrow t = 0, \; x = 1 \rightarrow t = t_0 \text{ である。（ただし、} t_0 \text{ は } \sinh t_0 = 2 \text{ を満たす数とする。）}
\textcolor{blue}{双曲線関数の恒等式 } \textcolor{blue}{\cosh^2 t - \sinh^2 t = 1} \text{ より、} \sqrt{1 + \sinh^2 t} = \cosh t \text{ であるから、}
\begin{aligned}
L &= \displaystyle \int_0^{t_0} \sqrt{1 + \sinh^2 t} \cdot \frac{\cosh t}{2} \, dt \\
&= \displaystyle \int_0^{t_0} \cosh t \cdot \frac{\cosh t}{2} \, dt \\
&= \frac{1}{2} \displaystyle \int_0^{t_0} \cosh^2 t \, dt
\end{aligned}
\textcolor{blue}{倍角の公式 } \textcolor{blue}{\cosh 2t = 2\cosh^2 t - 1} \text{ より、} \cosh^2 t = \frac{1 + \cosh 2t}{2} \text{ であるから、}
\begin{aligned}
L &= \frac{1}{2} \displaystyle \int_0^{t_0} \frac{1 + \cosh 2t}{2} \, dt \\
&= \frac{1}{4} \displaystyle \int_0^{t_0} (1 + \cosh 2t) \, dt \\
&= \frac{1}{4} \left[t + \frac{\sinh 2t}{2}\right]_0^{t_0}
\end{aligned}
\text{ここで、} t = t_0 \text{ のとき、} \sinh t_0 = 2 \text{ より } \cosh t_0 = \sqrt{1 + \sinh^2 t_0} = \sqrt{1 + 4} = \sqrt{5} \text{ である。}
\text{また、} \textcolor{blue}{倍角の公式を用いて、}
\textcolor{blue}{\sinh 2t_0 = 2\sinh t_0 \cosh t_0} = 2 \cdot 2 \cdot \sqrt{5} = 4\sqrt{5} \text{ であるから、}
\begin{aligned}
L &= \frac{1}{4} \left[t_0 + \frac{4\sqrt{5}}{2} - \left(0 + \frac{0}{2}\right)\right] \\
&= \frac{1}{4} \left[t_0 + 2\sqrt{5}\right] \\
&= \frac{\sqrt{5}}{2} + \frac{t_0}{4}
\end{aligned}
\text{ここで、} t_0 \text{を具体的に求めると、} t_0 \text{は、} \sinh t_0 = 2 \text{ を満たす数であるから、} \frac {e^{t_0}-e^{-t_0}}{2}=2 \text{ を解く。}
\begin{aligned}
      \frac {e^{t_0}-e^{-t_0}}{2}=2 \\
      e^{t_0}-e^{-t_0}=4 \\
      e^{2t_0}-1=4e^{t_0} \\
      e^{2t_0}-4e^{t_0}-1=0 \\
      e^{t_0}=2+\sqrt{5} \\
      t_0=\log(2+\sqrt{5})
      \end{aligned}
\text{したがって、}
\begin{aligned}
L &= \frac{\sqrt{5}}{2} + \frac{1}{4} \log(2+\sqrt{5}) = 1.4789\cdots > \sqrt 2 = 1.4142\cdots
\end{aligned}
\textcolor{blue}{【補足：双曲線関数の公式の証明】}
\text{【1】} \cosh^2 t - \sinh^2 t = 1 \text{ の証明：}
\begin{aligned}
\cosh^2 t - \sinh^2 t &= \left(\frac{e^t + e^{-t}}{2}\right)^2 - \left(\frac{e^t - e^{-t}}{2}\right)^2 \\
&= \frac{e^{2t} + 2 + e^{-2t}}{4} - \frac{e^{2t} - 2 + e^{-2t}}{4} \\
&= \frac{4}{4} = 1
\end{aligned}
\text{【2】} \cosh 2t = 2\cosh^2 t - 1 \text{ の証明：}
\begin{aligned}
\cosh 2t &= \frac{e^{2t} + e^{-2t}}{2} = \frac{(e^t)^2 + (e^{-t})^2}{2} \\
&= \frac{(e^t + e^{-t})^2 - 2}{2} = \frac{(e^t + e^{-t})^2}{2} - 1 \\
&= 2\left(\frac{e^t + e^{-t}}{2}\right)^2 - 1 = 2\cosh^2 t - 1
\end{aligned}
\text{【3】} \sinh 2t = 2\sinh t \cosh t \text{ の証明：}
\begin{aligned}
\sinh 2t &= \frac{e^{2t} - e^{-2t}}{2} = \frac{(e^t)^2 - (e^{-t})^2}{2} \\
&= \frac{(e^t - e^{-t})(e^t + e^{-t})}{2} \\
&= 2 \cdot \frac{e^t - e^{-t}}{2} \cdot \frac{e^t + e^{-t}}{2} = 2\sinh t \cosh t
\end{aligned}

\textbf{【方針】}
3^x + 3^{-x} = t \text{ とおいて、} 9^x + 9^{-x} \text{ を } t \text{ で表し、2次方程式に帰着させる。}
\textbf{【ポイント】}
\begin{aligned}
(3^x + 3^{-x})^2 &= 9^x + 2 \cdot 3^x \cdot 3^{-x} + 9^{-x} \\
&= 9^x + 2 + 9^{-x}
\end{aligned}
\text{よって、} 9^x + 9^{-x} = (3^x + 3^{-x})^2 - 2 = t^2 - 2 \text{ である。}
\textbf{【解説】}
3^x + 3^{-x} = t \text{ とおくと、} t > 0 \text{ であり、}
\begin{aligned}
9^x + 9^{-x} &= (3^x)^2 + (3^{-x})^2 \\
&= (3^x + 3^{-x})^2 - 2 \cdot 3^x \cdot 3^{-x} \\
&= t^2 - 2
\end{aligned}
\text{元の方程式は、}
\begin{aligned}
&\ \ \ \ \ 3^x + 3^{-x} + 9^x + 9^{-x} = 4 \\
&\Leftrightarrow t + (t^2 - 2) = 4 \\
&\Leftrightarrow t^2 + t - 6 = 0 \\
&\Leftrightarrow (t + 3)(t - 2) = 0 \\
&\Leftrightarrow t = -3 \text{ または } t = 2
\end{aligned}
\text{ここで、} t = 3^x + 3^{-x} > 0 \text{ なので、} t = 2 \text{ である。}
\text{したがって、}
\begin{aligned}
&\ \ \ \ \ 3^x + 3^{-x} = 2 \\
&\Leftrightarrow 3^x + \displaystyle\frac{1}{3^x} = 2 \\
&\Leftrightarrow (3^x)^2 + 1 = 2 \cdot 3^x \\
&\Leftrightarrow (3^x)^2 - 2 \cdot 3^x + 1 = 0 \\
&\Leftrightarrow (3^x - 1)^2 = 0 \\
&\Leftrightarrow 3^x = 1 \\
&\Leftrightarrow x = 0
\end{aligned}

\textbf{【方針】}
\text{分母分子に } \sin x \text{ をかけて、} u = \cos x \text{ と置換する。}
\textbf{【解説】}
\text{分母分子に } \sin x \text{ をかけると、}
\begin{aligned}
\int_{\frac{\pi}{6}}^{\frac{\pi}{2}} \frac{dx}{\sin x}
&= \int_{\frac{\pi}{6}}^{\frac{\pi}{2}} \frac{\sin x}{\sin^2 x} \, dx\\[5pt]
&= \textcolor{blue}{\int_{\frac{\pi}{6}}^{\frac{\pi}{2}} \frac{\sin x}{1-\cos^2 x} \, dx}
\end{aligned}
\text{ } u = \cos x \text{ とおくと、} du = -\sin x \, dx \text{ であり、}
\begin{aligned}
x = \frac{\pi}{6} &\Rightarrow u = \cos\frac{\pi}{6} = \frac{\sqrt{3}}{2}\\[5pt]
x = \frac{\pi}{2} &\Rightarrow u = \cos\frac{\pi}{2} = 0
\end{aligned}
\begin{aligned}
&\ \ \ \ \ \textcolor{blue}{\int_{\frac{\pi}{6}}^{\frac{\pi}{2}} \frac{\sin x}{1-\cos^2 x} \, dx}\\[5pt]
&= \int_{u=\frac{\sqrt{3}}{2}}^{u=0} \frac{-du}{1-u^2}\\[5pt]
&= \int_{0}^{\frac{\sqrt{3}}{2}} \frac{du}{1-u^2}\\[5pt]
&= \int_{0}^{\frac{\sqrt{3}}{2}} \frac{1}{2}\left(\frac{1}{1-u} + \frac{1}{1+u}\right) du\\[5pt]
&= \frac{1}{2}\left[-\log|1-u| + \log|1+u|\right]_{0}^{\frac{\sqrt{3}}{2}}\\[5pt]
&= \frac{1}{2}\log\left|\frac{1+u}{1-u}\right|_{0}^{\frac{\sqrt{3}}{2}}\\[5pt]
&= \frac{1}{2}\log\left(\frac{1+\frac{\sqrt{3}}{2}}{1-\frac{\sqrt{3}}{2}}\right)\\[5pt]
&= \frac{1}{2}\log\left({\frac{2+\sqrt{3}}{2-\sqrt{3}}}\right)\\[5pt]
&= \frac{1}{2}\log\left(\frac{2+\sqrt{3}}{2-\sqrt{3}} \cdot \frac{2+\sqrt{3}}{2+\sqrt{3}}\right)\\[5pt]
&= \frac{1}{2}\log\left(\frac{(2+\sqrt{3})^2}{(2-\sqrt{3})(2+\sqrt{3})}\right)\\[5pt]
&= \frac{1}{2}\log\left(\frac{(2+\sqrt{3})^2}{4-3}\right)\\[5pt]
&= \frac{1}{2}\log\left((2+\sqrt{3})^2\right)\\[5pt]
&= \log(2+\sqrt{3})
\end{aligned}

\textbf{【方針】}
1+x^3=(1+x)(1-x+x^2) \text{ に因数分解して部分分数分解を行い，原始関数を求めてから定積分を評価する。}
\textbf{【部分分数分解】}
\text{分母を因数分解すると、} 1+x^3=(1+x)(1-x+x^2) \text{ である。}
\text{部分分数分解の形を設定する：}
\displaystyle \frac{1}{1+x^3}=\displaystyle \frac{A}{1+x}+\displaystyle \frac{Bx+C}{1-x+x^2}
\text{両辺に } (1+x)(1-x+x^2) \text{ を掛けると、}
1=A(1-x+x^2)+(Bx+C)(1+x)
\text{右辺を展開すると、}
\begin{aligned}
1&=A(1-x+x^2)+(Bx+C)(1+x)\\
&=A-Ax+Ax^2+Bx+Bx^2+C+Cx\\
&=(A+C)+(-A+B+C)x+(A+B)x^2
\end{aligned}
\text{係数比較により、}
\begin{cases}
A+C=1\\
-A+B+C=0\\
A+B=0
\end{cases}
\text{これを解くと、} A=\displaystyle \frac{1}{3}, B=-\displaystyle \frac{1}{3}, C=\displaystyle \frac{2}{3}
\text{したがって、}
\displaystyle \frac{1}{1+x^3}=\displaystyle \frac{1}{3}\cdot\displaystyle \frac{1}{1+x}+\displaystyle \frac{-x+2}{3(1-x+x^2)}
\textbf{【第2項の変形】}
\text{第2項の分子を分母の導関数の形に分解し、積分したら}\log \text{の形になるようにすることを考える。分母 } 1-x+x^2 \text{ の導関数は } 2x-1 \text{ である。}
\text{そこで、} -x+2=\alpha(2x-1)+\beta \text{ とおく。}
\text{右辺を展開すると、}
\begin{aligned}
-x+2&=2\alpha x-\alpha+\beta\\
&=(2\alpha)x+(-\alpha+\beta)
\end{aligned}
\text{係数比較により、}
\begin{cases}
2\alpha=-1\\
-\alpha+\beta=2
\end{cases}
\text{これを解くと、} \alpha=-\displaystyle \frac{1}{2}, \beta=\displaystyle \frac{3}{2}
\text{したがって、}
\begin{aligned}
\displaystyle \frac{-x+2}{3(1-x+x^2)}
&=\displaystyle \frac{-\displaystyle \frac{1}{2}(2x-1)+\displaystyle \frac{3}{2}}{3(1-x+x^2)}\\[6pt]
&=-\displaystyle \frac{1}{6}\cdot\displaystyle \frac{2x-1}{1-x+x^2}+\displaystyle \frac{1}{2}\cdot\displaystyle \frac{1}{1-x+x^2}
\end{aligned}
\textbf{【定積分の評価】}
\text{部分分数分解の結果より、定積分は次の3つの積分の和として表される：}
\begin{aligned}
\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1+x^{3}}
&=\displaystyle \frac{1}{3}\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1+x}-\displaystyle \frac{1}{6}\displaystyle \int_{0}^{1}\displaystyle \frac{2x-1}{1-x+x^2}dx+\displaystyle \frac{1}{2}\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1-x+x^2}
\end{aligned}
\textcolor{blue}{\textbf{【第1項の計算】}}
\begin{aligned}
\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1+x}
&=\left[\log(1+x)\right]_{0}^{1}\\[6pt]
&=\log 2-\log 1\\[6pt]
&=\log 2
\end{aligned}
\textcolor{blue}{\textbf{【第2項の計算】}}
\text{分母 } 1-x+x^2 \text{ の導関数は } 2x-1 \text{ である。したがって、}
\begin{aligned}
\displaystyle \int_{0}^{1}\displaystyle \frac{2x-1}{1-x+x^2}dx
&=\left[\log(1-x+x^2)\right]_{0}^{1}\\[6pt]
&=\log(1-1+1)-\log(1-0+0)\\[6pt]
&=\log 1-\log 1\\[6pt]
&=0
\end{aligned}
\textcolor{blue}{\textbf{【第3項の計算】}}
\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1-x+x^2} =\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{\left(x-\displaystyle \frac{1}{2}\right)^2+\left(\displaystyle \frac{\sqrt{3}}{2}\right)^2}
\text{ここで変数変換 } x=\displaystyle \frac{1}{2}+\displaystyle \frac{\sqrt{3}}{2}u \text{ を行う。このとき、} dx=\displaystyle \frac{\sqrt{3}}{2}du \text{ である。}
\text{積分範囲の変換：}
    \begin{aligned}
    \begin{cases}
    x=0 \Leftrightarrow 0=\displaystyle \frac{1}{2}+\displaystyle \frac{\sqrt{3}}{2}u \Leftrightarrow \displaystyle \frac{\sqrt{3}}{2}u=-\displaystyle \frac{1}{2} \Leftrightarrow u=-\displaystyle \frac{1}{\sqrt{3}},\\[5pt]
    x=1 \Leftrightarrow 1=\displaystyle \frac{1}{2}+\displaystyle \frac{\sqrt{3}}{2}u \Leftrightarrow \displaystyle \frac{\sqrt{3}}{2}u=\displaystyle \frac{1}{2} \Leftrightarrow u=\displaystyle \frac{1}{\sqrt{3}}
    \end{cases}
    \end{aligned}
\text{したがって、}
\begin{aligned}
&=\displaystyle \int_{-\frac{1}{\sqrt{3}}}^{\frac{1}{\sqrt{3}}}\displaystyle \frac{\displaystyle \frac{\sqrt{3}}{2}du}{\left(\displaystyle \frac{\sqrt{3}}{2}u\right)^2+\left(\displaystyle \frac{\sqrt{3}}{2}\right)^2}\\[6pt]
&=\displaystyle \int_{-\frac{1}{\sqrt{3}}}^{\frac{1}{\sqrt{3}}}\displaystyle \frac{\displaystyle \frac{\sqrt{3}}{2}du}{\displaystyle \frac{3u^2}{4}+\displaystyle \frac{3}{4}}\\[6pt]
&=\displaystyle \int_{-\frac{1}{\sqrt{3}}}^{\frac{1}{\sqrt{3}}}\displaystyle \frac{\displaystyle \frac{\sqrt{3}}{2}du}{\displaystyle \frac{3}{4}(u^2+1)}\\[6pt]
&=\displaystyle \frac{2}{\sqrt{3}}\displaystyle \int_{-\frac{1}{\sqrt{3}}}^{\frac{1}{\sqrt{3}}}\displaystyle \frac{du}{u^2+1}
\end{aligned}
\text{ここで、} \displaystyle \int\displaystyle \frac{du}{u^2+1} \text{ を計算するため、} u=\tan\theta \text{ とおく：}
\text{積分範囲の変換：}
    \begin{aligned}
    \begin{cases}
    u=-\displaystyle \frac{1}{\sqrt{3}} \Leftrightarrow \tan\theta=-\displaystyle \frac{1}{\sqrt{3}} \Leftrightarrow \theta=-\displaystyle \frac{\pi}{6},\\[5pt]
    u=\displaystyle \frac{1}{\sqrt{3}} \Leftrightarrow \tan\theta=\displaystyle \frac{1}{\sqrt{3}} \Leftrightarrow \theta=\displaystyle \frac{\pi}{6}
    \end{cases}
    \end{aligned}
\begin{aligned}
\displaystyle \frac{2}{\sqrt{3}}\displaystyle \int_{-\frac{1}{\sqrt{3}}}^{\frac{1}{\sqrt{3}}}\displaystyle \frac{du}{u^2+1}
&=\displaystyle \frac{2}{\sqrt{3}}\displaystyle \int_{-\frac{\pi}{6}}^{\frac{\pi}{6}}\displaystyle \frac{\displaystyle \frac{1}{\cos^2\theta}d\theta}{\tan^2\theta+1}\\[6pt]
&=\displaystyle \frac{2}{\sqrt{3}}\displaystyle \int_{-\frac{\pi}{6}}^{\frac{\pi}{6}}\displaystyle \frac{\displaystyle \frac{1}{\cos^2\theta}d\theta}{\displaystyle \frac{1}{\cos^2\theta}}\\[6pt]
&=\displaystyle \frac{2}{\sqrt{3}}\displaystyle \int_{-\frac{\pi}{6}}^{\frac{\pi}{6}}d\theta\\[6pt]
&=\displaystyle \frac{2}{\sqrt{3}}\left[\theta\right]_{-\frac{\pi}{6}}^{\frac{\pi}{6}}\\[6pt]
&=\displaystyle \frac{2}{\sqrt{3}}\left(\displaystyle \frac{\pi}{6}-\left(-\displaystyle \frac{\pi}{6}\right)\right)\\[6pt]
&=\displaystyle \frac{2}{\sqrt{3}}\cdot\displaystyle \frac{\pi}{3}\\[6pt]
&=\displaystyle \frac{2\pi}{3\sqrt{3}}
\end{aligned}
\textbf{【まとめ】}
\text{3つの積分の結果をまとめると、}
\begin{aligned}
\displaystyle \int_{0}^{1}\displaystyle \frac{dx}{1+x^{3}}
&=\displaystyle \frac{1}{3}\cdot\log 2-\displaystyle \frac{1}{6}\cdot 0+\displaystyle \frac{1}{2}\cdot\displaystyle \frac{2\pi}{3\sqrt{3}}\\[6pt]
&=\displaystyle \frac{1}{3}\log 2+\displaystyle \frac{\pi}{3\sqrt{3}}
\end{aligned}

\textbf{【方針】}
\text{分母分子に}e^x\text{を掛けて} \dfrac{e^x}{1+e^{2x}} \text{とし，置換}u=e^x \text{を行う。}
\textbf{【解説】}
\begin{aligned}
\displaystyle \int_{0}^{ \frac{\log 3}{2}} \displaystyle \frac{2\,dx}{e^x+e^{-x}}
&= 2\displaystyle \int_{0}^{ \frac{\log 3}{2}} \displaystyle \frac{dx}{e^x+e^{-x}}\\
&= 2\displaystyle \int_{0}^{ \frac{\log 3}{2}} \displaystyle \frac{e^x}{1+e^{2x}}\,dx \\
\end{aligned}
\text{ここで、} u=e^x \text{とおくと、} du=e^x dx \text{より、積分範囲は} x=0\rightarrow  \displaystyle \frac{\log 3}{2} \text{の時、} u=1\rightarrow \sqrt{3} \text{となるので、}
\begin{aligned}
&= 2\displaystyle \int_{1}^{\sqrt{3}} \displaystyle \frac{1}{1+u^2}\,du
\end{aligned}
\text{ここで、} u= \tan \theta \text{とおくと、} du= \displaystyle \frac{1}{\cos^2 \theta} d\theta \text{より、積分範囲は} u=1\rightarrow \sqrt{3} \text{の時、} \tan\theta=1\rightarrow \sqrt{3} \text{より、} \theta=\displaystyle \frac{\pi}{4}\rightarrow \displaystyle \frac{\pi}{3} \text{と対応させる。}
\begin{aligned}
&= 2\displaystyle \int_{\frac{\pi}{4}}^{\frac{\pi}{3}} \displaystyle \frac{1}{1+\tan^2\theta}\cdot \displaystyle \frac{1}{\cos^2\theta}\,d\theta\\
&= 2\displaystyle \int_{\frac{\pi}{4}}^{\frac{\pi}{3}} \displaystyle \frac{1}{\frac{1}{\cos^2\theta}}\cdot \displaystyle \frac{1}{\cos^2\theta}\,d\theta\\
&= 2\displaystyle \int_{\frac{\pi}{4}}^{\frac{\pi}{3}} \cos^2\theta\cdot \displaystyle \frac{1}{\cos^2\theta}\,d\theta\\
&= 2\displaystyle \int_{\frac{\pi}{4}}^{\frac{\pi}{3}} d\theta\\
&= 2\left[\theta\right]_{\frac{\pi}{4}}^{\frac{\pi}{3}}\\
&= 2\left(\displaystyle \frac{\pi}{3}-\displaystyle \frac{\pi}{4}\right)\\
&= 2 \cdot \displaystyle \frac{\pi}{12}\\
&= \displaystyle \frac{\pi}{6}
\end{aligned}
\textbf{【補足】}
\text{双曲線関数を使うと下記のような流れになる。}
\cosh x = \displaystyle \frac{e^x+e^{-x}}{2} \text{が、双曲線余弦関数の定義である。この定義より、} e^x+e^{-x}=2\cosh x \text{なので、}
\begin{aligned}
\displaystyle \int \displaystyle \frac{2\,dx}{e^x+e^{-x}}
&= 2\displaystyle \int \displaystyle \frac{dx}{e^x+e^{-x}}\\
&= 2\displaystyle \int \displaystyle \frac{dx}{2\cosh x}\\
&= \displaystyle \int \displaystyle \frac{dx}{\cosh x}
\end{aligned}
\text{ここで、} u=e^x \text{とおいて、さらに} u=\tan\theta \text{とおくと、本解説の計算から}
\begin{aligned}
&= \displaystyle \int 2\,d\theta\\
&= 2\theta + C\\
&= 2\arctan(u) + C\\
&= 2\arctan(e^x) + C
\end{aligned}
\text{したがって、}
\begin{aligned}
\displaystyle \int \displaystyle \frac{2\,dx}{e^x+e^{-x}}
&= 2\arctan(e^x) + C
\end{aligned}
