\textbf{【解答】}
\text{対数を取ると、}\log\sqrt[n]{n} = \displaystyle \frac{\log n}{n} \ \underset{n\to\infty}{\longrightarrow} \ 0 \cdots (1)
\text{よって、}\log \text{の中身は} 1 \text{に収束する。ゆえに、}\lim_{n\to\infty} \sqrt[n]{n} = 1
\textbf{【補足：連続関数の性質】}
\text{一般に、連続関数 } f \text{ について、} \lim_{n\to\infty} f(a_n) = f\!\left(\lim_{n\to\infty} a_n\right) \text{ が成り立つ。}
\text{この問題では、} \log \text{ の連続性より：}
\lim_{n\to\infty} \log(\sqrt[n]{n}) = \log\!\left(\lim_{n\to\infty} \sqrt[n]{n}\right)
\text{この値は }(1) \text{より } 0 \text{ なので、} \log\!\left(\lim_{n\to\infty} \sqrt[n]{n}\right) = 0
\text{したがって、} \lim_{n\to\infty} \sqrt[n]{n} = 1

