\textbf{【方針】}
\text{(1) }\log(n!)=\displaystyle \sum_{k=1}^n\log k\text{ とおく。}
\text{(2) 単調増加関数 }\log x\text{ に対する積分評価で }\sum\log k\text{ をはさみうちする。}
\text{(3) 主要項 }n\log n-n\text{ で割ってはさみうちし、極限を出す。}
\textbf{【解答】}
\text{まず }S_n:=\log(n!)=\displaystyle \sum_{k=1}^n\log k\text{ とおく。}
\textbf{【積分ではさみうち】}
\text{関数 }f(x)=\log x\text{ は }x>0\text{ で単調増加である。}
\text{よって各 }k\ge1\text{ について区間 }[k,k+1]\text{ で } \log k\le \log x\le \log(k+1)\text{。}
\text{両辺を }[k,k+1]\text{ で積分すると}
\begin{aligned}
\log k
&\le \int_k^{k+1}\log x\,dx
\le \log(k+1).
\end{aligned}
\text{これを }k=1,2,\dots,n\text{ で和をとると}
\begin{aligned}
\displaystyle \sum_{k=1}^n \log k
&\le \int_{1}^{n+1}\log x\,dx
\le \displaystyle \sum_{k=1}^n \log(k+1).
\end{aligned}
\text{右端の和は}\displaystyle \sum_{k=1}^n\log(k+1)=\displaystyle \sum_{j=2}^{n+1}\log j=\log((n+1)!) \text{ だから}
\boxed{\displaystyle
\log(n!)\le \int_{1}^{n+1}\log x\,dx \le \log((n+1)!)
}
\text{同様に区間 }[k-1,k]\text{ を用いると } \int_{1}^{n}\log x\,dx \le \log(n!)\text{ も得られる。}
\text{よって}
\boxed{\displaystyle
 \displaystyle \int_{1}^{n}\log x\,dx \le \log(n!)\le \int_{1}^{n+1}\log x\,dx
}
\textbf{【積分の計算】}
\displaystyle \int \log x\,dx = x\log x - x + C\text{ より}
\begin{aligned}
\int_{1}^{n}\log x\,dx
&=\bigl[x\log x-x\bigr]_{1}^{n}
= n\log n-n+1,\\
\int_{1}^{n+1}\log x\,dx
&=\bigl[x\log x-x\bigr]_{1}^{n+1}
=(n+1)\log(n+1)-(n+1)+1.
\end{aligned}
\text{したがって}
\begin{aligned}
n\log n-n+1
\le \log(n!)
\le (n+1)\log(n+1)-(n+1)+1.
\end{aligned}
\textbf{【はさみうち】}
\text{両辺を }n\log n-n\ (>0)\text{ で割ると}
\box{\begin{aligned}
\frac{n\log n-n+1}{n\log n-n}
\le \frac{\log(n!)}{n\log n-n}
\le \frac{(n+1)\log(n+1)-(n+1)+1}{n\log n-n}.
\end{aligned}}
\textcolor{green}{左端は、 } \displaystyle 1+\frac{1}{n\log n-n}\to 1\ (n\to\infty)
\textcolor{green}{右端は、 } \log(n+1)=\log n+\log\!\left(1+\frac1n\right)\text{ を用いて整理する。}
\begin{aligned}
&\ \ \ \ \ \frac{(n+1)\log(n+1)-(n+1)+1}{n\log n-n}\\[5pt]
&=\frac{(n+1)\bigl(\log n+\log(1+\frac1n)\bigr)-(n+1)+1}{n\log n-n}\\[5pt]
&=\frac{(n+1)\log n+(n+1)\log(1+\frac1n)-n}{n\log n-n}\\[5pt]
&=\frac{n\log n-n+\log n+(n+1)\log(1+\frac1n)}{n\log n-n}\\[5pt]
&=1+\frac{\log n+(n+1)\log(1+\frac1n)}{n\log n-n}\\[5pt]
&=1+\frac{n\log(1+\frac1n)}{n\log n-n}
+\frac{\log n}{n\log n-n}
+\frac{\log(1+\frac1n)}{n\log n-n}\\[5pt]
&=1+\frac{\log(1+\frac1n)}{\log n-1}
+\frac{\log n}{n}\frac{1}{\log n-1}
+\frac{\log(1+\frac1n)}{n(\log n-1)}\\[5pt]
&=1+0 +0+0 = 1
\end{aligned}
\text{よって}
\boxed{\displaystyle 
\lim_{n\to\infty}\frac{(n+1)\log(n+1)-(n+1)+1}{n\log n-n}=1
}
\text{したがって右端も }1\text{ に収束する。}
\text{ゆえに、はさみうちより}
\boxed{\displaystyle \lim_{n\to\infty}\frac{\log(n!)}{n\log n-n}=1}

\textbf{【方針】}
\text{被積分関数 } \cos^3 x \text{ は偶関数なので、}
\displaystyle \int_{-\frac \pi 4}^{\frac \pi 4} \cos^3 x \, dx = \displaystyle 2\int_{0}^{\frac \pi 4} \cos^3 x \, dx \text{ として計算する。}
\textbf{【ポイント】}
\begin{aligned}
&\cos^3 x = \cos x(1-\sin^2 x)\\[5pt]
&u = \sin x \Rightarrow du = \cos x \, dx
\end{aligned}
\textbf{【解説】}
\begin{aligned}
\int_{-\frac{\pi}{4}}^{\frac{\pi}{4}} \cos^3 x \, dx
&= 2\int_{0}^{\frac{\pi}{4}} \cos^3 x \, dx\\[5pt]
&= 2\int_{0}^{\frac{\pi}{4}} (1-\sin^2 x)\cos x \, dx\\[5pt]
&= 2\int_{u=0}^{u=\sin(\frac \pi 4)} (1-u^2) \, du\\[5pt]
&= 2\int_{0}^{\frac{\sqrt{2}}{2}} (1-u^2) \, du\\[5pt]
&= 2\left[u - \displaystyle\frac{u^3}{3}\right]_{0}^{\frac{\sqrt{2}}{2}}\\[5pt]
&= 2\left(\displaystyle\frac{\sqrt{2}}{2} - \frac{\left(\frac{\sqrt{2}}{2}\right)^3}{3}\right)\\[5pt]
&= 2\left(\displaystyle\frac{\sqrt{2}}{2} - \frac{\frac{2\sqrt{2}}{8}}{3}\right)\\[5pt]
&= 2\left(\displaystyle\frac{\sqrt{2}}{2} - \displaystyle\frac{\sqrt{2}}{12}\right)\\[5pt]
&= 2\left(\displaystyle\frac{6\sqrt{2}}{12} - \displaystyle\frac{\sqrt{2}}{12}\right)\\[5pt]
&= 2 \cdot \displaystyle\frac{5\sqrt{2}}{12}\\[5pt]
&= \displaystyle\frac{5\sqrt{2}}{6}
\end{aligned}

