\textbf{【方針】}
\frac{2^{n}}{n!}=\prod_{k=1}^{n}\frac{2}{k} と書き，
3 \le k \text{ では } \displaystyle \frac{2}{k} \le \frac{2}{3} \text{ が成り立つ事を用いて、はさみうちにする。}
\textbf{【解答】}
\begin{aligned}
  0 &\le \frac{2^{n}}{n!}\\[6pt]
  &= \prod_{k=1}^{n}\frac{2}{k} \\[6pt]
  &= \left(\frac{2}{1}\cdot \frac{2}{2}\right)\cdot \prod_{k=3}^{n}\frac{2}{k} \\[6pt]
  &\le 2\cdot \left(\frac{2}{3}\right)^{\,n-2}
  \end{aligned}
\displaystyle \lim_{n\to\infty} 2 \cdot \left(\frac{2}{3}\right)^{\,n-2} = 0\text{ なので、はさみうちより、} \displaystyle \lim_{n\to\infty} \frac{2^{n}}{n!} = 0
\textbf{【補足：総乗記号】}
\displaystyle \prod_{k=m}^{n} a_k \ \ ( m\le n) \text{ は } a_m a_{m+1}\cdots a_n \text{ を表す。}
\textbf{【補足：総乗記号の例】}
\begin{aligned}
  \prod_{k=1}^{4} k
  &= 1\cdot 2\cdot 3\cdot 4 \\[4pt]
  &= 24 \\[10pt]
  \prod_{k=1}^{4}\frac{2}{k}
  &= \frac{2}{1}\cdot \frac{2}{2}\cdot \frac{2}{3}\cdot \frac{2}{4} \\[4pt]
  &= \frac{2^{4}}{1\cdot 2\cdot 3\cdot 4} \\[4pt]
  &= \frac{16}{24} \\[4pt]
  &= \frac{2}{3}
  \end{aligned}

