\textbf{【方針】}
\text{定数解を } A \text{ の形で求め、これを使ってただの等比数列の式に帰着させる。}
\textbf{【解法】}
\text{解の形を}A \text{と仮定して、元の漸化式に代入すると、} A = \displaystyle \frac{A - 9}{A - 5} \text{ である。}
\begin{aligned}
    &\ \ \ \ \ A(A - 5) = A - 9 \\
    &\Leftrightarrow A^2 - 5A = A - 9 \\
    &\Leftrightarrow A^2 - 6A + 9 = 0 \\
    &\Leftrightarrow (A - 3)^2 = 0 \\
    &\Leftrightarrow A = 3
    \end{aligned}
\text{解 } A = 3 \text{ を選んで、元の漸化式に代入すると、} 3 = \displaystyle \frac{3 - 9}{3 - 5} \cdots (1) \text{ である。}
\text{ここで命題1より、新たな数列}b_n = a_n - 3 \text{ を定義すると、分子の定数をなくした形に帰着させられる事が分かる。実際、元の漸化式から(1)を引いて、}
\begin{aligned}
      a_{n+1} &= \displaystyle \frac{a_n - 9}{a_n - 5}  \\
      3 &= \displaystyle \frac{3 - 9}{3 - 5} \cdots (1) \\
      \hline
      \ \ \ \ \ a_{n+1} - 3 &= \displaystyle \frac{a_n - 9}{a_n - 5} - \displaystyle \frac{3 - 9}{3 - 5} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{a_n - 9}{a_n - 5} - 3 \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{a_n - 9 - 3(a_n - 5)}{a_n - 5} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{a_n - 9 - 3a_n + 15}{a_n - 5} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{-2a_n + 6}{a_n - 5} \\
      \Leftrightarrow a_{n+1} - 3 &= \displaystyle \frac{-2(a_n - 3)}{a_n - 5}
      \end{aligned}
\text{ } b_n = a_n - 3 \text{ とおくと、} b_1 = a_1 - 3 = 2 - 3 = -1,\text{であり、}a_n = b_n + 3 \text{ である。これを代入すると、}
\begin{aligned}
    b_{n+1} &= \displaystyle \frac{-2(b_n + 3 - 3)}{b_n + 3 - 5} \\
    &= \displaystyle \frac{-2b_n}{b_n - 2}
    \end{aligned}
\text{両辺の逆数を取ると、}
\begin{aligned}
    &\ \ \ \ \ \displaystyle \frac{1}{b_{n+1}} = \displaystyle \frac{b_n - 2}{-2b_n} \\
    &\Leftrightarrow \displaystyle \frac{1}{b_{n+1}} = -\displaystyle \frac{1}{2} + \displaystyle \frac{1}{b_n}
    \end{aligned}
\text{ } c_n = \displaystyle \frac{1}{b_n} \text{ とおくと、} c_{n+1} = -\displaystyle \frac{1}{2} + c_n, c_1 = \frac{1}{b_1} = \frac{1}{-1} = -1 \text{ である。}
\text{これを解くと、} c_n = -1 + (n-1) \cdot \left(-\displaystyle \frac{1}{2}\right) = -\displaystyle \frac{n+1}{2}
\text{よって、}
\begin{aligned}
    &\ \ \ \ \ b_n = \displaystyle \frac{1}{c_n} \\
    &\Leftrightarrow b_n = -\displaystyle \frac{2}{n+1}
    \end{aligned}
\text{ここから、} a_n = b_n + 3 \text{ より、}a_n\text{を求めると、}
\begin{aligned}
    &\ \ \ \ \ a_n = b_n + 3 \\
    &\Leftrightarrow a_n = 3 - \displaystyle \frac{2}{n+1} \\
    &\Leftrightarrow a_n = \displaystyle \frac{3(n+1) - 2}{n+1} \\
    &\Leftrightarrow a_n = \displaystyle \frac{3n + 1}{n+1}
    \end{aligned}
\textbf{【命題1】}
\text{分数型の漸化式 } a_{n+1} = \displaystyle \frac{pa_n + q}{ra_n + s} \text{ が与えられたとき、定数解 } A \text{ を } A = \displaystyle \frac{pA + q}{rA + s} \text{ を満たすものとする。}
\text{このとき、} b_n = a_n - A \text{ とおくと、} b_{n+1} = \displaystyle \frac{(p - rA)b_n}{rb_n + rA + s} \text{ となり、分子の定数項がない漸化式に帰着する。}
\textbf{【証明】}
\text{定数解 } A \text{ は } A = \displaystyle \frac{pA + q}{rA + s} \text{ を満たすとする。両辺に } rA + s \text{ をかけると、}
\begin{aligned}
    &\ \ \ \ \ A(rA + s) = pA + q \\
    &\Leftrightarrow rA^2 + sA = pA + q \\
    &\Leftrightarrow rA^2 + (s - p)A - q = 0 \\
    &\Leftrightarrow rA^2 + (s - p)A - q = 0 \cdots (1)
    \end{aligned}
\text{ここで、} b_n = a_n - A \text{ とおくと、} a_n = b_n + A \text{ である。これを元の漸化式に代入すると、}
\begin{aligned}
    b_{n+1} + A &= \displaystyle \frac{p(b_n + A) + q}{r(b_n + A) + s} \\
    &= \displaystyle \frac{pb_n + pA + q}{rb_n + rA + s}
    \end{aligned}
\begin{aligned}
    b_{n+1} &= \displaystyle \frac{pb_n + pA + q}{rb_n + rA + s} - A \\
    &= \displaystyle \frac{pb_n + pA + q - A(rb_n + rA + s)}{rb_n + rA + s} \\
    &= \displaystyle \frac{pb_n  - rAb_n - (rA^2 + (s-p)A - q) }{rb_n + rA + s} \\
    \end{aligned}
\text{ここで、} A\text{は、(1)を満たし、分子の}rA^2 + (s-p)A - q\text{は0であるから、}
\begin{aligned}
      &=\displaystyle \frac{pb_n  - rAb_n}{rb_n + rA + s} \\
      &= \displaystyle \frac{(p - rA)b_n}{rb_n + rA + s} \\
    \end{aligned}
\text{よって、} b_{n+1} = \displaystyle \frac{(p - rA)b_n}{rb_n + rA + s}\cdot(2) \text{ となり、分子の定数項がない漸化式に帰着し、命題が示された。}
\text{【特に重解の場合】}
\text{重解の場合、判別式が0となるため、} (s-p)^2 + 4rq = 0 \text{ が成り立ち、解の公式より、} A = \displaystyle \frac{-(s-p)}{2r} = \displaystyle \frac{p-s}{2r} \text{ となる。}
\text{これを変形すると、} 2rA = p-s \Leftrightarrow rA + s = p -rA
\text{(2)について両辺の逆数をとると、} \displaystyle \frac{1}{b_{n+1}} = \displaystyle \frac{rb_n + rA + s}{(p - rA)b_n}
\text{ここで、} rA + s = p - rA \text{ より、} \displaystyle \frac{1}{b_{n+1}} = \displaystyle \frac{rb_n + (p - rA)}{(p - rA)b_n} = \displaystyle \frac{r}{p - rA} + \displaystyle \frac{1}{b_n}
\text{また、} p - rA = p - r \cdot \displaystyle \frac{p-s}{2r} = \displaystyle \frac{p+s}{2} \text{ であるから、} \displaystyle \frac{1}{b_{n+1}} = \displaystyle \frac{2r}{p+s} + \displaystyle \frac{1}{b_n}
\text{よって、} \displaystyle \frac{1}{b_n} \text{ は公差 } \displaystyle \frac{2r}{p+s} \text{ の等差数列となる。}

\textbf{【方針】}
\text{mod 6で考える。}
\textbf{【解法】}
\text{mod 6で考えると、}
\begin{aligned}
    6y^2 &\equiv 0 \pmod{6} \quad (\text{6の倍数}) \\
    223 &= 6 \times 37 + 1 \equiv 1 \pmod{6}
    \end{aligned}
\text{よって、}
\begin{aligned}
    x^2 + 6y^2 &\equiv x^2 \equiv 1 \pmod{6}
    \end{aligned}
\text{mod 6での }x \text{ の値を調べると、}
\begin{aligned}
    x \equiv 0 \pmod{6} &\Rightarrow x^2 \equiv 0 \pmod{6} \\
    x \equiv 1 \pmod{6} &\Rightarrow x^2 \equiv 1 \pmod{6} \\
    x \equiv 2 \pmod{6} &\Rightarrow x^2 \equiv 4 \pmod{6} \\
    x \equiv 3 \pmod{6} &\Rightarrow x^2 \equiv 9 \equiv 3 \pmod{6} \\
    x \equiv 4 \pmod{6} &\Rightarrow x^2 \equiv 16 \equiv 4 \pmod{6} \\
    x \equiv 5 \pmod{6} &\Rightarrow x^2 \equiv 25 \equiv 1 \pmod{6}
    \end{aligned}
\text{したがって } x^2 \equiv 1 \pmod{6} \text{ より、} x \equiv 1, 5 \pmod{6} \text{ が必要である。}
\text{また、} x^2 \le 223 \text{ より } |x| \le 14 \text{ である。}
\text{候補は } x = \pm 1, \pm 5, \pm 7, \pm 11, \pm 13 \text{ である。}
\text{各場合について } x^2 + 6y^2 = 223 \text{ を満たす整数 } y \text{ を求める。}
\textcolor{blue}{x = \pm 1 の場合}
\begin{aligned}
    1 + 6y^2 &= 223 \\
    6y^2 &= 222 \\
    y^2 &= 37
    \end{aligned}
\text{37は平方数ではないので}\textcolor{red}{解なし}
\textcolor{blue}{x = \pm 5 の場合}
\begin{aligned}
    25 + 6y^2 &= 223 \\
    6y^2 &= 198 \\
    y^2 &= 33
    \end{aligned}
\text{33は平方数ではないので}\textcolor{red}{解なし}
\textcolor{blue}{x = \pm 7 の場合}
\begin{aligned}
    49 + 6y^2 &= 223 \\
    6y^2 &= 174 \\
    y^2 &= 29
    \end{aligned}
\text{29は平方数ではないので}\textcolor{red}{解なし}
\textcolor{blue}{x = \pm 11 の場合}
\begin{aligned}
    121 + 6y^2 &= 223 \\
    6y^2 &= 102 \\
    y^2 &= 17
    \end{aligned}
\text{17は平方数ではないので}\textcolor{red}{解なし}
\textcolor{blue}{x = \pm 13 の場合}
\begin{aligned}
    169 + 6y^2 &= 223 \\
    6y^2 &= 54 \\
    y^2 &= 9 \\
    \textcolor{green}{y} & \textcolor{green}{= \pm 3}
    \end{aligned}
\text{よって、整数解は }(x,y)=(13,3),(13,-3),(-13,3),(-13,-3)\text{ である。}

\textbf{【方針】}
\text{極限点 } x = \displaystyle\frac{\pi}{2} \text{ を原点に平行移動する。すなわち、} t = x - \displaystyle\frac{\pi}{2} \text{ と置換することで、} x \to \displaystyle\frac{\pi}{2} \text{ を } t \to 0 \text{ に変換する。}
\text{この置換により、既知の極限公式 } \displaystyle \lim_{t\to 0}\frac{\sin t}{t} = 1 \text{ を直接適用できるようになる。}
\textbf{【解答】}
\text{変数変換 } t = x - \displaystyle\frac{\pi}{2} \text{ を行う。このとき、} x = t + \displaystyle\frac{\pi}{2} \text{ であり、} x \to \displaystyle\frac{\pi}{2} \text{ のとき } t \to 0 \text{ である。}
\text{まず、} \cos(3x) \text{ を変換する：}
\begin{aligned}
      \cos(3x) &= \cos\!\left(3\left(t + \displaystyle\frac{\pi}{2}\right)\right) \\[6pt]
      &= \cos\!\left(3t + \displaystyle\frac{3\pi}{2}\right) \\[6pt]
      &= \cos\!\left(3t + \pi + \displaystyle\frac{\pi}{2}\right) \\[6pt]
      &= -\cos\!\left(3t + \displaystyle\frac{\pi}{2}\right) \\[6pt]
      &= \sin(3t)
      \end{aligned}
\text{次に、} \tan(5x) \text{ を変換する：}
\begin{aligned}
      \tan(5x) &= \tan\!\left(5\left(t + \displaystyle\frac{\pi}{2}\right)\right) \\[6pt]
      &= \tan\!\left(5t + \displaystyle\frac{5}{2}\pi\right) \\[6pt]
      &= \tan\!\left(5t + 2\pi + \displaystyle\frac{\pi}{2}\right) \\[6pt]
      &= \tan\!\left(5t + \displaystyle\frac{\pi}{2}\right) \\[6pt]
      &= -\frac{\cos(5t)}{\sin(5t)}
      \end{aligned}
\text{したがって、}
\begin{aligned}
      \cos(3x)\tan(5x) &= \sin(3t) \cdot \left(-\frac{\cos(5t)}{\sin(5t)}\right) \\[6pt]
      &= -\frac{\sin(3t)\cos(5t)}{\sin(5t)}
      \end{aligned}
\text{よって、極限は } t \to 0 \text{ として、}
\begin{aligned}
      \lim_{x\to\frac{\pi}{2}}\cos(3x)\tan(5x) &= \lim_{t\to 0}\left(-\frac{\sin(3t)\cos(5t)}{\sin(5t)}\right) \\[6pt]
      &= -\lim_{t\to 0}\frac{\sin(3t)}{\sin(5t)} \cdot \lim_{t\to 0}\cos(5t) \\[6pt]
      &= -\lim_{t\to 0}\frac{\sin(3t)}{3t} \cdot \frac{5t}{\sin(5t)} \cdot \frac{3t}{5t} \cdot 1 \\[6pt]
      &= -\frac{3}{5} \cdot \lim_{t\to 0}\frac{\sin(3t)}{3t} \cdot \lim_{t\to 0}\frac{5t}{\sin(5t)} \\[6pt]
      &= -\frac{3}{5} \cdot 1 \cdot 1 \\[6pt]
      &= -\frac{3}{5}
      \end{aligned}

