\textbf{【方針】}
\text{対数を取る。}
\textbf{【解法】}
\text{両辺、底が2の対数を取ると、}
\log_2(a_n) = \log_2 \left(\frac {1}{2}(a_{n-1})^2\right) = -1 + 2\log_2(a_{n-1})
x_n:=\log_2 a_n \text{ とおけば、}
\text{これは1階線形漸化式 } x_n = - 1 + 2x_{n-1}  \text{ である。特性方程式 } \alpha = 2\alpha - 1 \text{ より } \alpha = 1 \text{ であるから、}
\begin{aligned}
x_n - 1 &= 2\left(x_{n-1} - 1\right) \\
&= 2^{n-1}\left(x_1 - 1\right) \\
&= 2^{n-1}\left(\log_2 5 - 1\right)
\end{aligned}
\text{よって、}
\begin{aligned}
x_n &= 2^{n-1}\log_2 5 - 2^{n-1} + 1 \\
&= 2^{n-1}\log_2 5 + 1 - 2^{n-1}
\end{aligned}
2^{x_n}= a_n \text{を用いて元に戻すと、}
\begin{aligned}
a_n &= 2^{x_n} = 2^{2^{n-1}\log_2 5 + 1 - 2^{n-1}} \\
&= 2^{2^{n-1}\log_2 5} \cdot 2^{1 - 2^{n-1}} \\
&= \left(2^{\log_2 5}\right)^{2^{n-1}} \cdot 2 \cdot 2^{-2^{n-1}} \\
&= 5^{2^{n-1}} \cdot 2 \cdot 2^{-2^{n-1}} \\
&= 2 \cdot \frac{5^{2^{n-1}}}{2^{2^{n-1}}} \\
&= 2 \cdot \left(\frac{5}{2}\right)^{2^{n-1}}
\end{aligned}
\text{例えば、} n = 4 \text{ のとき、}
\begin{aligned}
a_4 &= 2 \cdot \left(\frac{5}{2}\right)^{2^{3}} = 2 \cdot \left(\frac{5}{2}\right)^{8}\\[5pt]
&= 2 \cdot \frac{5^8}{2^8} = 2 \cdot \frac{390625}{256} = \frac{390625}{128} \approx 3051.76
\end{aligned}

\textbf{【解説】}
\text{無限級数} \displaystyle \sum_{k=1}^{\infty} a_k= (2-2)+(2-2)+(2-2)+\cdots \text{ の収束の定義より、まず部分和} S_n \text{を考えると、}
\text{ここで、} a_1 = 2-2 = 0, \ a_2 = 2-2 = 0, \ a_3 = 2-2 = 0, \ \ldots \text{ である。}
\begin{aligned}
        S_n &= (2-2)+(2-2)+\cdots+(2-2) \\[6pt]
        &= 0+0+\cdots+0 \\[6pt]
        &= 0
      \end{aligned}
\text{したがって、部分和の数列} S_n \text{ は } (0,0,0,0,\cdots) \text{ となる。}
\text{よって、無限級数} \displaystyle \sum_{k=1}^{\infty} a_k= (2-2)+(2-2)+(2-2)+\cdots \text{ は } 0 \text{ に収束する。}

\textbf{【解説】}
x^4 \text{ は偶関数，} \sin^5 x \text{ は奇関数。また、偶} \times \text{奇} = \text{奇関数なので、} x^4 \sin^5 x \text{ は奇関数。}
\text{したがって、対称区間 }[-2,2] \text{ での積分は、奇関数が原点対称なグラフであることから、}
\begin{aligned}
      \displaystyle \int_{-2}^{2} x^4 \sin^5 x \, dx = 0
      \end{aligned}
\textbf{【補足】}
\text{偶関数と奇関数の積分公式：}
\begin{aligned}
      &\text{（1）偶関数：} f(-x)=f(x) \text{ のとき、} \displaystyle \int_{-a}^{a} f(x)\,dx = 2\displaystyle \int_{0}^{a} f(x)\,dx\\[6pt]
      &\text{（2）奇関数：} f(-x)=-f(x) \text{ のとき、} \displaystyle \int_{-a}^{a} f(x)\,dx = 0
      \end{aligned}
\text{【証明】（1）偶関数の場合：}
\begin{aligned}
      \displaystyle \int_{-a}^{a} f(x)\,dx
      &=\textcolor{red}{\displaystyle \int_{-a}^{0} f(x)\,dx} + \displaystyle \int_{0}^{a} f(x)\,dx
      \end{aligned}
\text{第一項で } t=-x \text{ と置換すると、} x=-t,\; dx=-dt,\; x:-a\to 0 \;\Rightarrow\; t:a\to 0 \text{ より、}
\begin{aligned}
      \textcolor{red}{\displaystyle \int_{-a}^{0} f(x)\,dx}
      &=\displaystyle \int_{a}^{0} f(-t)(-dt)\\
      &=\displaystyle \int_{0}^{a} f(-t)\,dt
      \end{aligned}
\text{偶関数なので } f(-t)=f(t) \text{ より、}
\begin{aligned}
      &=\displaystyle \int_{0}^{a} f(t)\,dt\\
      &=\textcolor{red}{\displaystyle \int_{0}^{a} f(x)\,dx}
      \end{aligned}
\text{したがって、}
\begin{aligned}
      \displaystyle \int_{-a}^{a} f(x)\,dx
      &=\textcolor{red}{\displaystyle \int_{0}^{a} f(x)\,dx} + \displaystyle \int_{0}^{a} f(x)\,dx\\
      &=2\displaystyle \int_{0}^{a} f(x)\,dx
      \end{aligned}
\text{（2）奇関数の場合：}
\begin{aligned}
      \displaystyle \int_{-a}^{a} f(x)\,dx
      &=\textcolor{red}{\displaystyle \int_{-a}^{0} f(x)\,dx} + \displaystyle \int_{0}^{a} f(x)\,dx
      \end{aligned}
\text{第一項で } t=-x \text{ と置換すると、} x=-t,\; dx=-dt,\; x:-a\to 0 \;\Rightarrow\; t:a\to 0 \text{ より、}
\begin{aligned}
      \textcolor{red}{\displaystyle \int_{-a}^{0} f(x)\,dx}
      &=\displaystyle \int_{a}^{0} f(-t)(-dt)\\
      &=\displaystyle \int_{0}^{a} f(-t)\,dt
      \end{aligned}
\text{奇関数なので } f(-t)=-f(t) \text{ より、}
\begin{aligned}
      &=\displaystyle \int_{0}^{a} (-f(t))\,dt\\
      &=-\displaystyle \int_{0}^{a} f(t)\,dt\\
      &=\textcolor{red}{- \displaystyle \int_{0}^{a} f(x)\,dx}
      \end{aligned}
\text{したがって、}
\begin{aligned}
      \displaystyle \int_{-a}^{a} f(x)\,dx
      &=\textcolor{red}{- \displaystyle \int_{0}^{a} f(x)\,dx} + \displaystyle \int_{0}^{a} f(x)\,dx\\
      &=0
      \end{aligned}

\text{【力学(※大学レベル)】}
\text{• 減衰振動}
\textcolor{brown}{\large{【電磁気学】}}
\text{• RLC直列回路について、キルヒホッフの第二法則を用いると }
  LQ^{\prime\prime}(t) + RQ^{\prime}(t) + \displaystyle \frac{Q(t)}{C} = 0 \text{が成り立つ。}
\text{【問題の記号と力学における記号の対応】}
\text{減衰振動:} \ mx^{\prime\prime}(t) + 2cx^{\prime}(t) + kx(t) = 0
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } f_0 \leftrightarrow x_0 \text{（初期位置）}
\text{• } v_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RLC直列回路の過渡応答:} \ LQ^{\prime\prime}(t) + RQ^{\prime}(t) + \displaystyle \frac{Q(t)}{C} = 0
\text{• } f(t) \leftrightarrow Q(t) \text{（コンデンサに蓄えられた電荷）}
\text{• } f^{\prime}(t) \leftrightarrow Q^{\prime}(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow Q^{\prime\prime}(t) \text{（電流変化率）}
\text{• } \beta \leftrightarrow \displaystyle \frac{R}{2L} \text{（減衰定数）}
\text{• } \omega_0 \leftrightarrow \displaystyle \frac{1}{\sqrt{LC}} \text{（減衰定数が0の場合の固有角周波数）}
\text{• } \sqrt{\omega_0^2 - \beta^2} \leftrightarrow \sqrt{\displaystyle \frac{1}{LC} - \left(\displaystyle \frac{R}{2L}\right)^2} \text{（減衰角周波数）}
\text{• } f_0 \leftrightarrow Q_0 \text{（初期電荷）}
\text{• } v_0 \leftrightarrow I_0 \text{（初期電流）}
\textcolor{brown}{\large{【物理的意味】}}
\text{• 包絡線: } e^{-\beta t} \text{ で指数的に減衰しながら振動}
\text{• 振動周波数: } \sqrt{\omega_0^2 - \beta^2} \text{ （自然周波数より低い）}
\text{• 条件 } \omega_0 > \beta \text{ により減衰振動}
\textcolor{brown}{\large{【解法】}}
\textcolor{green}{f'の係数 Rが0の場合の公式}
\text{微分方程式 } f^{\prime\prime}(t) = -\omega^2 f(t) \text{ に対する初期値問題}
f(0) = A_0,\quad f^{\prime}(0) = v_0 \text{の解は}
f(t) = A_0\cos(\omega t) + \displaystyle \frac{v_0}{\omega}\sin(\omega t) \text{である。}
\textcolor{blue}{この公式を用いて、本問を解く。}
\textcolor{green}{1.\ } \textcolor{green}{変数変換で1階微分を消す}
\text{元の微分方程式の両辺に、}e^{\beta t}\text{を掛けると}
\quad \ \ f^{\prime\prime}(t) + 2\beta f^{\prime}(t) + \omega_0^2 f(t) = 0
\Leftrightarrow \textcolor{red}{e^{\beta t}f^{\prime\prime}(t)} + \textcolor{red}{2e^{\beta t} \beta f^{\prime}(t)} +  e^{\beta t} \omega_0^2 f(t) = 0 \cdots (1)
\text{ここで、積の微分公式より、}
\left(e^{\beta t}f(t)\right)''(t) = e^{\beta t}f^{\prime\prime}(t) + 2e^{\beta t} \beta f^{\prime}(t) + e^{\beta t} \beta^2 f(t)
\text{が成り立つ。ゆえに、}
\textcolor{red}{e^{\beta t}f^{\prime\prime}(t)} + \textcolor{red}{2e^{\beta t} \beta f^{\prime}(t)} = \textcolor{blue}{\left(e^{\beta t}f(t)\right)''(t) - \beta^2 e^{\beta t}f(t)}
\text{これを用いて置き換えると、}(1) \text{ は}
\quad \ \textcolor{blue}{\left(e^{\beta t}f(t)\right)'' - \beta^2 e^{\beta t}f(t)} + \omega_0^2 e^{\beta t}f(t) = 0
\Leftrightarrow \left(e^{\beta t}f(t)\right)'' + \left(\omega_0^2 - \beta^2\right) e^{\beta t}f(t) = 0
\text{ここで、} g(t) = e^{\beta t} f(t) \text{ とおくと}
g^{\prime\prime}(t) + \left(\omega_0^2 - \beta^2\right) g(t) = 0\ \ \cdots (2)
\textcolor{green}{2.\ } \textcolor{green}{公式を適用し} \textcolor{green}{g} \textcolor{green}{を求める}
\text{(2)は単振動の方程式なので、冒頭の公式を適用すると（}\omega = \sqrt{\omega_0^2 - \beta^2}\text{）}
g(t) = g(0)\cos\left(\sqrt{\omega_0^2 - \beta^2}\ \,t\right) + \displaystyle \frac{g^{\prime}(0)}{\sqrt{\omega_0^2 - \beta^2}}\sin\left(\sqrt{\omega_0^2 - \beta^2}\ \,t\right)
\textcolor{green}{3.\ } \textcolor{green}{g} \textcolor{green}{の初期条件を求める}
\text{ } g(t) = e^{\beta t} f(t) \text{ より}
\begin{aligned}
  g(0) &= e^{\beta \cdot 0} f(0) = f_0\\[6pt]
  g^{\prime}(0) &= \beta e^{\beta \cdot 0} f(0) + e^{\beta \cdot 0} f^{\prime}(0) = \beta f_0 + v_0
  \end{aligned}
\textcolor{green}{4.\ } \textcolor{green}{g} \textcolor{green}{を求める}
\text{公式に代入すると}
g(t) = f_0\cos\left(\sqrt{\omega_0^2 - \beta^2}\ \,t\right) + \displaystyle \frac{v_0 + \beta f_0}{\sqrt{\omega_0^2 - \beta^2}}\sin\left(\sqrt{\omega_0^2 - \beta^2}\ \,t\right)
\textcolor{green}{5.\ } \textcolor{green}{g} \textcolor{green}{から} \textcolor{green}{f} \textcolor{green}{を求める}
\text{ } g(t) = e^{\beta t} f(t) \text{ より、} f(t) = e^{-\beta t} g(t)
\text{よって}
f(t) = e^{-\beta t}\left(f_0\cos\left(\sqrt{\omega_0^2 - \beta^2}\ \,t\right) + \displaystyle \frac{v_0 + \beta f_0}{\sqrt{\omega_0^2 - \beta^2}}\sin\left(\sqrt{\omega_0^2 - \beta^2}\ \,t\right)\right)

\textbf{【命題】}
\displaystyle \sum_{k=1}^{\infty}\frac{(-1)^{k+1}}{k}=\log 2
\textbf{【解答1】（偶数部分和→区分求積）}
\text{部分和 } S_n=\displaystyle \sum_{k=1}^{n}\frac{(-1)^{k+1}}{k}\text{ とおく。まず偶数部分和 }S_{2N}\text{ を調べる。}
\textbf{【補題】}\ \displaystyle \sum_{k=1}^{2N}\frac{(-1)^{k+1}}{k}=\displaystyle \sum_{k=1}^{N}\frac{1}{N+k}
\textbf{【補題の証明】}
\text{交代和}
\displaystyle \  1-\frac12+\frac13-\frac14+\cdots-\frac{1}{2N}
\text{ を考える。}\text{まずすべて正として足すと}
\displaystyle \  1+\frac12+\frac13+\frac14+\cdots+\frac{1}{2N}
\text{ここから負号が付いていた項} \displaystyle \  \frac12,\frac14,\ldots,\frac{1}{2N} \text{を2回引くと}
\begin{aligned}
&\ \displaystyle \ \ \ \ \ \displaystyle \sum_{k=1}^{2N}\frac{(-1)^{k+1}}{k}\\[6pt]
&\displaystyle = 1-\frac12+\frac13-\frac14+\cdots-\frac{1}{2N}\\[6pt]
&\displaystyle =\left(1+\frac12+\cdots+\frac{1}{2N}\right)
-2\left(\frac12+\frac14+\cdots+\frac{1}{2N}\right)\\[6pt]
&\displaystyle =\left(1+\frac12+\cdots+\frac{1}{2N}\right)
-\left(1+\frac12+\cdots+\frac{1}{N}\right)\\[6pt]
& \displaystyle =\frac{1}{N+1}+\frac{1}{N+2}+\cdots+\frac{1}{2N}\\[6pt]
& \displaystyle  =\displaystyle \sum_{k=1}^{N}\frac{1}{N+k}
\end{aligned} \quad \text{Q.E.D}
\text{補題より } S_{2N}=\displaystyle \sum_{k=1}^{N}\frac{1}{N+k} \text{これを }N\text{ で割って}
\begin{aligned}
  S_{2N}
  &=\displaystyle \sum_{k=1}^{N}\frac{1}{N+k}
  =\frac1N\displaystyle \sum_{k=1}^{N}\frac{1}{1+\frac{k}{N}}.
  \end{aligned}
\text{右辺は } \displaystyle f(x)=\frac{1}{1+x}\text{ の区間 }[0,1]\text{ 上のリーマン和であるから}
\begin{aligned}
  \lim_{N\to\infty}S_{2N}   &=\lim_{N\to\infty}\frac1N\displaystyle \sum_{k=1}^{N}\frac{1}{1+\frac{k}{N}}\\[6pt]
  &=\int_{0}^{1}\frac{1}{1+x}\,dx\\[6pt]
  &=\Bigl[\log(1+x)\Bigr]_{0}^{1}\\[6pt]
  &=\log 2
  \end{aligned}
\textbf{【注意：}S_{2N+1}\textbf{も同じ極限】}
\begin{aligned}
  S_{2N+1} &=\displaystyle \sum_{k=1}^{2N+1}\frac{(-1)^{k+1}}{k}\\[6pt]
  &=\displaystyle \sum_{k=1}^{2N}\frac{(-1)^{k+1}}{k}+\frac{1}{2N+1}\\[6pt]
  &= S_{2N}+\frac{1}{2N+1}
  \end{aligned}
\text{よって }\displaystyle S_{2N+1}-S_{2N}=\frac{1}{2N+1}\to 0 \ (N\to\infty)\text{したがって}
\lim_{N\to\infty}S_{2N}=\log 2 \ \Rightarrow\ \lim_{N\to\infty}S_{2N+1}=\log 2 \text{ でもある。}
\text{偶数・奇数の部分和が同じ極限 } \log 2 \text{ に収束するので、全体の部分和 }S_n\text{ も } \log 2 \text{ に収束する。}
\textbf{【解答2】（積分表示→等比数列の和）}
\text{各項は } \displaystyle \frac{(-1)^{k+1}}{k}=\int_0^1 (-t)^{k-1}\,dt \text{ と表せる。}
\begin{aligned}
  S_n&=\displaystyle \sum_{k=1}^{n}\frac{(-1)^{k+1}}{k}\\[6pt]
  &=\displaystyle \sum_{k=1}^{n}\int_0^1 (-t)^{k-1}\,dt\\[6pt]
  &=\int_0^1\displaystyle \sum_{k=0}^{n-1}(-t)^k\,dt
  \end{aligned}
\text{等比数列の和より } \displaystyle \sum_{k=0}^{n-1}(-t)^k=\frac{1-(-t)^n}{1+t}\text{。よって}
\begin{aligned}
  S_n&=\int_0^1\frac{1-(-t)^n}{1+t}\,dt\\[6pt]
  &=\int_0^1\frac{1}{1+t}\,dt-\int_0^1\frac{(-t)^n}{1+t}\,dt  
  \end{aligned}
\int_0^1\frac{1}{1+t}\,dt=\Bigl[\log(1+t)\Bigr]_0^1=\log 2.
\text{また } 0<\frac{t^n}{1+t}<t^n\ (0<t<1)\text{ より}
\begin{aligned}
  \left|\int_0^1\frac{(-t)^n}{1+t}\,dt\right|
  &\le \int_0^1 \frac{t^n}{1+t}\,dt
  <\int_0^1 t^n\,dt
  =\frac{1}{n+1}\to 0.
  \end{aligned}
\text{したがって } \displaystyle \lim_{n\to\infty}S_n=\log 2 \text{。}
\boxed{\displaystyle \sum_{k=1}^{\infty}\frac{(-1)^{k+1}}{k}=\log 2}
\textbf{【補足】}
\text{この級数をメルカトル級数という。}

\textbf{【方針】}
\text{二次・一次項に注目し、二つの一次式の積に分解する。定数は後で調整する。}
\textbf{【解法】}
2x^2 + 11xy + 12y^2 - 5y = (ax+by+c)(dx+ey+f) -cf\text{ とおく。すると、}
\begin{aligned}
    &\ \ \ \ \ 2x^2 + 11xy + 12y^2 - 5y \\
    &= (ax+by+c)(dx+ey+f) -cf \\
    &= ad x^2 + (ae+bd) xy + (af+cd)x \\
    &\quad + be y^2 + (bf+ce) y + cf
    \end{aligned}
\text{となる。二次・一次項の係数を比較すると、}
\begin{cases}
    \textcolor{blue}{ad=2 \cdots} \textcolor{blue}{(1)}\\
    \textcolor{blue}{ae+bd=11 \cdots} \textcolor{blue}{(2)}\\
    \textcolor{blue}{af+cd=0 \cdots} \textcolor{blue}{(3)}\\
    \textcolor{blue}{be=12 \cdots} \textcolor{blue}{(4)}\\
    \textcolor{blue}{bf+ce=-5 \cdots} \textcolor{blue}{(5)}
    \end{cases}
\textcolor{blue}{(1)}\text{ より、}ad=2\text{ については }(1,2),(2,1),(-1,-2),(-2,-1)\text{ のいずれを選んでも符号や順序が交換するだけなので、} \textcolor{green}{(a,d)=(1,2)} \text{とする。}
\textcolor{blue}{(2)}\text{ と }\textcolor{blue}{(4)}\text{ より、}be=12\text{ かつ }e+2b=11\text{ となる正の整数の組を探す。}
b,e\text{どちらの正の数であるので候補を列挙すると }(b,e)=(1,12),(2,6),(3,4),(4,3),(6,2),(12,1)
\text{条件 }e+2b=11\text{ を満たすのは }\textcolor{green}{(b,e)=(4,3)}\text{ のみ。}
\textcolor{blue}{(3)}\text{ より、}af+cd=0 \Leftrightarrow f+2c=0 \Leftrightarrow f=-2c
\textcolor{blue}{(5)}\text{ より、}bf+ce=-5 \Leftrightarrow 4f+3c=-5
\text{ }f=-2c\text{ を代入して }4(-2c)+3c=-5 \Leftrightarrow -5c=-5 \Leftrightarrow \textcolor{green}{c=1}\text{よって} \textcolor{green}{f=-2}
\text{したがって連立方程式(1)~(5)の整数解は }
\begin{aligned}
    \textcolor{green} {(a,b,c,d,e,f)=(1,4,1,2,3,-2)}
    \end{aligned}
\text{したがって一次因子は } x+4y+1 \text{ と } 2x+3y-2 \text{ である。}
\text{よって、} 2x^2 + 11xy + 12y^2 - 5y = (x+4y+1)(2x+3y-2) + 2
\text{従って、元の方程式は }
\begin{aligned}
    &\ \ \ \ \ 2x^2+11xy+12y^2-5y-5=0 \\
    &  \Leftrightarrow (x+4y+1)(2x+3y-2) + 2 - 5=0 \\
    &  \Leftrightarrow (x+4y+1)(2x+3y-2)=3 \\ 
    &  \Leftrightarrow (x+4y+1,2x+3y-2)=(1,3),(3,1),(-1,-3),(-3,-1) \\ 
    \end{aligned}
\text{各場合について連立方程式を解く。}
\textcolor{blue}{(x+4y+1,2x+3y-2)=(1,3)}\text{ の場合}
\begin{aligned}
    &\ \ \ \ \ x+4y+1=1 \\
    &\ \ \ \ \ 2x+3y-2=3 \\
    &\Leftrightarrow x+4y=0,\ 2x+3y=5 \\
    &\Leftrightarrow x=-4y\text{ を第2式に代入して }2(-4y)+3y=5 \\
    &\Leftrightarrow -5y=5 \\
    &\Leftrightarrow \textcolor{green}{y=-1,\ x=4}
    \end{aligned}
\textcolor{blue}{(x+4y+1,2x+3y-2)=(3,1)}\text{ の場合}
\begin{aligned}
    &\ \ \ \ \ x+4y+1=3 \\
    &\ \ \ \ \ 2x+3y-2=1 \\
    &\Leftrightarrow x+4y=2,\ 2x+3y=3 \\
    &\Leftrightarrow \text{第1式×2: }2x+8y=4 \\
    &\Leftrightarrow \text{第2式から引いて }5y=1 \\
    &\Leftrightarrow y=\frac{1}{5}\textcolor{red}{（整数でない）}
    \end{aligned}
\textcolor{blue}{(x+4y+1,2x+3y-2)=(-1,-3)}\text{ の場合}
\begin{aligned}
    &\ \ \ \ \ x+4y+1=-1 \\
    &\ \ \ \ \ 2x+3y-2=-3 \\
    &\Leftrightarrow x+4y=-2,\ 2x+3y=-1 \\
    &\Leftrightarrow \text{第1式×2: }2x+8y=-4 \\
    &\Leftrightarrow \text{第2式から引いて }5y=3 \\
    &\Leftrightarrow y=\frac{3}{5}\textcolor{red}{（整数でない）}
    \end{aligned}
\textcolor{blue}{(x+4y+1,2x+3y-2)=(-3,-1)}\text{ の場合}
\begin{aligned}
    &\ \ \ \ \ x+4y+1=-3 \\
    &\ \ \ \ \ 2x+3y-2=-1 \\
    &\Leftrightarrow x+4y=-4,\ 2x+3y=1 \\
    &\Leftrightarrow \text{第1式×2: }2x+8y=-8 \\
    &\Leftrightarrow \text{第2式から引いて }5y=9 \\
    &\Leftrightarrow y=\frac{9}{5}\textcolor{red}{（整数でない）}
    \end{aligned}
\text{よって、整数解は }(x,y)=(4,-1)\text{ のみ。}

\textbf{【方針】}
I_{m,n}=\displaystyle \int_{0}^{\frac{\pi}{2}} \sin^{2m-1} x \cos^{2n-1} x\,dx \text{ とおき、} u=\sin^2 x \text{ とおく置換積分により、階乗を使った形に帰着させる。}
\textcolor{green}{【命題】}
m,n \text{ を正の整数として、} I_{m,n}=\displaystyle\int_{0}^{\frac{\pi}{2}} \sin^{2m-1} x \cos^{2n-1} x\,dx \text{ とおくとき、} \textcolor{green}{I_{m,n}=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{(m-1)!(n-1)!}{(m+n-1)!}} \text{ が成り立つ。}
\textbf{【証明】}
\text{置換 } u=\sin^2 x \text{ とおくと、} du=2\sin x\cos x\,dx \text{ である。}
\text{積分範囲の変換：}
\begin{aligned}
      \begin{cases}
      x=0 \Leftrightarrow u=\sin^2 0=0,\\[5pt]
      x=\displaystyle\frac{\pi}{2} \Leftrightarrow u=\sin^2\displaystyle\frac{\pi}{2}=1
      \end{cases}
      \end{aligned}
\text{被積分関数を変形すると、}
\begin{aligned}
      \sin^{2m-1} x \cos^{2n-1} x
      &=\sin^{2m-1} x \cos^{2n-1} x\\[6pt]
      &=(\sin^2 x)^{m-\frac{1}{2}} (\cos^2 x)^{n-\frac{1}{2}}\\[6pt]
      &=u^{m-\frac{1}{2}} (1-u)^{n-\frac{1}{2}}
      \end{aligned}
\text{また、} dx=\displaystyle\frac{du}{2\sin x\cos x}=\frac{du}{2u^{\frac{1}{2}}(1-u)^{\frac{1}{2}}} \text{ であるから、}
\begin{aligned}
      I_{m,n}
      &=\displaystyle\int_{0}^{\frac{\pi}{2}} \sin^{2m-1} x \cos^{2n-1} x\,dx\\[6pt]
      &=\displaystyle\int_{0}^{1} u^{m-\frac{1}{2}} (1-u)^{n-\frac{1}{2}} \cdot \frac{du}{2u^{\frac{1}{2}}(1-u)^{\frac{1}{2}}}\\[6pt]
      &=\displaystyle\frac{1}{2}\displaystyle\int_{0}^{1} u^{m-1} (1-u)^{n-1}\,du
      \end{aligned}
\text{部分積分を用いて、}
\begin{aligned}
      &\ \ \ \ \ \displaystyle\frac{1}{2}\displaystyle\int_{0}^{1} u^{m-1}(1-u)^{n-1}\,du\\
      &=\displaystyle\frac{1}{2}\displaystyle\int_{0}^{1} \left(\displaystyle\frac{u^m}{m}\right)' \cdot (1-u)^{n-1} \,du\\[6pt]
      &=\displaystyle\frac{1}{2}\left(\left[\displaystyle\frac{u^m}{m}(1-u)^{n-1}\right]_{0}^{1}-\displaystyle\int_{0}^{1} \displaystyle\frac{u^m}{m} \cdot (n-1)(1-u)^{n-2}(-1)\,du\right)\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m}\displaystyle\int_{0}^{1} u^m(1-u)^{n-2}\,du
      \end{aligned}
\text{同様に繰り返すと、}
\begin{aligned}
      &\ \ \ \ \  \displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m}\int_{0}^{1} u^m(1-u)^{n-2}\,du\\
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m} \int_{0}^{1} \left(\displaystyle\frac{u^{m+1}}{m+1}\right)' \cdot (1-u)^{n-2} \,du\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m}\left( \left[\displaystyle\frac{u^{m+1}}{m+1}(1-u)^{n-2}\right]_{0}^{1}-\displaystyle\int_{0}^{1} \displaystyle\frac{u^{m+1}}{m+1} \cdot (n-2)(1-u)^{n-3}(-1)\,du\right) \\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m} \cdot\displaystyle\frac{n-2}{m+1}\displaystyle\int_{0}^{1} u^{m+1}(1-u)^{n-3}\,du
      \end{aligned}
\text{さらに繰り返すと、}
\begin{aligned}
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m}\cdot\displaystyle\frac{n-2}{m+1}\displaystyle\int_{0}^{1} u^{m+1}(1-u)^{n-3}\,du\\[6pt]
      &=\cdots\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{n-1}{m}\cdot\displaystyle\frac{n-2}{m+1}\cdots\displaystyle\frac{1}{m+n-2}\displaystyle\int_{0}^{1} u^{m+n-2}(1-u)^0\,du\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{(n-1)!}{m(m+1)\cdots(m+n-2)}\cdot\displaystyle\frac{1}{m+n-1}\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{(n-1)!}{m(m+1)\cdots(m+n-2)}\cdot\displaystyle\frac{1}{m+n-1} \cdot \frac{(m-1)!}{(m-1)!}\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{(m-1)!(n-1)!}{(m+n-1)!}
      \end{aligned}
\text{したがって、}
\begin{aligned}
      I_{m,n}
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{(m-1)!(n-1)!}{(m+n-1)!}
      \end{aligned}\quad\text{Q.E.D}
\textbf{【$\sin^7 x \cos^9 x$ の場合】}
\text{本問では } \sin^7 x \cos^9 x \text{ であるから、} 2m-1=7, 2n-1=9 \text{ より } m=4, n=5 \text{ である。}
\begin{aligned}
      I_{4,5}
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{(4-1)!(5-1)!}{(4+5-1)!}\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{3! \cdot 4!}{8!}\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{6}{8\cdot 7 \cdot 6 \cdot 5}\\[6pt]
      &=\displaystyle\frac{1}{2}\cdot\displaystyle\frac{1}{280}\\[6pt]
      &=\displaystyle\frac{1}{560}
      \end{aligned}

\textbf{【方針】}
\text{係数 }3,7\text{ の最大公約数は }1\text{ であり、このことにより任意の }z\text{ に対して，方程式 }7x-3y+13z=2\text{ の整数解 }x,y\text{ が存在する。よって適当に }z\text{ を定め、その値に対する全ての} (x,y) \text{を求めることで一般解を求める。}
\textbf{【解法】}
\text{今，適当に 整数}z \text{ を定め，それを }\ell\text{ とする。すなわち }z=\ell \text{ とおき，方程式を}7x-3y=2-13\ell\text{ として、}\ell \text{を一つ固定してそれについて解き、一般解は全ての整数}\ell\text{を集めたものとして表す。}
\textbf{【解を1つ見つける】}
\text{まず，}7x-3y=1\text{ の解として、}(x,y)=(1,2)\text{ が見つかる。}
\text{したがって両辺を，} 2-13\ell \text{倍すると、} 7x-3y=2-13\ell \text{ の解}(x_0,y_0)=(2-13\ell,2(2-13\ell))\text{ が見つかる。}
\text{すなわち、} 7 \cdot (2-13\ell) - 3 \cdot 2(2-13\ell) = 2-13\ell
\textbf{【一般解の構成】}
\text{ここで、式} 7x-3y=2-13\ell \text{から} 7 \cdot (2-13\ell) - 3 \cdot 2(2-13\ell) = 2-13\ell \text{を引くと、}
\begin{aligned}
    7x - 3y &= 2-13\ell \\
    7 \cdot (2-13\ell) - 3 \cdot 2(2-13\ell) &= 2-13\ell \\
    \hline
    7(x - (2-13\ell)) - 3(y - 2(2-13\ell)) &= 0 
    \end{aligned}
7,3 \text{は互いに素なので、}
    \begin{aligned}
    \begin{cases} 
    &x-(2-13\ell) = 3k \\
    &y-2(2-13\ell) = 7k
    \end{cases}
    \end{aligned}
    \text{となる整数} k \text{が存在する。よって、}
\begin{aligned}
    &\ \ \ \ \ 
    \begin{cases} 
    x - (2-13\ell) = 3k \\
    y-2(2-13\ell) = 7k
    \end{cases}\\
    &\Leftrightarrow
    \begin{cases} 
    x = (2 - 13\ell) + 3k = 3k + 2 - 13\ell\\
    y = 2(2 - 13\ell) + 7k = 7k + 4 - 26\ell
    \end{cases}
    \end{aligned}
\text{が与えられた、}z = \ell \text{ に対する全ての解なので、問題の方程式} 7x-3y+13z=2 \text{ の一般解は}
    \begin{cases} 
    x = 3k + 2 - 13\ell\\
    y = 7k + 4 - 26\ell\\
    z = \ell
    \end{cases}
    \text{である。ただし、} k,\ell \text{は任意の整数。}

