&\ \ \ \ \ \textcolor{blue}{2\int_{0}^{\frac{1}{2}} \frac{du}{(1-u^2)^2}}\\[5pt]
&= 2\int_{0}^{\frac{1}{2}} \left[\frac{1}{4(1-u)} + \frac{1}{4(1-u)^2} + \frac{1}{4(1+u)} + \frac{1}{4(1+u)^2}\right] du\\[5pt]
&= \frac{1}{2}\left[-\log|1-u| + \frac{1}{1-u} + \log|1+u| - \frac{1}{1+u}\right]_{0}^{\frac{1}{2}}\\[5pt]
&= \frac{1}{2}\left[\log\left|\frac{1+u}{1-u}\right| + \frac{2u}{1-u^2}\right]_{0}^{\frac{1}{2}}\\[5pt]
&= \frac{1}{2}\left[\log\left(\frac{1+\frac{1}{2}}{1-\frac{1}{2}}\right) + \frac{2 \cdot \frac{1}{2}}{1-\frac{1}{4}}\right]\\[5pt]
&= \frac{1}{2}\left[\log\left(\frac{\frac{3}{2}}{\frac{1}{2}}\right) + \frac{1}{\frac{3}{4}}\right]\\[5pt]
&= \frac{1}{2}\left[\log 3 + \frac{4}{3}\right]\\[5pt]
&= \frac{1}{2}\log 3 + \frac{2}{3}
\end{aligned}

\textbf{【ポイント】}
\text{因数定理を用いる。定数項が } 6 \text{ なので、} \pm 1, \pm 2, \pm 3, \pm 6 \text{が候補。}
\textbf{【解説】}
\begin{aligned}
 f(1) &= 1^3 - 2 \cdot 1^2 - 5 \cdot 1 + 6 \\
 &= 1 - 2 - 5 + 6 = 0
 \end{aligned}
\text{よって、} x - 1 \text{ が因数。}
\text{ } x^3 - 2x^2 - 5x + 6 \text{ を } x - 1 \text{ で割ると、}
\begin{aligned}
 x^3 - 2x^2 - 5x + 6 &= (x - 1)(x^2 - x - 6) \\
 &= (x - 1)(x - 3)(x + 2)
 \end{aligned}

\textbf{【方針】}
\text{これは } f(x)=\log(1+x) \text{ の } x=0 \text{ での微分係数である}
\textbf{【解答】}
\begin{aligned}
      \lim_{x\to 0}\frac{\log(1+x)}{x}
      &= \lim_{x\to 0}\frac{\log(1+x)-\log(1+0)}{x-0} \\[6pt]
      &= \lim_{x\to 0}\frac{f(x)-f(0)}{x-0} \\[6pt]
      &= f^{\prime}(0) \\[6pt]
      &= (\log(1+x))' \Big|_{x=0} \\[6pt]
      &= \frac{1}{1+x} \Big|_{x=0} \\[6pt]
      &= \frac{1}{1+0} \\[6pt]
      &= 1
      \end{aligned}

\textbf{【方針】}
\text{共役な数} \sqrt{n+1}+\sqrt{n} \text{を分母分子に掛けて不定形を解消する。}
\textbf{【解答】}
\begin{aligned}
      n\!\left(\sqrt{n+1}-\sqrt{n}\right)
      &= n\cdot \frac{\sqrt{n+1}-\sqrt{n}}{1} \\[6pt]
      &= n\cdot \frac{(\sqrt{n+1}-\sqrt{n})(\sqrt{n+1}+\sqrt{n})}{(\sqrt{n+1}+\sqrt{n})} \\[6pt]
      &= n\cdot \frac{(\sqrt{n+1})^2-(\sqrt{n})^2}{\sqrt{n+1}+\sqrt{n}} \\[6pt]
      &= n\cdot \frac{(n+1)-n}{\sqrt{n+1}+\sqrt{n}} \\[6pt]
      &= n\cdot \frac{1}{\sqrt{n+1}+\sqrt{n}} \\[6pt]
      &= \frac{n}{\sqrt{n+1}+\sqrt{n}} \\[6pt]
      &= \frac{\sqrt{n}}{\sqrt{1+\frac{1}{n}}+1} \\[6pt]
      &  \underset{n\to\infty}{\longrightarrow}\  \infty
      \end{aligned}

\textbf{【方針】}
\; x=4\sin\theta \textbf{ と置く。}
\textbf{【解説】}
x = 2 \rightarrow 2\sqrt{3}\text{の時、} 2=4\sin\theta \Leftrightarrow \sin\theta=\displaystyle \frac{1}{2} \text{より } \theta=\displaystyle \frac{\pi}{6} \text{であり、} 2\sqrt{3}=4\sin\theta \Leftrightarrow \sin\theta=\displaystyle \frac{\sqrt{3}}{2} \text{より } \theta=\displaystyle \frac{\pi}{3}\text{である。}
16-x^{2}=16-16\sin^{2}\theta=16(1-\sin^{2}\theta)=16\cos^{2}\theta,\ dx = \displaystyle \frac{dx}{d\theta} d\theta =4\cos \theta d\theta
\text{なので、}
\begin{aligned}
\displaystyle \int_{2}^{2\sqrt{3}} \displaystyle \frac{dx}{\sqrt{16-x^{2}}}
=&\displaystyle \int_{\frac{\pi}{6}}^{\frac{\pi}{3}}\displaystyle \frac{4\cos\theta\,d\theta}{\sqrt{16-16\sin^{2}\theta}}\\
=&\displaystyle \int_{\frac{\pi}{6}}^{\frac{\pi}{3}}\displaystyle \frac{4\cos\theta\,d\theta}{\sqrt{16\cos^{2}\theta}}\\
=&\displaystyle \int_{\frac{\pi}{6}}^{\frac{\pi}{3}}\displaystyle \frac{4\cos\theta\,d\theta}{4|\cos\theta|}\\
=&\displaystyle \int_{\frac{\pi}{6}}^{\frac{\pi}{3}}\displaystyle \frac{4\cos\theta\,d\theta}{4\cos\theta}\\
=&\displaystyle \int_{\frac{\pi}{6}}^{\frac{\pi}{3}}1\ d\theta\\
=&\left[\theta\right]_{\frac{\pi}{6}}^{\frac{\pi}{3}}\\
=&\displaystyle \frac{\pi}{3} - \displaystyle \frac{\pi}{6}\\
=&\displaystyle \frac{\pi}{6}
\end{aligned}
\textbf{【補足】}
\text{逆正弦関数 } \arcsin x \text{を用いる。 }\arcsin x \text{の定義域は } [-1, 1] \text{、値域は } \left[-\displaystyle \frac{\pi}{2}, \displaystyle \frac{\pi}{2}\right] \text{ である。}
\text{公式 } \displaystyle \int \displaystyle \frac{dx}{\sqrt{a^{2}-x^{2}}} =\arcsin\displaystyle \frac{x}{a} + C \text{ を用いる。ここで、} a=4 \text{ である。}
\text{まず不定積分を求める。}
\begin{aligned}
\displaystyle \int \displaystyle \frac{dx}{\sqrt{16-x^{2}}}
&= \displaystyle \int \displaystyle \frac{dx}{\sqrt{4^{2}-x^{2}}}\\
&= \arcsin\displaystyle \frac{x}{4} + C
\end{aligned}
\text{したがって、定積分は、}
\begin{aligned}
\displaystyle \int_{2}^{2\sqrt{3}} \displaystyle \frac{dx}{\sqrt{16-x^{2}}}
&= \left[\arcsin\displaystyle \frac{x}{4}\right]_{2}^{2\sqrt{3}}\\
&= \arcsin\displaystyle \frac{2\sqrt{3}}{4} - \arcsin\displaystyle \frac{2}{4}\\
&= \arcsin\displaystyle \frac{\sqrt{3}}{2} - \arcsin\displaystyle \frac{1}{2}\\
&= \displaystyle \frac{\pi}{3} - \displaystyle \frac{\pi}{6}\\
&= \displaystyle \frac{\pi}{6}
\end{aligned}

\textbf{【方針】}
\text{逆数を取る。}
\textbf{【解法】}
\text{両辺の逆数を取ると、}
\begin{aligned}
    &\ \ \ \ \ \displaystyle \frac{1}{a_{n+1}} = \displaystyle \frac{a_n + 1}{a_n} \\
    &\Leftrightarrow \displaystyle \frac{1}{a_{n+1}} = 1 + \displaystyle \frac{1}{a_n}
    \end{aligned}
\text{ } b_n = \displaystyle \frac{1}{a_n} \text{ とおくと、} b_{n+1} = b_n + 1, \ b_1 = \displaystyle \frac{1}{a_1} = 1 \text{ である。}
\text{よって、} b_n = 1 + (n-1) \cdot 1 = n \text{ なので、}
\begin{aligned}
    &\ \ \ \ \ a_n = \displaystyle \frac{1}{b_n} \\
    &\Leftrightarrow a_n = \displaystyle \frac{1}{n}
    \end{aligned}

\textbf{【方針】}
\text{部分和を積分で表し、等比数列の和の公式を用いて評価する}
\textbf{【解答】}
\text{部分和を考えると、}
\begin{aligned}
      S_n &= \displaystyle \sum_{k=1}^{n}\frac{(-1)^{k-1}}{2k-1} \\[6pt]
      &= 1 - \frac{1}{3} + \frac{1}{5} - \frac{1}{7} + \cdots + \frac{(-1)^{n-1}}{2n-1}
      \end{aligned}
\text{各項 } \displaystyle \frac{(-1)^{k-1}}{2k-1} \text{ は、} \int_0^1 (-t^2)^{k-1} \, dt \text{ と表せる。}
\text{（例えば、} \displaystyle -\frac 1 3 = \int_0^1 (-t^2)^{1} \, dt \text{と表せる。}）
\text{実際、}
\begin{aligned}
      \int_0^1 (-t^2)^{k-1} \, dt &= \int_0^1 (-1)^{k-1} t^{2k-2} \, dt \\[6pt]
      &= (-1)^{k-1} \left[ \frac{t^{2k-1}}{2k-1} \right]_0^1 \\[6pt]
      &= (-1)^{k-1} \cdot \frac{1}{2k-1} \\[6pt]
      &= \frac{(-1)^{k-1}}{2k-1}
      \end{aligned}
\text{したがって、部分和は積分の和として、}
\begin{aligned}
      S_n &= \displaystyle \sum_{k=1}^{n} \int_0^1 (-t^2)^{k-1} \, dt \\[6pt]
      &= \displaystyle \sum_{k=0}^{n-1} \int_0^1 (-t^2)^k \, dt \\[6pt]
      &= \int_0^1 \displaystyle \sum_{k=0}^{n-1} (-t^2)^k \, dt
      \end{aligned}
\text{等比数列の和の公式より、}
\begin{aligned}
      \displaystyle \sum_{k=0}^{n-1} (-t^2)^k &= \frac{1-(-t^2)^n}{1-(-t^2)} \\[6pt]
      &= \frac{1-(-t^2)^n}{1+t^2}
      \end{aligned}
\text{よって、}
\begin{aligned}
      S_n &= \int_0^1 \frac{1-(-t^2)^n}{1+t^2} \, dt \\[6pt]
      &= \int_0^1 \frac{1}{1+t^2} \, dt - \int_0^1 \frac{(-t^2)^n}{1+t^2} \, dt
      \end{aligned}
\textcolor{blue}{右辺の第1項は、}
\begin{aligned}
      \int_0^1 \frac{1}{1+t^2} \, dt &= \int_0^{\frac{\pi}{4}} \frac{1}{1+\tan^2 x}\frac{1}{\cos^2 x}dx \\[6pt]
      &= \int_0^{\frac{\pi}{4}} 1 dx  \\[6pt]
      &= \frac{\pi}{4}
      \end{aligned}
\textcolor{blue}{右辺の第2項は、} n \to \infty \text{ で } \textcolor{red}{0}\ \textcolor{red}{に収束する}\text{(詳しくは補足参照)}
\text{したがって、}
\boxed{\displaystyle \sum_{k=1}^{\infty} \frac{(-1)^{k-1}}{2k-1} = \frac{\pi}{4}}
\textbf{【補足】第2項の収束性を示す：}
\text{} (-1)^n \text{ を外に出すと、}
\frac{(-t^2)^n}{1+t^2} = (-1)^n \cdot \frac{(t^2)^n}{1+t^2}
\text{0-1区間で } 0 < \displaystyle \frac{(t^2)^n}{1+t^2} < (t^2)^n \text{ より、}
\begin{aligned}
      \left| \int_0^1 \frac{(-t^2)^n}{1+t^2} \, dt \right| &= \left| \int_0^1 (-1)^n \cdot \frac{(t^2)^n}{1+t^2} \, dt \right| \\[6pt]
      &= \left| (-1)^n \right| \cdot \left| \int_0^1 \frac{(t^2)^n}{1+t^2} \, dt \right| \\[6pt]
      &=  \int_0^1 \frac{(t^2)^n}{1+t^2} \, dt  \\[6pt]
      &< \int_0^1 (t^2)^n \, dt \\[6pt]
      &= \left[ \frac{t^{2n+1}} {2n+1} \right]_0^1 \\[6pt]
      &= \frac{1}{2n+1} \to 0 \quad (n \to \infty)
      \end{aligned}
\text{よって、} \displaystyle a_n = \int_0^1 \frac{(-t^2)^n}{1+t^2} \, dt \text{ と見做すと、} \lim_{n\to\infty} |a_n| = 0
\text{したがって第2項} \displaystyle \lim_{n\to\infty} a_n =\lim_{n\to\infty} \int_0^1 \frac{(-t^2)^n}{1+t^2} \, dt  = 0
\text{（注：一般に } \lim_{n\to\infty} |a_n| = 0 \Leftrightarrow \lim_{n\to\infty} a_n = 0 \text{ が成り立つ）}
\textbf{【補足】}
\text{この級数をライプニッツ級数という。}

\textbf{【方針】}
\text{ } x \text{ について整理し、たすきがけを用いて因数分解する。}
\textbf{【途中式変形】}
\begin{aligned}
&\ \ 2x^2 + 5xy + 2y^2 - 5x - y - 3 \\
&= 2x^2 + x(5y - 5) + (2y^2 - y - 3) \\
&= 2x^2 + x(5y - 5) + (y+1)(2y-3) \\
&= (2x + y + 1)(x + 2y - 3)
\end{aligned}

\textcolor{brown}{\large{【力学】}}
\text{• 力学においては、} mx^{\prime\prime}(t) + kx(t) = 0 \text{ の形でよく登場する。これはばね-質量系の単振動の運動方程式。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• 電磁気学においては、} LQ^{\prime\prime}(t) + \displaystyle \frac{Q(t)}{C} = 0 \text{ の形でよく登場する。これはLC回路の放電におけるキルヒホッフの法則であり、電気振動をする。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{単振動（ばね-質量系の自由振動）:} \ mx^{\prime\prime}(t) + kx(t) = 0
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } \omega_0 \leftrightarrow \sqrt{\displaystyle \frac{k}{m}} \text{（固有角周波数）}
\text{• } A_0 \leftrightarrow x_0 \text{（初期位置）}
\text{• } v_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{LC振動回路（コンデンサとコイルの自由振動）:} \ LQ^{\prime\prime}(t) + \displaystyle \frac{Q(t)}{C} = 0
\text{• } f(t) \leftrightarrow Q(t) \text{（コンデンサに蓄えられた電荷）}
\text{• } f^{\prime}(t) \leftrightarrow I(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow I' \text{（電流変化率）}
\text{• } \omega_0 \leftrightarrow \displaystyle \frac{1}{\sqrt{LC}} \text{（固有角周波数）}
\text{• } A_0 \leftrightarrow Q_0 \text{（コンデンサに蓄えられた初期電荷）}
\text{• } v_0 \leftrightarrow I_0 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
\textcolor{green}{1.\ } \textcolor{green}{\displaystyle \frac{1}{2}f^{\prime}(t)^2 + \displaystyle \frac{\omega_0^2}{2}f(t)^2} \textcolor{green}{は時間によらず一定}
f^{\prime\prime}(t) = -\omega_0^2 f(t) \text{の両辺に}f^{\prime}(t)\text{ を掛ける。(こうやるとうまくいく)}
\Rightarrow \ f^{\prime\prime}(t)f^{\prime}(t) = -\omega_0^2 f(t)f^{\prime}(t)
\text{積の微分より}
\Leftrightarrow \ \left(\displaystyle \frac{1}{2}f^{\prime}(t)^2\right)' = \left(-\displaystyle \frac{\omega_0^2}{2}f(t)^2\right)'
\text{移項する：}
\Leftrightarrow \ \left(\displaystyle \frac{1}{2}f^{\prime}(t)^2\right)' - \left(-\displaystyle \frac{\omega_0^2}{2}f(t)^2\right)' = 0
\Leftrightarrow \ \left(\displaystyle \frac{1}{2}f^{\prime}(t)^2 + \displaystyle \frac{\omega_0^2}{2}f(t)^2\right)' = 0
\text{時間微分が0なので、} \displaystyle  \frac{1}{2}f^{\prime}(t)^2 + \displaystyle \frac{\omega_0^2}{2}f(t)^2 \text{は時間によらない保存量である。}
\textcolor{green}{2.\ } \textcolor{green}{任意の時刻} \textcolor{green}{t} \textcolor{green}{において、} \textcolor{green}{\left(\displaystyle \frac{f^{\prime}(t)}{\omega_0}\right)^2 + f(t)^2 = \displaystyle \frac{v_0^2+\omega_0^2 A_0^2}{\omega_0^2}} \textcolor{green}{　: 一定}
\text{初期条件} f(0)=A_0,\ f^{\prime}(0)=v_0 \text{より、上段で求めた時間によらない保存量} \displaystyle \frac{1}{2}f^{\prime}(t)^2 + \displaystyle \frac{\omega_0^2}{2}f(t)^2 \text{の値を}C\text{と置く。ここで初期条件を用いると、}
C = \displaystyle \frac12\cdot v_0^2 + \displaystyle \frac{\omega_0^2}{2}\cdot A_0^2
\text{よって、任意の時刻} t \text{で、}
\displaystyle \frac{1}{2}f^{\prime}(t)^2 + \displaystyle \frac{\omega_0^2}{2}f(t)^2 = \displaystyle \frac{v_0^2+\omega_0^2 A_0^2}{2} \  \cdots (1)
\text{が成り立つ。(1)の両辺を}\displaystyle \frac{\omega_0^2}{2}\text{で割って}
\Leftrightarrow \left(\displaystyle \frac{f^{\prime}(t)}{\omega_0}\right)^2 + f(t)^2 = \displaystyle \frac{v_0^2+\omega_0^2 A_0^2}{\omega_0^2} \  \cdots (2)
\textcolor{green}{3.\ } \textcolor{green}{\displaystyle \frac{f^{\prime}(t)}{\omega_0} = \frac{\sqrt{v_0^2+\omega_0^2 A_0^2}}{\omega_0}\cos\theta(t),\ \  f(t) = \frac{\sqrt{v_0^2+\omega_0^2 A_0^2}}{\omega_0}\sin\theta(t)} \textcolor{green}{を満たす関数} \textcolor{green}{\theta(t)}\textcolor{green}{を取る事ができる。}
(2) \text{より} \left(\displaystyle \frac{f^{\prime}(t)}{\omega_0},\, f(t)\right) \text{は常に半径}\displaystyle \frac{\sqrt{v_0^2+\omega_0^2 A_0^2}}{\omega_0}\text{の円上。}
\text{よって、連続な角度} \theta(t) \text{を用いて下記のように表すことができる。}
\begin{cases}
