\textbf{【方針】}
\text{対称性から } a \le b \le c \le d \text{ と仮定し、範囲を絞り込む。}
\textbf{【解法】}
\text{ }a \le b \le c \le d \text{ より、}
\begin{aligned}
    abcd &= a + b + c + d \\
    &\le d + d + d + d = 4d
    \end{aligned}
abcd \le 4d \Leftrightarrow abc \le 4\cdots(1) \text{ である。}
\text{また、}a=2\text{とすると、}b,c\text{がaよりも大きい事から、}(1)\text{を満たさないので、}a=1\text{となる。}
\text{ }a = 1 \text{ より、}b \le c \text{ かつ } bc \le 4 \text{ より、候補は限られる。}
\textcolor{blue}{a = 1}\textcolor{blue}{ の場合}
\text{ }bc \le 4 \text{ より、} (b,c) = (1,1), (1,2), (1,3), (1,4), (2,2) \text{ が候補。}
\textcolor{blue}{(a,b,c) = (1,1,1)}\textcolor{blue}{ の場合}
\text{方程式に代入すると、}
\begin{aligned}
    1 \cdot 1 \cdot 1 \cdot d &= 1 + 1 + 1 + d \\
    \Leftrightarrow d &= 3 + d
    \end{aligned}
\textcolor{red}{これは成立しない。}
\textcolor{blue}{(a,b,c) = (1,1,2)}\textcolor{blue}{ の場合}
\text{方程式に代入すると、}
\begin{aligned}
    1 \cdot 1 \cdot 2 \cdot d &= 1 + 1 + 2 + d \\
    \Leftrightarrow 2d &= 4 + d \\
    \Leftrightarrow d &= 4
    \end{aligned}
\text{よって、} \textcolor{green}{(a,b,c,d) = (1,1,2,4)} \text{ は解。}
\textcolor{blue}{(a,b,c) = (1,1,3)}\textcolor{blue}{ の場合}
\text{方程式に代入すると、}
\begin{aligned}
    1 \cdot 1 \cdot 3 \cdot d &= 1 + 1 + 3 + d \\
    \Leftrightarrow 3d &= 5 + d \\
    \Leftrightarrow d &= \frac{5}{2}
    \end{aligned}
\text{ } \textcolor{red}{d は整数解ではない。}
\textcolor{blue}{(a,b,c) = (1,1,4)}\textcolor{blue}{ の場合}
\text{方程式に代入すると、}
\begin{aligned}
    1 \cdot 1 \cdot 4 \cdot d &= 1 + 1 + 4 + d \\
    \Leftrightarrow 4d &= 6 + d \\
    \Leftrightarrow d &= 2
    \end{aligned}
\text{しかし } c \le d \text{ より } 4 \le 2 \text{ となり} \textcolor{red}{そもそもの場合分けの条件を満たさない。}
\textcolor{blue}{(a,b,c) = (1,2,2)}\textcolor{blue}{ の場合}
\text{方程式に代入すると、}
\begin{aligned}
    1 \cdot 2 \cdot 2 \cdot d &= 1 + 2 + 2 + d \\
    \Leftrightarrow 4d &= 5 + d \\
    \Leftrightarrow d &= \frac{5}{3}
    \end{aligned}
\text{ } \textcolor{red}{d は整数解ではない。}
\text{よって、} a \le b \le c \le d \text{ の条件下では } (a,b,c,d) = (1,1,2,4) \text{ のみが解。}
\text{問題は順序の制約がないため、} 1, 1, 2, 4 \text{ の順列すべてが解となる。すなわち、}
\begin{aligned}
    (a,b,c,d) = &(1,1,2,4), (1,1,4,2), (1,2,1,4), (1,2,4,1),\\
    &(1,4,1,2), (1,4,2,1), (2,1,1,4), (2,1,4,1),\\
    &(2,4,1,1), (4,1,1,2), (4,1,2,1), (4,2,1,1)
    \end{aligned}

\textbf{【方針】}
\text{対数の性質 } \log a - \log b = \log \displaystyle\frac{a}{b} \text{ を用いて差を商に直し、その後1次分数関数の方程式に帰着させる。真数条件に注意する。}
\textbf{【真数条件】}
\begin{aligned}
x + 1 > 0 \quad &\Leftrightarrow \quad x > -1 \\
x - 1 > 0 \quad &\Leftrightarrow \quad x > 1
\end{aligned}
\text{よって、} x > 1 \text{ が必要。}
\textbf{【解説】}
\text{対数の性質より、}
\begin{aligned}
\log_3(x+1) - \log_3(x-1) &= \log_3\displaystyle\frac{x+1}{x-1}
\end{aligned}
\text{したがって、元の方程式は、}
\begin{aligned}
&\ \ \ \ \ \log_3\displaystyle\frac{x+1}{x-1} = 1 \\
&\Leftrightarrow \displaystyle\frac{x+1}{x-1} = 3^1 \\
&\Leftrightarrow \displaystyle\frac{x+1}{x-1} = 3 \\
&\Leftrightarrow x + 1 = 3(x - 1) \\
&\Leftrightarrow x + 1 = 3x - 3 \\
&\Leftrightarrow 1 + 3 = 3x - x \\
&\Leftrightarrow 4 = 2x \\
&\Leftrightarrow x = 2
\end{aligned}
\text{真数条件 } x > 1 \text{ を満たすので、} x = 2 \text{ が解である。}

\textbf{【解説】}
\text{分母} = (x+1)^2+4\text{より、置換} x+1=2\tan\theta\text{を行う。}
\begin{aligned} dx &= \displaystyle \frac{dx}{d\theta} d\theta = 2\displaystyle \frac{1}{\cos ^2 \theta} d \theta \\
    &= 2\left( 1 + \tan ^2 \theta \right) d \theta
    \end{aligned}
\text{より、}x=-1\rightarrow 1 \text{の時、}\tan \theta = 0 \rightarrow 1 \Leftrightarrow \theta= 0 \rightarrow \displaystyle \frac \pi 4 \text{よって、}
\begin{aligned}
&\displaystyle \int_{-1}^{1}\displaystyle \frac{1}{(x+1)^2+4}\,dx\\
&=\displaystyle \int_{0}^{\pi/4}\displaystyle \frac{1}{(2\tan\theta)^2+4}\cdot 2(1+\tan^2\theta)\,d\theta\\
&=\displaystyle \int_{0}^{\pi/4}\displaystyle \frac{2(1+\tan^2\theta)}{4(1+\tan^2\theta)}\,d\theta\\
&=\displaystyle \int_{0}^{\pi/4}\displaystyle \frac{1}{2}\,d\theta\\
&=\displaystyle \frac{1}{2}\theta\Big|_{0}^{\pi/4}\\
&=\displaystyle \frac{1}{2}\cdot\displaystyle \frac{\pi}{4}\\
&=\displaystyle \frac{\pi}{8}.
\end{aligned}
\textbf{【補足】}
\tan \text{の逆関数} \arctan \text{を使うと、}
\begin{aligned}
&\theta=\arctan\displaystyle \frac{x+1}{2} \\ 
&\displaystyle \int\displaystyle \frac{1}{(x+1)^2+4}\,dx=\displaystyle \frac{1}{2}\arctan\displaystyle \frac{x+1}{2}+C.
\end{aligned}

\textbf{【方針】}
\text{置換 } u = 3x \text{ を用いて、基本積分 } \displaystyle \int \frac{1}{\cos^2 u} \, du = \tan u + C \text{ に帰着させる。}
\textbf{【解説】}
\text{ } u = 3x \text{ とおくと、} du = 3 \, dx \text{ であり、} \displaystyle dx = \frac{1}{3} \, du \text{ である。}
\begin{aligned}
x = -\frac{\pi}{12} &\Rightarrow u = 3 \cdot \left(-\frac{\pi}{12}\right) = -\frac{\pi}{4}\\[5pt]
x = \frac{\pi}{12} &\Rightarrow u = 3 \cdot \frac{\pi}{12} = \frac{\pi}{4}
\end{aligned}
\begin{aligned}
&\ \ \ \ \ \int_{-\frac{\pi}{12}}^{\frac{\pi}{12}} \frac{dx}{\cos^2(3x)}\\[5pt]
&= \int_{u=-\frac{\pi}{4}}^{u=\frac{\pi}{4}} \frac{1}{\cos^2 u} \cdot \frac{1}{3} \, du\\[5pt]
&= \frac{1}{3} \int_{-\frac{\pi}{4}}^{\frac{\pi}{4}} \frac{1}{\cos^2 u} \, du\\[5pt]
&= \frac{1}{3} \left[\tan u\right]_{-\frac{\pi}{4}}^{\frac{\pi}{4}}\\[5pt]
&= \frac{1}{3} \left(\tan\frac{\pi}{4} - \tan\left(-\frac{\pi}{4}\right)\right)\\[5pt]
&= \frac{1}{3} \left(1 - (-1)\right)\\[5pt]
&= \frac{1}{3} \cdot 2\\[5pt]
&= \frac{2}{3}
\end{aligned}

