\textbf{【方針】}
\sin x = t \text{ とおいて、2次方程式に帰着させる。ただし、} -1 \leq t \leq 1 \text{ の範囲に注意する。}
\textbf{【解説】}
\sin x = t \text{ とおくと、元の方程式は、}
\begin{aligned}
&\ \ \ \ \ 2t^2 - t - 1 = 0 \\
&\Leftrightarrow (2t + 1)(t - 1) = 0 \\
&\Leftrightarrow t = -\displaystyle\frac{1}{2} \text{ または } t = 1
\end{aligned}
\text{ここで、} -1 \leq t \leq 1 \text{ なので、両方とも有効な解である。}
\textbf{【場合分け】}
\text{（1）} \sin x = 1 \text{ の場合}
\begin{aligned}
&\ \ \ \ \ \sin x = 1 \\
&\Leftrightarrow x = \displaystyle\frac{\pi}{2} + 2n\pi \quad (n \text{ は整数})
\end{aligned}
0 \leq x < 2\pi \text{ より、} \textcolor{green}{x = \displaystyle\frac{\pi}{2}}
\text{（2）} \sin x = -\displaystyle\frac{1}{2} \text{ の場合}
\begin{aligned}
&\ \ \ \ \ \sin x = -\displaystyle\frac{1}{2} \\[7pt]
&\Leftrightarrow \begin{cases}
x = \displaystyle\frac{7\pi}{6} + 2n\pi \quad (n \text{ は整数}) \\[8pt]
x = \displaystyle\frac{11\pi}{6} + 2n\pi \quad (n \text{ は整数})
\end{cases}
\end{aligned}
0 \leq x < 2\pi \text{ より、} \textcolor{green}{x = \displaystyle\frac{7\pi}{6}, \displaystyle\frac{11\pi}{6}}
\text{（1）と（2）を合わせて、}
x = \displaystyle\frac{\pi}{2}, \displaystyle\frac{7\pi}{6}, \displaystyle\frac{11\pi}{6}

\color{black}\textbf{【解答（定理を使う）】}
\color{black}g(t)=\sqrt{1+\cos^{3}t}\text{ とおく。}
\color{black}\text{ }g\text{ は }t=0\text{ の近くで連続である。}
\color{black}\text{積分の平均値の定理より、}
\color{black}\int_{0}^{x}g(t)\,dt = g(\xi)\,x\text{ となる実数 }\xi\text{ が }0\text{ と }x\text{ の間に存在する。}
\color{black}\Rightarrow\ \frac{1}{x}\int_{0}^{x}\sqrt{1+\cos^{3}t}\,dt=\sqrt{1+\cos^{3}\xi}
\color{black}x\to0\text{ のとき }\xi\text{ は }0\text{ と }x\text{ の間にあるので、}\xi\to0\text{。}
\color{black}\cos\text{ は連続だから }\cos\xi\to1
\color{black}\Rightarrow 1+\cos^{3}\xi\to2\Rightarrow \sqrt{1+\cos^{3}\xi}\to\sqrt2
\color{black}\boxed{\displaystyle \lim_{x\to0}\frac{1}{x}\int_{0}^{x}\sqrt{1+\cos^{3}t}\,dt=\sqrt2}
\color{black}\textbf{【補足：積分の平均値の定理（証明）】}
\color{black}\text{ }x>0\text{ の場合で示す。（}x<0\text{ も同様に成り立つ。）}
\color{black}\text{関数 }g\text{ は }[0,x]\text{ で連続だから、最大値と最小値をとる。}
\color{black}\text{最小値を }m,\ \text{最大値を }M\text{ とおく。すると }m\le g(t)\le M\ (0\le t\le x).
\color{black}\text{両辺を }0\text{ から }x\text{ まで積分すると}
\color{black}\int_{0}^{x}m\,dt\le \int_{0}^{x}g(t)\,dt\le \int_{0}^{x}M\,dt
\color{black}\Rightarrow mx\le \int_{0}^{x}g(t)\,dt\le Mx
\color{black}\Rightarrow m\le \frac{1}{x}\int_{0}^{x}g(t)\,dt\le M
\color{black}\text{ここで }g\text{ は連続なので、値は }m\text{ から }M\text{ まで連続的に動く。}
\color{black}\text{したがって }\frac{1}{x}\int_{0}^{x}g(t)\,dt\text{ と等しくなる }g(\xi)\text{ が存在する。}
\color{black}\text{すなわち }\int_{0}^{x}g(t)\,dt=g(\xi)x\text{ となる実数 }\xi\text{ が }0\text{ と }x\text{ の間に存在する。}

\textbf{【方針】}
\text{和積の公式を用いて、} \cos A + \cos B \text{ を積の形に変形する。}
\textbf{【ポイント】}
\begin{aligned}
\cos A + \cos B &= 2\cos\displaystyle\frac{A+B}{2}\cos\displaystyle\frac{A-B}{2}
\end{aligned}
\textbf{【解説】}
\text{和積の公式より、}
\begin{aligned}
\cos 2x + \cos 3x &= 2\cos\displaystyle\frac{2x+3x}{2}\cos\displaystyle\frac{2x-3x}{2} \\
&= 2\cos\displaystyle\frac{5x}{2}\cos\left(-\displaystyle\frac{x}{2}\right) \\
&= 2\cos\displaystyle\frac{5x}{2}\cos\displaystyle\frac{x}{2}
\end{aligned}
\text{したがって、元の方程式は、}
\begin{aligned}
&\ \ \ \ \ 2\cos\displaystyle\frac{5x}{2}\cos\displaystyle\frac{x}{2} = 0 \\
&\Leftrightarrow \cos\displaystyle\frac{5x}{2} = 0 \text{ または } \cos\displaystyle\frac{x}{2} = 0
\end{aligned}
\textbf{【場合分け】}
\text{（1）} \cos\displaystyle\frac{5x}{2} = 0 \text{ の場合}
\begin{aligned}
&\ \ \ \ \ \cos\displaystyle\frac{5x}{2} = 0 \\
&\Leftrightarrow \displaystyle\frac{5x}{2} = \displaystyle\frac{\pi}{2} + n\pi \quad (n \text{ は整数}) \\
&\Leftrightarrow 5x = \pi + 2n\pi \\
&\Leftrightarrow x = \displaystyle\frac{\pi}{5} + \displaystyle\frac{2n\pi}{5}
\end{aligned}
0 \leq x < 2\pi \text{ より、} n = 0, 1, 2, 3, 4 \text{ のとき、}
\textcolor{green}{x = \displaystyle\frac{\pi}{5}, \displaystyle\frac{3\pi}{5}, \pi, \displaystyle\frac{7\pi}{5}, \displaystyle\frac{9\pi}{5}}
\text{（2）} \cos\displaystyle\frac{x}{2} = 0 \text{ の場合}
\begin{aligned}
&\ \ \ \ \ \cos\displaystyle\frac{x}{2} = 0 \\
&\Leftrightarrow \displaystyle\frac{x}{2} = \displaystyle\frac{\pi}{2} + n\pi \quad (n \text{ は整数}) \\
&\Leftrightarrow x = \pi + 2n\pi
\end{aligned}
0 \leq x < 2\pi \text{ より、} \textcolor{green}{x = \pi}
\text{（1）と（2）を合わせて、}
x = \displaystyle\frac{\pi}{5}, \displaystyle\frac{3\pi}{5}, \pi, \displaystyle\frac{7\pi}{5}, \displaystyle\frac{9\pi}{5}
\textbf{【正五角形との関連】}
\text{正五角形の中心角は } \displaystyle\frac{2\pi}{5} \text{ である。}
\text{解 } x = \displaystyle\frac{\pi}{5}, \displaystyle\frac{3\pi}{5}, \pi, \displaystyle\frac{7\pi}{5}, \displaystyle\frac{9\pi}{5} \text{ は、}
\text{正五角形の中心角 } \displaystyle\frac{2\pi}{5} \text{ の倍数（またはその半分）に対応している。}
\text{特に、} \cos\displaystyle\frac{5x}{2} = 0 \text{ の解は、正五角形の頂点の位置に関連する角度を表している。}
\text{また、} \cos 2x + \cos 3x = 0 \text{ は、正五角形の対称性を反映した方程式である。}

\textcolor{brown}{\large{【力学】}}
\text{• 初期位置 }x_0=f_0\text{、初期速度 }v_0\text{、重力加速度 }g\text{ の自由落下運動の位置についての微分方程式。}
\text{• 力学においては、} x^{\prime\prime}(t) = g \text{の形でよく登場する。これは重力を受ける質点の位置変化を表す。}
\text{• 解 }f(t) = \displaystyle \frac{1}{2}g t^2 + v_0 t + f_0\text{ は、等加速度運動の位置公式そのものである。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{自由落下運動の位置変化}
x^{\prime\prime}(t) = g
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } g \leftrightarrow g \text{（重力加速度）}
\text{• } f_0 \leftrightarrow x_0 \text{（初期位置）}
\text{• } v_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【解法】}}
f^{\prime\prime}(t) = g
\text{両辺を }0\text{ から }t\text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime\prime}(s)\,ds = \int_0^t g\,ds\\[5pt]
&\Leftrightarrow [f^{\prime}(s)]_{0}^{t} = [gs]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f^{\prime}(t) - f^{\prime}(0) = g t - 0\\[5pt]
&\Leftrightarrow \ f^{\prime}(t) = g t + f^{\prime}(0)
\end{aligned}
\text{初期条件より} f^{\prime}(0) = v_0 \text{なので、}
\Leftrightarrow \ f^{\prime}(t) = g t + v_0
\text{さらに両辺を }0\text{ から }t\text{ まで定積分する：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime}(s)\,ds = \int_0^t (g s + v_0)\,ds\\[5pt]
&\Leftrightarrow [f(s)]_{0}^{t} = \left[\displaystyle \frac{1}{2}g s^2 + v_0 s\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f(t) - f(0) = \displaystyle \frac{1}{2}g t^2 + v_0 t - 0\\[5pt]
&\Leftrightarrow \ f(t) = \displaystyle \frac{1}{2}g t^2 + v_0 t + f(0)
\end{aligned}
\text{初期条件より} f(0) = f_0 \text{なので、}
\Leftrightarrow \ f(t) = \displaystyle \frac{1}{2}g t^2 + v_0 t + f_0

\textbf{【方針】}
f(x) = x^4 - 4x^3 + 5x^2 - 4x + 1\text{とおいて、まずは、因数定理を用い、候補（±1）を代入して、1次式の因数を持たないことを認識したら、その後、2次式×2次式の形で係数比較を行うのが自然。}
\textbf{【途中式変形】}
\text{因数定理の候補を代入すると、}
\begin{aligned}
 f(1) &= 1 - 4 + 5 - 4 + 1 = -1 \neq 0 \\
 f(-1) &= 1 + 4 + 5 + 4 + 1 = 15 \neq 0
 \end{aligned}
\text{よって、1次式の因数を持たない。よって2次式×2次式の因数分解を探す。}
\text{整数係数で } f(x) = (x^2 + ax + b)(x^2 + cx + d) \text{ とおく。}
\textcolor{red}{実は計算すると、下記のように計算できる。}
\textcolor{red}{a = -1,\ b = 1,\ c = -3,\ d = 1}
\textcolor{red}{以下ではこの証明を行う。}
\textbf{【証明】}
\text{ここで } x^4 - 4x^3 + 5x^2 - 4x + 1 \text{ の定数項が } 1 \text{ であることから、 } (b, d) = (-1, -1), (1, 1) \text{ の場合に分けて解を探す。}
\textcolor{blue}{1. } \textcolor{blue}{(b, d) = (-1, -1)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax - 1)(x^2 + cx - 1) \text{ とおくと、}
\begin{aligned}
 x^4 - 4x^3 + 5x^2 - 4x + 1 &= (x^2 + ax - 1)(x^2 + cx - 1) \\
 &= x^4 + (a+c)x^3 + (ac - 2)x^2 + (-a - c)x + 1
 \end{aligned}
\text{係数比較より、}
\begin{aligned}
 &\text{3次: } a + c = -4\ \cdots (1) \\[2pt]
 &\text{2次: } ac - 2 = 5\ \ \cdots (2) \\[2pt]
 &\text{1次: } -a - c = -4\ \ \cdots (3)
 \end{aligned}
\text{(3) より } -a - c = -4 \text{、すなわち } a + c = 4
\textcolor{red}{しかし (1) より } a + c = -4 \text{ であるから、これは矛盾する。}
\textcolor{red}{したがってこの場合は解なし。}
\textcolor{blue}{2. } \textcolor{blue}{(b, d) = (1, 1)} \textcolor{blue}{の場合}
\text{ } f(x) = (x^2 + ax + 1)(x^2 + cx + 1) \text{ とおくと、}
\begin{aligned}
 x^4 - 4x^3 + 5x^2 - 4x + 1 &= (x^2 + ax + 1)(x^2 + cx + 1) \\
 &= x^4 + (a+c)x^3 + (ac + 2)x^2 + (a + c)x + 1
 \end{aligned}
\text{係数比較より、}
\begin{aligned}
 &\text{3次: } a + c = -4\ \cdots (1) \\[2pt]
 &\text{2次: } ac + 2 = 5\ \ \cdots (2) \\[2pt]
 &\text{1次: } a + c = -4\ \ \cdots (3)
 \end{aligned}
\text{(2),(1) より } ac = 3, a + c = -4 \text{ であるから、}
\text{ } (a = -1, c = -3) \text{ または } (a = -3, c = -1) \text{ を得る。}
\textcolor{green}{最終的に2つの解 } (a, b, c, d) = (-1, 1, -3, 1) \text{ と } (a, b, c, d) = (-3, 1, -1, 1) \text{ が見つかったが、どちらを選んでも因数分解の結果は同じになる。}
\textcolor{green}{したがって、}
\textcolor{green}{\begin{aligned}
 x^4 - 4x^3 + 5x^2 - 4x + 1 &= (x^2 - x + 1)(x^2 - 3x + 1)
 \end{aligned}}

\textbf{【解法】}
\text{部分積分を用いて、一般のnについての漸化式及び計算結果を導出する。 }
\textcolor{green}{一般に下記が成立する事を示す。}
\textcolor{green}{
    \begin{aligned}
    \begin{cases}
      & nが0の時: \displaystyle I_0=\frac{\pi}{2} \\
      & nが偶数の時: I_n =\displaystyle \frac{(n-1) \cdot (n-3) \cdot \cdots \cdot 3 \cdot 1}{n \cdot (n-2) \cdot \cdots \cdot 4 \cdot 2}\cdot\frac{\pi}{2}\\
      & nが奇数の時: I_n = \displaystyle \frac{(n-1) \cdot (n-3) \cdot \cdots \cdot 4 \cdot 2}{n \cdot (n-2) \cdot \cdots \cdot 3 \cdot 1} \quad 
      \end{cases}
      \end{aligned}
    }
\begin{aligned}
I_n&=\displaystyle \int_0^{\frac{\pi}{2}}\sin^{n-1}x\cdot\sin x\,dx \\
& = \displaystyle \int_0^{\frac{\pi}{2}}\sin^{n-1}x\cdot(-\cos x)'\,dx \\
& = \displaystyle \int_0^{\frac{\pi}{2}}- \sin^{n-1}x\cdot(\cos x)'\,dx \\
&= \left[-\sin^{n-1}x\cos x\right]_0^{\frac{\pi}{2}} + (n-1)\displaystyle \int_0^{\frac{\pi}{2}}\sin^{n-2}x\cos^2 x\,dx \\
&= (n-1)\displaystyle \int_0^{\frac{\pi}{2}}\sin^{n-2}x\cos^2 x\,dx \\
&= (n-1)\displaystyle \int_0^{\frac{\pi}{2}}\sin^{n-2}x(1-\sin^2 x)\,dx \\
&= (n-1)\displaystyle \int_0^{\frac{\pi}{2}}\sin^{n-2}x\,dx - (n-1)\displaystyle \int_0^{\frac{\pi}{2}}\sin^n x\,dx \\
&= (n-1)\left(I_{n-2}-I_n\right)
\end{aligned}
\text{これより漸化式 }\displaystyle I_n=\frac{n-1}{n}I_{n-2}\text{ を得る。}
\displaystyle I_0,\ I_1\text{ は簡単に計算できる。}
\begin{aligned}
\displaystyle I_0&=\int_0^{\frac{\pi}{2}}1\,dx=\frac{\pi}{2} \\
\displaystyle I_1&=\int_0^{\frac{\pi}{2}}\sin x\,dx=1
\end{aligned}
\text{漸化式を繰り返すと偶奇で場合分けでき、下記を得る：}
\begin{aligned}
    \textcolor{green}{
\displaystyle I_n =
\begin{cases}
\displaystyle \frac{(n-1) \cdot (n-3) \cdot \cdots \cdot 3 \cdot 1}{n \cdot (n-2) \cdot \cdots \cdot 4 \cdot 2}\cdot\frac{\pi}{2} & (n\ \text{:偶数})\\[6pt]
\displaystyle \frac{(n-1) \cdot (n-3) \cdot \cdots \cdot 4 \cdot 2}{n \cdot (n-2) \cdot \cdots \cdot 3 \cdot 1} & (n\ \text{:奇数})
\end{cases}}
