\textcolor{blue}{【応用1：アステロイドの面積】}
\text{アステロイド }x=\cos^3 t,\ y=\sin^3 t\text{ （}0\le t\le2\pi\text{）は4つの対称ローブを持つ。第1象限は }0< t<\displaystyle \frac{\pi}{2}\text{ に対応する。}
\text{第1象限の面積を }x\text{-方向で表すと } \displaystyle \int_{x=0}^{1} y\,dx \text{ となる。パラメータ変換 }x=x(t)\text{ を使うと、上下限が }\displaystyle t=\frac{\pi}{2}\to0\text{ になる点に注意する。}
\begin{aligned}
&\ \ \ \ \ \text{第1象限の面積}\\
&= \displaystyle \int_{x=0}^{1} Y(x)\,dx \\
&= \displaystyle \int_{t=\frac{\pi}{2}}^{0} y(t)\,x^{\prime}(t)\,dt \\
&= -\displaystyle \int_{0}^{\frac{\pi}{2}} y(t)\,x^{\prime}(t)\,dt
\end{aligned}
\text{ここで }x^{\prime}(t)=-3\cos^2 t\sin t,\ y(t)=\sin^3 t\text{ なので、第1象限の寄与は}
\begin{aligned}
&\ \ \ \ \ \text{第1象限の面積} \\
&= -\displaystyle \int_0^{\frac{\pi}{2}} \sin^3 t \cdot (-3\cos^2 t\sin t)\,dt \\
&= \displaystyle \int_0^{\frac{\pi}{2}} 3\sin^4 t\cos^2 t\,dt \\
&= 3\displaystyle \int_0^{\frac{\pi}{2}}\sin^4 t(1-\sin^2 t)\,dt \\
&= 3\left(I_4 - I_6\right)
\end{aligned}
\text{全体は4対称なので4倍して }
\begin{aligned}
&\ \ \ \ \ \text{囲まれた面積} \\
&= 12\left(I_4 - I_6\right) \\
  &= 12\left(\frac{3 \cdot 1}{4 \cdot 2} \cdot \frac{\pi}{2} - \frac{5 \cdot 3 \cdot 1}{6 \cdot 4 \cdot 2} \cdot \frac{\pi}{2}\right) \\
  &= 12\left(\frac{3\pi}{16}-\frac{5\pi}{32}\right) \\
  &= 12\cdot\frac{\pi}{32} \\
  &= \textcolor{green}{ \frac{3\pi}{8} }
\end{aligned}
\textcolor{blue}{【応用2：アステロイドのX軸回転体積】}
V_x=\pi\displaystyle \int_{x=-1}^{1}Y(x)^2\,dx\text{。左右対称なので}
V_x=2\pi\displaystyle \int_0^1 Y(x)^2\,dx\text{ と書ける。 }
\text{ここで}x:0\to1\text{ と変化するので、}x=t\text{ と置換すると、}t:\frac{\pi}{2}\to0\text{ と変化する。}
y^2=\sin^6 t,\ x'=-3\cos^2 t\sin t\text{ だから、}
\begin{aligned}
    V_x&=2\pi\displaystyle \int_0^1 Y(x)^2\,dx\\
    &=2\pi\displaystyle \int_{t=\frac{\pi}{2}}^{0} y(t)^2\,x^{\prime}(t)\,dt\\
    &=-6\pi\displaystyle \int_{t=\frac{\pi}{2}}^{0} \sin^7 t\cos^2 t\,dt\\
    &=6\pi\displaystyle \int_{t=0}^{\frac{\pi}{2}} \sin^7 t(1-\sin^2 t)\,dt\\
    &= 6\pi\displaystyle \int_0^{\frac{\pi}{2}}(\sin^7 t-\sin^9 t)\,dt \\
    &= 6\pi\bigl(I_7 - I_9\bigr) \\
    &= 6\pi\left(\frac{6 \cdot 4 \cdot 2}{7 \cdot 5 \cdot 3 \cdot 1} - \frac{8 \cdot 6 \cdot 4 \cdot 2}{9 \cdot 7 \cdot 5 \cdot 3 \cdot 1}\right) \\
    &= 6\pi\left(\frac{48}{105} - \frac{384}{945}\right) \\
    &= 6\pi\left(\frac{144}{315} - \frac{128}{315}\right) \\
    &= 6\pi\cdot\frac{16}{315} \\
    &= \textcolor{green}{ \frac{32\pi}{105} }
\end{aligned}
\textbf{【補足：Green の公式による確認】}
\text{（補足）面積は Green の公式 }A=\oint x\,dy\text{ を用いても求められる。}

\textbf{【背景】}
\text{この問題は、曲線 } y = \sin x \left( 0 \leq x \leq \displaystyle \frac{\pi}{2} \right) \text{を } y \text{ 軸の周りに回転させてできる回転体の体積を求める問題である。}
\text{実際、回転体の体積は }
\begin{aligned}
      \displaystyle  V =  \pi \int_0^{1} Y(x)^2 dy \\
      =  \pi \int_0^{\frac{\pi}{2}} x^2 \frac {dy}{dx} dx \\
      =  \pi \int_0^{\frac{\pi}{2}} x^2 \cos x \, dx
      \end{aligned}
\text{ で与えられる。}
\textbf{【解法】}
\text{部分積分を用いる。}
\begin{aligned}
\int_0^{\frac{\pi}{2}} x^2 \cos x \, dx &= \int_0^{\frac{\pi}{2}} x^2 \cdot (\sin x)' \, dx \\
&= \left[x^2 \sin x\right]_0^{\frac{\pi}{2}} - \int_0^{\frac{\pi}{2}} \sin x \cdot 2x \, dx \\
&= \left(\displaystyle \frac{\pi}{2}\right)^2 \cdot 1 - 0 - 2\int_0^{\frac{\pi}{2}} x \sin x \, dx \\
&= \displaystyle \frac{\pi^2}{4} - 2\textcolor{blue} {\int_0^{\frac{\pi}{2}} x \sin x \, dx}
\end{aligned}
\text{次に、} \displaystyle \int_0^{\frac{\pi}{2}} x \sin x \, dx \text{ を部分積分する。}
\begin{aligned}
\textcolor{blue} {\int_0^{\frac{\pi}{2}} x \sin x \, dx} &= \int_0^{\frac{\pi}{2}} x \cdot (-\cos x)' \, dx \\
&= \left[-x \cos x\right]_0^{\frac{\pi}{2}} + \int_0^{\frac{\pi}{2}} \cos x \, dx \\
&= -\displaystyle\frac{\pi}{2} \cdot 0 + 0 + \left[\sin x\right]_0^{\frac{\pi}{2}} \\
&= \textcolor{blue} {1}
\end{aligned}
\text{したがって、}
\begin{aligned}
\int_0^{\frac{\pi}{2}} x^2 \cos x \, dx &= \displaystyle \frac{\pi^2}{4} - 2 \cdot \textcolor{blue} {1} \\
&= \displaystyle \frac{\pi^2}{4} - 2
\end{aligned}

\textbf{【方針】}
\text{これは } f(x)=3^{x} \text{ の } x=0 \text{ での微分係数である}
\textbf{【解答】}
\begin{aligned}
      \lim_{x\to 0}\frac{3^{x}-1}{x}
      &= \lim_{x\to 0}\frac{3^{x}-3^{0}}{x-0} \\[6pt]
      &= \lim_{x\to 0}\frac{f(x)-f(0)}{x-0} \\[6pt]
      &= f^{\prime}(0) \\[6pt]
      &= (3^{x})' \Big|_{x=0} \\[6pt]
      &= (e^{x\log 3})'\Big|_{x=0} \\[6pt]
      &= e^{x\log 3} \cdot \log 3 \Big|_{x=0} \\[6pt]
      &= e^{0} \cdot \log 3 \\[6pt]
      &= \log 3
      \end{aligned}

\textbf{【ポイント】}
