\textbf{【途中式変形】}
\begin{aligned}
&\ \ a^2(b-c) + b^2(c-a) + c^2(a-b) \\
&= a^2(b-c) - a b^2 + b^2 c + a c^2 - c^2 b \\
&= a^2(b-c) - a(b^2- c^2) + (b^2 c - c^2 b) \\
&= a^2(b-c) - a(b-c)(b+c) + bc(b-c) \\
&= (b-c)\bigl(a^2 - (b+c)a + bc\bigr) \\
&= (b-c)(a-b)(a-c) \\
&= -(a-b)(b-c)(c-a)
\end{aligned}

\textbf{【解説】}
\text{無限級数} \displaystyle \sum_{k=1}^{\infty} a_k= 2+(-2+2)+(-2+2)+\cdots \text{ の収束の定義より、まず部分和} S_n \text{を考えると、}
\text{ここで、} a_1 = 2, \ a_2 = -2+2 = 0, \ a_3 = -2+2 = 0, \ \ldots \text{ である。}
\begin{aligned}
        S_n &= 2+(-2+2)+(-2+2)+\cdots+(-2+2) \\[6pt]
        &= 2+0+0+\cdots+0 \\[6pt]
        &= 2
      \end{aligned}
\text{したがって、部分和の数列} S_n \text{ は } (2,2,2,2,\cdots) \text{ となる。}
\text{よって、無限級数} \displaystyle \sum_{k=1}^{\infty} a_k= 2+(-2+2)+(-2+2)+\cdots \text{ は } 2 \text{ に収束する。}

\textbf{【方針】}
\text{半角公式 } \cos^2 x=\displaystyle\frac{1+\cos 2x}{2} \text{ を用いる。}
\textbf{【解説】}
\begin{aligned}
\displaystyle &\int_0^{\frac {\pi}{2}}\cos^2 x\,dx\\
=& \displaystyle \int_0^{  \frac{\pi}{2}}\displaystyle\frac{1+\cos 2x}{2}\,dx\\
=& \displaystyle\frac{1}{2}\displaystyle \int_0^{  \frac{\pi}{2}}1\,dx+\displaystyle\frac{1}{2}\displaystyle \int_0^{  \frac{\pi}{2}}\cos 2x\,dx\\
=& \displaystyle\frac{1}{2}\left[x\right]_0^{  \frac{\pi}{2}}+\displaystyle\frac{1}{2}\left[\displaystyle\frac{\sin 2x}{2}\right]_0^{  \frac{\pi}{2}}\\
=& \displaystyle\frac{1}{2}\left(\displaystyle\frac{\pi}{2}-0\right)+\displaystyle\frac{1}{2}\left(\displaystyle\frac{\sin \pi}{2}-\displaystyle\frac{\sin 0}{2}\right)\\
=& \displaystyle\frac{\pi}{4}+\displaystyle\frac{1}{2}\left(\displaystyle\frac{0}{2}-\displaystyle\frac{0}{2}\right)\\
=& \displaystyle\frac{\pi}{4}
\end{aligned}
\textbf{【補足】}
\sin^2 \text{の計算も同様。}

\textbf{【方針】}
\text{和積の公式を用いて、} \sin A + \sin B \text{ を積の形に変形する。}
\textbf{【ポイント】}
\begin{aligned}
\sin A + \sin B &= 2\sin\displaystyle\frac{A+B}{2}\cos\displaystyle\frac{A-B}{2} \\
\sin A - \sin B &= 2\cos\displaystyle\frac{A+B}{2}\sin\displaystyle\frac{A-B}{2}
\end{aligned}
\textbf{【解説】}
\text{和積の公式より、}
\begin{aligned}
\sin 3x + \sin x &= 2\sin\displaystyle\frac{3x+x}{2}\cos\displaystyle\frac{3x-x}{2} \\
&= 2\sin 2x \cos x
\end{aligned}
\text{したがって、元の方程式は、}
\begin{aligned}
&\ \ \ \ \ 2\sin 2x \cos x = 0 \\
&\Leftrightarrow \sin 2x \cos x = 0 \\
&\Leftrightarrow \sin 2x = 0 \text{ または } \cos x = 0
\end{aligned}
\textbf{【場合分け】}
\text{（1）} \sin 2x = 0 \text{ の場合}
\begin{aligned}
&\ \ \ \ \ \sin 2x = 0 \\
&\Leftrightarrow 2x = n\pi \quad (n \text{ は整数}) \\
&\Leftrightarrow x = \displaystyle\frac{n\pi}{2}
\end{aligned}
0 \leq x < 2\pi \text{ より、} \textcolor{green}{x = 0, \displaystyle\frac{\pi}{2}, \pi, \displaystyle\frac{3\pi}{2}}
\text{（2）} \cos x = 0 \text{ の場合}
\begin{aligned}
&\ \ \ \ \ \cos x = 0 \\
&\Leftrightarrow x = \displaystyle\frac{\pi}{2} + n\pi \quad (n \text{ は整数})
\end{aligned}
0 \leq x < 2\pi \text{ より、} \textcolor{green}{x = \displaystyle\frac{\pi}{2}, \displaystyle\frac{3\pi}{2}}
\text{（1）と（2）を合わせて、}
x = 0, \displaystyle\frac{\pi}{2}, \pi, \displaystyle\frac{3\pi}{2}

\textcolor{brown}{\large{【力学】}}
\text{• 力学の空気抵抗を受ける質点の自由落下は} v^{\prime}(t) = -\displaystyle \frac{k}{m}v(t) + g \text{ でモデル化され、速度は指数関数的に}\ \displaystyle \frac{mg}{k} \text{に収束する。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• 直流電圧を印加したRL回路について、キルヒホッフの第二法則を適用すると、微分方程式}
      LI^{\prime}(t) + RI(t) = V \text{を得られ、両辺をコイルの自己インダクタンス}L \text{で割ると、問題の式の形に帰着される。電流の値は指数関数的}\ \displaystyle \frac{V}{R} \text{に収束する。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{空気抵抗を受ける自由落下の運動方程式:} \ mv^{\prime}(t) = -kv(t)+mg
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } 3 \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } \displaystyle \frac 2 3 \leftrightarrow \displaystyle \frac{mg}{k} \text{(終端速度)}
\text{• } 2 \leftrightarrow \displaystyle \frac{mg}{m} = g \text{（重力加速度）}
\text{• } f(0)=1 \leftrightarrow v_0=1 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RL回路(直流):} \ LI^{\prime}(t) + RI(t) = V
\text{• } f(t) \leftrightarrow I(t) \text{（電流）}
\text{• } 3 \leftrightarrow \displaystyle \frac{R}{L} \text{（時定数の逆数）}
\text{• } 2 \leftrightarrow \displaystyle \frac{V}{L} \text{（電圧 ÷ インダクタンス）}
\text{• } \displaystyle \frac 2 3 \leftrightarrow \displaystyle \frac{V}{R} \text{（定常電流）}
\text{• } f(0)=1 \leftrightarrow I_0=1 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t) + 3f(t) = 2
\text{両辺に}e^{3t}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{3t}f^{\prime}(t) + 3e^{3t}f(t) = 2e^{3t}
\text{積の微分より}
\Leftrightarrow (e^{3t}f(t))' = 2e^{3t}
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\begin{aligned}
&\Leftrightarrow \int_0^t (e^{3s}f(s))'\,ds = \int_0^t 2e^{3s}\,ds\\[5pt]
&\Leftrightarrow [e^{3s}f(s)]_{0}^{t} = \left[\displaystyle \frac{2}{3}e^{3s}\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ e^{3t}f(t) - e^0 f(0) = \displaystyle \frac{2}{3}e^{3t} - \displaystyle \frac{2}{3}e^0\\[5pt]
&\Leftrightarrow \ e^{3t}f(t) = f(0) + \displaystyle \frac{2}{3}(e^{3t}-1)
\end{aligned}
\text{初期条件より} f(0) = 1 \text{なので、}
\Leftrightarrow \ e^{3t}f(t) = 1 + \displaystyle \frac{2}{3}(e^{3t}-1)
\Leftrightarrow \ e^{3t}f(t) = \displaystyle \frac{2}{3}e^{3t} + \displaystyle \frac{1}{3}
\Leftrightarrow \ f(t) = \displaystyle \frac{2}{3} + \displaystyle \frac{1}{3}e^{-3t}
\text{この解は目標値}\displaystyle \frac 2 3 \text{への指数関数的収束で、時定数 }\displaystyle \frac{1}{3}\text{ で収束する。}

\textbf{【方針】}
\text{階差数列 } b_n = a_{n+1} - a_n = 2n + 1 \text{ を用いて一般項を求める。}
\textbf{【解法】}
\text{ } \textcolor{blue}{n \ge 2} \textcolor{blue}{ のとき}
\begin{aligned}
    &\ \ \ \ \ a_n = a_1 + \displaystyle \sum_{k=1}^{n-1} (a_{k+1} - a_k) \\
    &\Leftrightarrow a_n = 1 + \displaystyle \sum_{k=1}^{n-1} (2k + 1) \\
    &\Leftrightarrow a_n = 1 + 2 \displaystyle \sum_{k=1}^{n-1} k + \displaystyle \sum_{k=1}^{n-1} 1 \\
    &\Leftrightarrow a_n = 1 + 2 \cdot \displaystyle \frac{(n-1)n}{2} + (n-1) \\
    &\Leftrightarrow a_n = 1 + n(n-1) + n - 1 \\
    &\Leftrightarrow a_n = n^2 - n + n \\
    &\Leftrightarrow a_n = n^2
    \end{aligned}
\text{ } \textcolor{blue}{n = 1} \textcolor{blue}{ のとき}
a_1 = 1 = 1^2
\text{よって} a_n \text{はまとめて、} a_n = n^2 (n \ge 1)\text{と書ける。}

\textbf{【方針】}
\text{三角置換 } x = 3\tan\theta \text{ を用いて、被積分関数を簡略化する。}
\textbf{【解説】}
\text{ } x = 3\tan\theta \text{ とおくと、}
\begin{aligned}
x = 0 &\Rightarrow 0 = 3\tan\theta \Rightarrow \theta = 0\\[5pt]
x = 3 &\Rightarrow 3 = 3\tan\theta \Rightarrow \tan\theta = 1 \Rightarrow \theta = \frac{\pi}{4}
\end{aligned}
\text{また、}
\begin{aligned}\begin{cases}
dx = 3(\tan\theta)' \, d\theta = 3 \cdot \frac{1}{\cos^2\theta} \, d\theta = 3(1+\tan^2\theta) \, d\theta\\[5pt]
\sqrt{x^2+9} = 3\sqrt{1+\tan^2\theta}
\end{cases}\end{aligned}
\text{であるので}
\begin{aligned}
\int_{0}^{3} \frac{dx}{\sqrt{x^2+9}}
&= \int_{\theta=0}^{\theta=\frac{\pi}{4}} \frac{3(1+\tan^2\theta)\,d\theta}{3\sqrt{1+\tan^2\theta}}\\[5pt]
&= \int_{0}^{\frac{\pi}{4}} \frac{1+\tan^2\theta}{\sqrt{1+\tan^2\theta}} \, d\theta\\[5pt]
&= \int_{0}^{\frac{\pi}{4}} \sqrt{1+\tan^2\theta} \, d\theta\\[5pt]
&= \int_{0}^{\frac{\pi}{4}} \frac{1}{\cos\theta} \, d\theta\\[5pt]
&= \int_{0}^{\frac{\pi}{4}} \frac{\cos\theta}{\cos^2\theta} \, d\theta\\[5pt]
&= \textcolor{blue}{\int_{0}^{\frac{\pi}{4}} \frac{\cos\theta}{1-\sin^2\theta} \, d\theta}
\end{aligned}
\text{ } u = \sin\theta \text{ とおくと、} du = \cos\theta \, d\theta \text{ であり、}
\begin{aligned}
\theta = 0 &\Rightarrow u = 0\\[5pt]
\theta = \frac{\pi}{4} &\Rightarrow u = \frac{\sqrt{2}}{2}
\end{aligned}
\begin{aligned}
 &\ \ \ \ \ \textcolor{blue}{\int_{0}^{\frac{\pi}{4}} \frac{\cos\theta}{1-\sin^2\theta} \, d\theta}\\[5pt]
&= \int_{0}^{\frac{\sqrt{2}}{2}} \frac{du}{1-u^2}\\[5pt]
&= \int_{0}^{\frac{\sqrt{2}}{2}} \frac{1}{2}\left(\frac{1}{1-u} + \frac{1}{1+u}\right) du\\[5pt]
&= \frac{1}{2}\left[-\log|1-u| + \log|1+u|\right]_{0}^{\frac{\sqrt{2}}{2}}\\[5pt]
&= \frac{1}{2}\log\left|\frac{1+u}{1-u}\right|_{0}^{\frac{\sqrt{2}}{2}}\\[5pt]
&= \frac{1}{2}\log\left(\frac{1+\frac{\sqrt{2}}{2}}{1-\frac{\sqrt{2}}{2}}\right)\\[5pt]
&= \frac{1}{2}\log\left(\frac{2+\sqrt{2}}{2-\sqrt{2}}\right)\\[5pt]
&= \frac{1}{2}\log\left(\frac{(2+\sqrt{2})^2}{4-2}\right)\\[5pt]
&= \frac{1}{2}\log\left(\frac{6+4\sqrt{2}}{2}\right)\\[5pt]
&= \frac{1}{2}\log(3+2\sqrt{2})\\[5pt]
&= \frac{1}{2} \log\left(\left(1+\sqrt{2}\right)^2\right)\\[5pt]
&=\log(1+\sqrt{2})
\end{aligned}

\textbf{【方針】}
\text{区分求積と円の一部である事を用いるとよい。}
\begin{aligned}
        &\lim_{n\to\infty}\frac{1}{n}\displaystyle \sum_{k=-n}^{n}\sqrt{1-\left(\frac{k}{n}\right)^{2}} \\[6pt]
        =& \int_{-1}^{1}\sqrt{1-x^{2}}\,dx \\[6pt]
