\textbf{【方針】}
\text{両辺に } 2 \cdot 3^x \text{ をかけて整理し、} 3^x = t \text{ とおいて2次方程式に帰着させる。}
\textbf{【解説】}
\text{元の方程式の両辺に } 2 \cdot 3^x \text{ をかけると、}
\begin{aligned}
&\ \ \ \ \ \displaystyle\frac{3^x + 3^{-x}}{2} = 5 \\
&\Leftrightarrow 3^x + 3^{-x} = 10 \\
&\Leftrightarrow 3^x + \displaystyle\frac{1}{3^x} = 10 \\
&\Leftrightarrow (3^x)^2 + 1 = 10 \cdot 3^x \\
&\Leftrightarrow (3^x)^2 - 10 \cdot 3^x + 1 = 0
\end{aligned}
\text{ここで、} 3^x = t \text{ とおくと、} t > 0 \text{ であり、}
\begin{aligned}
&\ \ \ \ \ t^2 - 10t + 1 = 0
\end{aligned}
\text{2次方程式の解の公式より、}
\begin{aligned}
t &= \displaystyle\frac{10 \pm \sqrt{10^2 - 4 \cdot 1 \cdot 1}}{2 \cdot 1} \\
&= \displaystyle\frac{10 \pm \sqrt{100 - 4}}{2} \\
&= \displaystyle\frac{10 \pm \sqrt{96}}{2} \\
&= \displaystyle\frac{10 \pm 4\sqrt{6}}{2} \\
&= 5 \pm 2\sqrt{6}
\end{aligned}
\text{ここで、} t = 3^x > 0 \text{ なので、} t = 5 + 2\sqrt{6} \text{ または } t = 5 - 2\sqrt{6} \text{ である。}
\text{（1）} 3^x = 5 + 2\sqrt{6} \text{ の場合}
\begin{aligned}
&\ \ \ \ \ 3^x = 5 + 2\sqrt{6} \\
&\Leftrightarrow x = \log_3(5 + 2\sqrt{6})
\end{aligned}
\text{（2）} 3^x = 5 - 2\sqrt{6} \text{ の場合}
\text{ここで、共役同士を掛け算すると、}
\begin{aligned}
&(5 + 2\sqrt{6})(5 - 2\sqrt{6}) \\
= & 5^2 - (2\sqrt{6})^2 \\
= & 25 - 24 = 1
\end{aligned}
\text{したがって、} 5 - 2\sqrt{6} = \displaystyle\frac{1}{5 + 2\sqrt{6}} \text{ である。}
\begin{aligned}
&\ \ \ \ \ x = \log_3(5 - 2\sqrt{6}) \\
&\Leftrightarrow x = \log_3\displaystyle\frac{1}{5 + 2\sqrt{6}} \\
&\Leftrightarrow x = -\log_3(5 + 2\sqrt{6})
\end{aligned}
\text{したがって、} x = \pm \log_3(5 + 2\sqrt{6}) \text{ が解である。}
\textbf{【補足】}
\text{この問題は、底 } 3 \text{ を自然対数の底 } e = 2.718\ldots \text{ に変えると、双曲線関数 } \cosh x = \displaystyle\frac{e^x + e^{-x}}{2} \text{ に対する方程式となる。}
\text{また、} \cosh x \text{ は } \displaystyle\int \sqrt{x^2+1} dx \text{ などの置換積分に関連して登場する関数である。}

\textbf{【方針】}
\text{関数 } \displaystyle \frac{1}{\sqrt{x}} \text{ の積分を使って級数を評価する。}
\textbf{【解答】}
\text{各 } k \text{ に対して、区間 } [k, k+1] \text{ で } \displaystyle \frac{1}{\sqrt{k}} \geq \frac{1}{\sqrt{x}} \ (k \leq x \leq k+1) \text{ が成り立つ。}
\text{したがって、}
\begin{aligned}
      \frac{1}{\sqrt{k}} &\geq \int_{k}^{k+1}\frac{1}{\sqrt{x}}\,dx
      \end{aligned}
\text{よって、}
\begin{aligned}
      \displaystyle \sum_{k=1}^{n}\frac{1}{\sqrt{k}} &\geq \displaystyle \sum_{k=1}^{n}\int_{k}^{k+1}\frac{1}{\sqrt{x}}\,dx \\[6pt]
      &= \int_{1}^{n+1}\frac{1}{\sqrt{x}}\,dx \\[6pt]
      &= \left[2\sqrt{x}\right]_{1}^{n+1} \\[6pt]
      &= 2\sqrt{n+1} - 2\sqrt{1} \\[6pt]
      &= 2\sqrt{n+1} - 2
      \end{aligned}
\text{したがって、}\displaystyle 2\sqrt{n+1} - 2 \leq \displaystyle \sum_{k=1}^{n}\frac{1}{\sqrt{k}}
\text{左辺 } 2\sqrt{n+1} - 2 \text{ は } n \to \infty \text{ で発散するので、}\displaystyle \lim_{n\to\infty}\displaystyle \sum_{k=1}^{n}\frac{1}{\sqrt{k}} = \infty \text{（発散）}

\textbf{【方針】}
\text{半角公式 } \sin^2 x=\displaystyle\frac{1-\cos 2x}{2} \text{ を用いて、基本的な定積分に帰着する。}
\textbf{【解説】}
\begin{aligned}
\displaystyle &\int_0^{\pi}\sin^2 x\,dx\\
=& \displaystyle \int_0^{\pi}\displaystyle\frac{1-\cos 2x}{2}\,dx\\
=& \displaystyle\frac{1}{2}\displaystyle \int_0^{\pi}1\,dx-\displaystyle\frac{1}{2}\displaystyle \int_0^{\pi}\cos 2x\,dx\\
=& \displaystyle\frac{1}{2}\left[x\right]_0^{\pi}-\displaystyle\frac{1}{2}\left[\displaystyle\frac{\sin 2x}{2}\right]_0^{\pi}\\
=& \displaystyle\frac{1}{2}\left(\pi-0\right)-\displaystyle\frac{1}{2}\left(\displaystyle\frac{\sin 2\pi}{2}-\displaystyle\frac{\sin 0}{2}\right)\\
=& \displaystyle\frac{1}{2}\pi-\displaystyle\frac{1}{2}\left(\displaystyle\frac{0}{2}-\displaystyle\frac{0}{2}\right)\\
=& \displaystyle\frac{\pi}{2}
\end{aligned}

\textcolor{brown}{\large{【力学】}}
\text{• 力学の空気抵抗下での一定外力運動は} mx'' + kx' = mg \text{ でモデル化される。}
\text{• 速度は指数関数的に終端速度} \displaystyle \frac{mg}{k} \text{ に収束する。終端速度に近くになると、外力と抵抗力がつり合った、等速直線運動に近似できる。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{空気抵抗下での一定外力運動:} \ mx^{\prime\prime}(t) + kx^{\prime}(t) = mg
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } a \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } b \leftrightarrow \displaystyle \frac{mg}{m} = g \text{（重力加速度）}
\text{• } f_0 \leftrightarrow x_0 \text{（初期位置）}
\text{• } v_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【解法】}}
f^{\prime\prime}(t) + af^{\prime}(t) = b
\textcolor{green}{1.\ } \textcolor{green}{一階線形非斉次に帰着}
\text{置換：}u(t) = f^{\prime}(t)\text{ とおくと、}
\Leftrightarrow \ u^{\prime}(t) + au(t) = b
\textcolor{green}{2.\ } \textcolor{green}{積分因子法で} \textcolor{green}{u} \textcolor{green}{を求める}
\text{両辺に}e^{at}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{at}u^{\prime}(t) + ae^{at}u(t) = be^{at}
\text{積の微分より}
\Leftrightarrow (e^{at}u(t))' = be^{at}
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\begin{aligned}
&\Leftrightarrow \int_0^t (e^{as}u(s))'\,ds = \int_0^t be^{as}\,ds\\[5pt]
&\Leftrightarrow [e^{as}u(s)]_{0}^{t} = \left[\displaystyle \frac{b}{a}e^{as}\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ e^{at}u(t) - e^0 u(0) = \displaystyle \frac{b}{a}e^{at} - \displaystyle \frac{b}{a}e^0\\[5pt]
&\Leftrightarrow \ e^{at}u(t) = u(0) + \displaystyle \frac{b}{a}(e^{at}-1)
\end{aligned}
\text{初期条件より} u(0) = v_0 \text{なので、}
\Leftrightarrow \ e^{at}u(t) = v_0 + \displaystyle \frac{b}{a}(e^{at}-1)
\Leftrightarrow \ e^{at}u(t) = \displaystyle \frac{b}{a}e^{at} + v_0 - \displaystyle \frac{b}{a}
\Leftrightarrow \ u(t) = \displaystyle \frac{b}{a} + \left(v_0-\displaystyle \frac{b}{a}\right)e^{-at}
\textcolor{green}{3.\ } \textcolor{green}{f} \textcolor{green}{を求める}
\text{元の変数に戻す：}f^{\prime}(t) = u(t)\text{ より}
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\begin{aligned}
&\Leftrightarrow \int_0^t f^{\prime}(s)\,ds = \int_0^t u(s)\,ds\\[5pt]
&\Leftrightarrow [f(s)]_{0}^{t} = \int_0^t \left[\displaystyle \frac{b}{a} + \left(v_0-\displaystyle \frac{b}{a}\right)e^{-as}\right]ds\\[5pt]
&\Leftrightarrow \ f(t) - f(0) = \left[\displaystyle \frac{b}{a}s\right]_{0}^{t} + \left(v_0-\displaystyle \frac{b}{a}\right)\left[-\displaystyle \frac{1}{a}e^{-as}\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ f(t) = f(0) + \displaystyle \frac{b}{a}t - 0 + \left(v_0-\displaystyle \frac{b}{a}\right)\left(-\displaystyle \frac{1}{a}e^{-at} + \displaystyle \frac{1}{a}e^0\right)
\end{aligned}
\text{初期条件より} f(0) = f_0 \text{なので、}
\Leftrightarrow \ f(t) = f_0 + \displaystyle \frac{b}{a}t + \left(v_0-\displaystyle \frac{b}{a}\right)\left(-\displaystyle \frac{1}{a}e^{-at} + \displaystyle \frac{1}{a}\right)
\Leftrightarrow \ f(t) = f_0 + \displaystyle \frac{b}{a}t - \displaystyle \frac{v_0-\displaystyle \frac{b}{a}}{a}e^{-at} + \displaystyle \frac{v_0-\displaystyle \frac{b}{a}}{a}
\Leftrightarrow \ f(t) = f_0 + \displaystyle \frac{v_0-\displaystyle \frac{b}{a}}{a} + \displaystyle \frac{b}{a}t - \displaystyle \frac{v_0-\displaystyle \frac{b}{a}}{a}e^{-at}
\text{この解は、時定数 }a\text{ で指数関数的に}f_0 + \displaystyle \frac{v_0-\displaystyle \frac{b}{a}}{a} + \displaystyle \frac{b}{a}t\text{の一次関数に収束する。}

