\text{よって、} \lim_{h\to +0}\left(1+\frac{1}{h}\right)^{h} =\lim_{u\to\infty}\left(1+u\right)^{\frac{1}{u}} \text{この対数を取ると、}
\begin{aligned}
      \log\left(\lim_{u\to\infty}(1+u)^{\frac{1}{u}}\right)
      &=\lim_{u\to\infty}\log\left((1+u)^{\frac{1}{u}}\right) \\[6pt]
      &=\textcolor{blue}{\lim_{u\to\infty}\frac{\log(1+u)}{u}\cdots(1)}
      \end{aligned}
\text{ここで、} \displaystyle \frac{\log(1+u)}{u} = \frac{\log(1+u)}{1+u}\cdot\frac{1+u}{u}
\text{とすると、既知の極限 } \displaystyle\lim_{u\to\infty}\frac{\log(1+u)}{1+u}=0,\ \lim_{u\to\infty}\frac{1+u}{u}=1 \text{ より、}\textcolor{blue}{(1)は}\textcolor{blue}{\displaystyle \lim_{u\to\infty}\frac{\log(1+u)}{u}} =  0 \cdot 1= 0
\text{したがって、} \displaystyle \log\left(\lim_{u\to\infty}(1+u)^{\frac{1}{u}}\right) = 0 \text{ より、} \displaystyle \lim_{u\to\infty}(1+u)^{\frac{1}{u}} = 1

