  &\quad (f^{\prime\prime}(t) - f_p^{\prime\prime}(t)) + 2(f^{\prime}(t) - f_p^{\prime}(t)) + 4(f(t) - f_p(t)) = 0
  \end{aligned}
\text{平行移動：} g(t) = f(t) - f_p(t) \text{ とおくと、} g^{\prime\prime}(t) + 2g^{\prime}(t) + 4g(t) = 0
\textcolor{blue}{すなわち、} \textcolor{blue}{g(t)} \textcolor{blue}{ は微分方程式 } \textcolor{blue}{g^{\prime\prime}(t) + 2g^{\prime}(t) + 4g(t) = 0} \textcolor{blue}{ の解である。}
\textcolor{green}{3.\ } \textcolor{green}{g} \textcolor{green}{の初期条件を求める}
f_p(t) = 5\sin(2t)\text{ より、}
\begin{aligned}
  g(0) &= f(0) - f_p(0) \\[5pt]
  &= 0 - 5\sin(0) \\[5pt]
  &= 0
  \end{aligned}
\text{次に、}f_p^{\prime}(t)\text{ を計算する：}
\begin{aligned}
  f_p^{\prime}(t) &= 5 \cdot 2\cos(2t) = 10\cos(2t)
  \end{aligned}
\text{したがって、}
\begin{aligned}
  g^{\prime}(0) &= f^{\prime}(0) - f_p^{\prime}(0) \\[5pt]
  &= 0 - 10\cos(0) \\[5pt]
  &= 0 - 10 \\[5pt]
  &= -10
  \end{aligned}
\textcolor{green}{4.\ } \textcolor{green}{問題12の公式を適用して} \textcolor{green}{g(t)} \textcolor{green}{を求める}
\text{微分方程式 }g^{\prime\prime}(t) + 2g^{\prime}(t) + 4g(t) = 0\text{ について、}\textcolor{blue}{方針通り、放電RLC回路の公式を適用する。}
\text{問題12の公式より、}g(t) = e^{-\beta t}\left(g(0)\cos(\sqrt{\omega_0^2-\beta^2}t) + \frac{g^{\prime}(0)+\beta g(0)}{\sqrt{\omega_0^2-\beta^2}}\sin(\sqrt{\omega_0^2-\beta^2}t)\right)
\beta = 1,\ \omega_0^2 = 4,\ g(0) = 0,\ g^{\prime}(0) = -10 \quad \text{を公式に代入して、}
\begin{aligned}
  g(t) &=  e^{-\beta t}\left(g(0)\cos(\sqrt{\omega_0^2-\beta^2}t) + \frac{g^{\prime}(0)+\beta g(0)}{\sqrt{\omega_0^2-\beta^2}}\sin(\sqrt{\omega_0^2-\beta^2}t)\right)\\[5pt]
  &= e^{-t}\left(0 \cdot \cos(\sqrt{3}t) + \frac{-10 + 1 \cdot 0}{\sqrt{3}}\sin(\sqrt{3}t)\right) \\[5pt]
