\textbf{【方針】}
\sin^3 x=\sin x(1-\cos^2 x)\text{ として } u=\cos x \text{ に置換し、多項式の原始関数に帰着する。}
\textbf{【ポイント】}
\begin{aligned}
&\sin^3 x = \sin x(1-\cos^2 x)\\[5pt]
&u = \cos x \Rightarrow du = -\sin x \, dx
\end{aligned}
\textbf{【解説】}
\begin{aligned}
\int_{0}^{\frac{\pi}{6}} \sin^3 x \, dx
&= \int_{0}^{\frac{\pi}{6}} (1-\cos^2 x)\sin x \, dx\\[5pt]
&= \int_{u=\cos 0}^{u=\cos(\pi/6)} (1-u^2)(-du)\\[5pt]
&= \int_{u=1}^{u=\displaystyle\frac{\sqrt{3}}{2}} (u^2-1) \, du\\[5pt]
&= \int_{\frac{\sqrt{3}}{2}}^{1} (1-u^2) \, du\\[5pt]
&= \left[u - \displaystyle\frac{u^3}{3}\right]_{\displaystyle\frac{\sqrt{3}}{2}}^{1}\\[5pt]
&= \left(1 - \displaystyle\frac{1}{3}\right) - \left(\displaystyle\frac{\sqrt{3}}{2} - \displaystyle\frac{(\sqrt{3}/2)^3}{3}\right)\\[5pt]
&= \displaystyle\frac{2}{3} - \displaystyle\frac{\sqrt{3}}{2} + \displaystyle\frac{(\sqrt{3}/2)^3}{3}\\[5pt]
&= \displaystyle\frac{2}{3} - \displaystyle\frac{\sqrt{3}}{2} + \displaystyle\frac{\displaystyle\frac{3\sqrt{3}}{8}}{3}\\[5pt]
&= \displaystyle\frac{2}{3} - \displaystyle\frac{\sqrt{3}}{2} + \displaystyle\frac{\sqrt{3}}{8}\\[5pt]
&= \displaystyle\frac{2}{3} - \displaystyle\frac{4\sqrt{3}}{8} + \displaystyle\frac{\sqrt{3}}{8}\\[5pt]
&= \displaystyle\frac{2}{3} - \displaystyle\frac{3\sqrt{3}}{8}\\[5pt]
&= \displaystyle\frac{16}{24} - \displaystyle\frac{9\sqrt{3}}{24}
\end{aligned}
\text{ここで、} \cos\displaystyle\frac{\pi}{6} = \displaystyle\frac{\sqrt{3}}{2}, \ \sin\displaystyle\frac{\pi}{6} = \displaystyle\frac{1}{2} \text{ である。}
\text{別の方法として、不定積分を先に求める：}
\begin{aligned}
\int \sin^3 x \, dx &= \int \sin x (1-\cos^2 x) \, dx\\[5pt]
&= \int \sin x \, dx - \int \sin x \cos^2 x \, dx\\[5pt]
&= -\cos x + \displaystyle\frac{\cos^3 x}{3} + C
\end{aligned}
\text{したがって、}
\begin{aligned}
\int_{0}^{\frac{\pi}{6}} \sin^3 x \, dx &= \left[-\cos x + \displaystyle\frac{\cos^3 x}{3}\right]_{0}^{\frac{\pi}{6}}\\[5pt]
&= \left(-\cos\displaystyle\frac{\pi}{6} + \displaystyle\frac{\cos^3(\pi/6)}{3}\right) - \left(-\cos 0 + \displaystyle\frac{\cos^3 0}{3}\right)\\[5pt]
&= \left(-\displaystyle\frac{\sqrt{3}}{2} + \displaystyle\frac{(\sqrt{3}/2)^3}{3}\right) - \left(-1 + \displaystyle\frac{1}{3}\right)\\[5pt]
&= -\displaystyle\frac{\sqrt{3}}{2} + \displaystyle\frac{\displaystyle\frac{3\sqrt{3}}{8}}{3} + 1 - \displaystyle\frac{1}{3}\\[5pt]
&= -\displaystyle\frac{\sqrt{3}}{2} + \displaystyle\frac{\sqrt{3}}{8} + \displaystyle\frac{2}{3}\\[5pt]
&= -\displaystyle\frac{4\sqrt{3}}{8} + \displaystyle\frac{\sqrt{3}}{8} + \displaystyle\frac{2}{3}\\[5pt]
&= -\displaystyle\frac{3\sqrt{3}}{8} + \displaystyle\frac{2}{3}\\[5pt]
&= \displaystyle\frac{16}{24} - \displaystyle\frac{9\sqrt{3}}{24}
\end{aligned}
\text{したがって、}
\begin{aligned}
\int_{0}^{\frac{\pi}{6}} \sin^3 x \, dx = \displaystyle\frac{16-9\sqrt{3}}{24}
\end{aligned}

\textbf{【方針】} 
      \text{特性方程式} x^2 - x - 6 = 0 \text{を解き、解}r_1,r_2\text{を求めて、}a_n = A r_1^{n-1} + B r_2^{n-1} \text{と置き、初期条件を代入して実数} A,B\text{を求める。(なぜこう置く事ができるかは解説の命題1を参照。)}
\textbf{【解法】}
\text{特性方程式 }
\begin{aligned}
      &\ \ \ \ \ r^2 - r - 6 = 0 \\
      &\Leftrightarrow (r - 3)(r + 2) = 0 \\
      &\Leftrightarrow r = 3 \text{ または } r = -2
      \end{aligned}
\text{よって命題(1)より、解は} a_n = A \cdot 3^{\,n-1} + B \cdot (-2)^{\,n-1}\text{と表す事ができる。}
\text{(2) 初期条件から } A,B \text{ を求める}
\text{初期条件 } a_1=1,\ a_2=2 \text{ より、}
\begin{aligned}
      \begin{cases}
        1 = A + B \\
        2 = 3A - 2B
      \end{cases}
      & \Leftrightarrow
      \begin{cases}
        A = \displaystyle \frac{4}{5} \\[6pt]
        B = \displaystyle \frac{1}{5}
      \end{cases}
      \end{aligned}
\textcolor{green}{したがって} \textcolor{green}{a_n = \displaystyle \frac{4}{5} \cdot 3^{\,n-1} + \displaystyle \frac{1}{5}(-2)^{\,n-1}}
\textbf{【命題1】}
\text{漸化式 } a_{n+2} + p a_{n+1} + q a_n = 0 \text{と、実数の初期条件} a_1,a_2\text{が与えられたとする。}
\text{この時、漸化式に対して定まる二次方程式} r^2 + p r + q = 0 \text{の互いに異なる2根を} r_1,r_2 \text{とすると、一般項} a_n \textcolor{green}{はある実数} \textcolor{green}{A,B} \textcolor{green}{を用いて}
\textcolor{green}{a_n = A r_1^{\,n-1} + B r_2^{\,n-1}} \textcolor{green}{ と表す事ができる。}
\text{※ ただし、} A,B \text{ は初期条件}a_1, a_2\text{によって定まる実数。}
\textbf{【証明】}
\text{解と係数の関係より、}r_1+r_2= -p, r_1r_2= q\text{であるから、次の式が成り立つ：}
\begin{aligned}
  &a_{n+2}-r_1 a_{n+1} = r_2\bigl(a_{n+1}-r_1 a_n\bigr)\\
  &a_{n+2}-r_2 a_{n+1} = r_1\bigl(a_{n+1}-r_2 a_n\bigr)
\end{aligned}
\text{ここで}
b_n := a_{n+1}-r_1 a_n,\quad  c_n := a_{n+1}-r_2 a_n
\text{と置くと，上の恒等式から}
  b_{n+1}=r_2 b_n,\quad c_{n+1}=r_1 c_n
\text{が成り立つ。したがって初項}
  b_1 = a_2 - r_1 a_1,\quad  c_1 = a_2 - r_2 a_1
\text{に対して、}
  b_n = b_1 r_2^{\,n-1},\quad c_n = c_1 r_1^{\,n-1} \quad\cdots(1)
\text{である。}

\text{一方，} b_n,c_n \text{の定義から}
\begin{aligned}
  c_n - b_n &= (a_{n+1}-r_2 a_n) - (a_{n+1}-r_1 a_n)\\[5pt]
            &= (r_1-r_2)a_n
\end{aligned}
\text{よって}
a_n = \displaystyle \frac{c_n-b_n}{r_1-r_2}
\text{(1) を適用して展開すると，}
\quad = \displaystyle \frac{c_1 r_1^{\,n-1} - b_1 r_2^{\,n-1}}{r_1-r_2}
\text{ここで } b_1,c_1 \text{ の値を代入すると，}
\quad = \displaystyle \frac{(a_2 - r_2 a_1)\,r_1^{\,n-1} - (a_2 - r_1 a_1)\,r_2^{\,n-1}}{r_1-r_2}
\text{右辺について，}
\displaystyle A=\displaystyle \frac{a_2 - r_2 a_1}{r_1-r_2},\quad  B=\displaystyle \frac{r_1 a_1-a_2 }{r_1-r_2}
\text{とおくと明らかに}A,B\text{は実数で、}
  a_n = A r_1^{\,n-1} + B r_2^{\,n-1}
\text{の形で書ける。これで命題の主張が示された。Q.E.D}
\textbf{【注意】}
r_1=r_2 \text{ の重解の場合は上の議論は使えないため別扱いで，重根 } r \text{ に対して解が} a_n=(A+Bn)r^{\,n-1} \text{の形になることを別途示す必要がある。}

