\text{【力学】}
\text{• 力学の空気抵抗を受ける質点の自由落下は} v^{\prime}(t) = -\displaystyle \frac{k}{m}v(t) + g \text{ でモデル化され、速度は指数関数的に}\ \displaystyle \frac{mg}{k} \text{に収束する。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• 直流電圧を印加したRL回路について、キルヒホッフの第二法則を適用すると、微分方程式}
      LI^{\prime}(t) + RI(t) = V \text{を得られ、両辺をコイルの自己インダクタンス}L \text{で割ると、問題の式の形に帰着される。電流の値は指数関数的}\ \displaystyle \frac{V}{R} \text{に収束する。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{空気抵抗を受ける自由落下の運動方程式:} \ mv^{\prime}(t) = -kv(t)+mg
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } a \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } \frac b a \leftrightarrow \displaystyle \frac{mg}{k} \text{(終端速度)}
\text{• } b \leftrightarrow \displaystyle \frac{mg}{m} = g \text{（重力加速度）}
\text{• } f_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RL回路(直流):} \ LI^{\prime}(t) + RI(t) = V
\text{• } f(t) \leftrightarrow I(t) \text{（電流）}
\text{• } a \leftrightarrow \displaystyle \frac{R}{L} \text{（時定数の逆数）}
\text{• } b \leftrightarrow \displaystyle \frac{V}{L} \text{（電圧 ÷ インダクタンス）}
\text{• } \frac b a \leftrightarrow \displaystyle \frac{V}{R} \text{（定常電流）}
\text{• } f_0 \leftrightarrow I_0 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t) + af(t) = b
\text{両辺に}e^{at}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{at}f^{\prime}(t) + ae^{at}f(t) = be^{at}
\text{積の微分より}
\Leftrightarrow (e^{at}f(t))' = be^{at}
\text{両辺を }0\text{ から }t\text{ まで定積分：}
\begin{aligned}
&\Leftrightarrow \int_0^t (e^{as}f(s))'\,ds = \int_0^t be^{as}\,ds\\[5pt]
&\Leftrightarrow [e^{as}f(s)]_{0}^{t} = \left[\displaystyle \frac{b}{a}e^{as}\right]_{0}^{t}\\[5pt]
&\Leftrightarrow \ e^{at}f(t) - e^0 f(0) = \displaystyle \frac{b}{a}e^{at} - \displaystyle \frac{b}{a}e^0\\[5pt]
&\Leftrightarrow \ e^{at}f(t) = f(0) + \displaystyle \frac{b}{a}(e^{at}-1) 
\end{aligned}
\text{初期条件より} f(0) = f_0 \text{なので、}
\Leftrightarrow \ e^{at}f(t) = f_0 + \displaystyle \frac{b}{a}(e^{at}-1)
\Leftrightarrow \ e^{at}f(t) = \displaystyle \frac{b}{a}e^{at} + f_0 - \displaystyle \frac{b}{a}
\Leftrightarrow \ f(t) = \displaystyle \frac{b}{a}+\left(f_0-\displaystyle \frac{b}{a}\right)e^{-at}
\text{この解は目標値}\displaystyle \frac{b}{a} \text{ への指数関数的収束で、時定数は}\displaystyle \frac{1}{a}\text{ である。}

\textbf{【方針】}
\text{ }x \le y \le z \text{ の条件を使って } x+y+z \le 3z \text{として、} x,y \text{を有限個の候補に落とし込む。}
\textbf{【解法】}
\text{ }x \le y \le z \text{ より、}
\begin{aligned}
    xyz &= x + y + z \\
    &\le z + z + z = 3z
    \end{aligned}
xyz \le 3z \Leftrightarrow xy \le 3 \text{ である。}
\text{従って、} x \le y \text{も含めて考慮すると、}(x,y) = (1,1), (1,2), (1,3), (2,2) \text{ が候補である。}
\text{方程式にこれらの候補を代入すると、}
\textcolor{blue}{(x,y) = (1,1)}\textcolor{blue}{ の場合}
\text{方程式に } x = 1, y = 1 \text{ を代入すると、}
\begin{aligned}
    1 \cdot 1 \cdot z &= 1 + 1 + z
    \end{aligned}
\textcolor{red}{この式は成立しない。}
\textcolor{blue}{(x,y) = (1,2)}\textcolor{blue}{ の場合}
\text{方程式に } x = 1, y = 2 \text{ を代入すると、}
\begin{aligned}
    1 \cdot 2 \cdot z &= 1 + 2 + z \\
    \Leftrightarrow 2z &= 3 + z \\
    \Leftrightarrow z &= 3
    \end{aligned}
\text{よって、} \textcolor{green}{(x,y,z) = (1,2,3)} \text{ は解。}
\textcolor{blue}{(x,y) = (1,3)}\textcolor{blue}{ の場合}
\text{方程式に } x = 1, y = 3 \text{ を代入すると、}
\begin{aligned}
    1 \cdot 3 \cdot z &= 1 + 3 + z \\
    \Leftrightarrow 3z &= 4 + z \\
    \Leftrightarrow 2z &= 4 \\
    \Leftrightarrow z &= 2
    \end{aligned}
\text{しかしながら問題文より、}y \le z \text{ よって、} \textcolor{red}{この式は成立しない。}
\textcolor{blue}{(x,y) = (2,2)}\textcolor{blue}{ の場合}
\text{方程式に } x = 2, y = 2 \text{ を代入すると、}
\begin{aligned}
    2 \cdot 2 \cdot z &= 2 + 2 + z \\
    \Leftrightarrow 4z &= 4 + z \\
    \Leftrightarrow 3z &= 4 \\
    \Leftrightarrow z &= \frac{4}{3}
    \end{aligned}
\text{しかしながら問題文より、}y \le z \text{ よって、} \textcolor{red}{この式は成立しない。}
\textcolor{blue}{(x,y) = (2,3)}\textcolor{blue}{ の場合}
\text{方程式に } x = 2, y = 3 \text{ を代入すると、}
\begin{aligned}
    2 \cdot 3 \cdot z &= 2 + 3 + z \\
    \Leftrightarrow 6z &= 5 + z \\
    \Leftrightarrow 5z &= 5 \\
    \Leftrightarrow z &= 1
    \end{aligned}
\text{しかしながら問題文より、}y \le z \text{ よって、} \textcolor{red}{この式は成立しない。}
\text{よって、整数解は }(x,y,z)=(1,2,3) \text{のみ。}

