\textbf{【方針】}
\text{直線 } y=\displaystyle\frac{4x}{\pi} \text{ と比較し、はさみうちの原理を用いて評価する。}
\textbf{【解答】}
\text{まず、次の命題を用いる：}
\text{【命題】}
0 \leq x \leq \displaystyle\frac{\pi}{4} \text{ のとき、} \tan x \leq \displaystyle\frac{4x}{\pi} \text{ が成り立つ。}
\text{この命題により、} 0 \leq x \leq \displaystyle\frac{\pi}{4} \text{ のとき、}
\begin{aligned}
    0 \leq \tan^{2n}x \leq \left(\frac{4x}{\pi}\right)^{2n}
    \end{aligned}
\text{が成り立つ。したがって、積分について、}
\begin{aligned}
    0 \leq \int_{0}^{\frac{\pi}{4}}\tan^{2n}x\,dx &\leq \int_{0}^{\frac{\pi}{4}}\left(\frac{4x}{\pi}\right)^{2n}\,dx \\[6pt]
    &= \left(\frac{4}{\pi}\right)^{2n}\int_{0}^{\frac{\pi}{4}}x^{2n}\,dx \\[6pt]
    &= \left(\frac{4}{\pi}\right)^{2n} \cdot \frac{\left(\frac{\pi}{4}\right)^{2n+1}}{2n+1} \\[6pt]
    &= \frac{\pi}{4(2n+1)}
    \end{aligned}
\text{したがって、}
\begin{aligned}
    0 < \int_{0}^{\frac{\pi}{4}}\tan^{2n}x\,dx < \frac{\pi}{4(2n+1)}
    \end{aligned}
\text{右辺は } n \to \infty \text{ で } 0 \text{ に収束するので、はさみうちの原理より、}
\begin{aligned}
    \lim_{n\to\infty}\int_{0}^{\frac{\pi}{4}}\tan^{2n}x\,dx = 0
    \end{aligned}
\textbf{【命題の証明】}
\text{区間 }[0,\frac{\pi}{4}]\text{ において }
\displaystyle \frac{d^2}{dx^2}(\tan x) =\frac{2\sin x}{\cos^{3}x}\ge0 \text{ が成り立つ。}
\text{したがって }\tan x\text{ はこの区間で下に凸であり、} 0\text{ と }\tfrac{\pi}{4}\text{ を結ぶ直線の下に位置する。}

