\textbf{【方針】}
\text{すべての項を } 2^x \text{ で表し、} 2^x = t \text{ とおいて2次方程式に帰着させる。}
\textbf{【解説】}
\text{各項を } 2^x \text{ で表すと、}
\begin{aligned}
2^{2x+1} &= 2 \cdot 2^{2x} \\
&= 2 \cdot (2^x)^2 \\
2^{x+2} &= 2^2 \cdot 2^x \\
&= 4 \cdot 2^x
\end{aligned}
\text{したがって、元の方程式は、}
\begin{aligned}
&\ \ \ \ \ 2 \cdot (2^x)^2 - 4 \cdot 2^x = 2^x - 2 \\
&\Leftrightarrow 2 \cdot (2^x)^2 - 4 \cdot 2^x - 2^x + 2 = 0 \\
&\Leftrightarrow 2 \cdot (2^x)^2 - 5 \cdot 2^x + 2 = 0
\end{aligned}
\text{ここで、} 2^x = t \text{ とおくと、} t > 0 \text{ であり、}
\begin{aligned}
&\ \ \ \ \ 2t^2 - 5t + 2 = 0 \\
&\Leftrightarrow (2t - 1)(t - 2) = 0 \\
&\Leftrightarrow t = \displaystyle\frac{1}{2} \text{ または } t = 2
\end{aligned}
\textbf{【場合分け】}
\text{（1）} 2^x = \displaystyle\frac{1}{2} \text{ の場合}
\begin{aligned}
&\ \ \ \ \ 2^x = \displaystyle\frac{1}{2} \\
&\Leftrightarrow 2^x = 2^{-1} \\
&\Leftrightarrow x = -1
\end{aligned}
\text{（2）} 2^x = 2 \text{ の場合}
\begin{aligned}
&\ \ \ \ \ 2^x = 2 \\
&\Leftrightarrow 2^x = 2^1 \\
&\Leftrightarrow x = 1
\end{aligned}
\text{（1）と（2）より、} x = -1, 1

\textbf{【方針】}
\displaystyle \int a^x\,dx = \dfrac{a^x}{\log a} + C\ (a>0, a\neq 1) \text{の公式を用いる。}
\textbf{【ポイント】}
\text{公式は合成関数の微分で導出可能である。すなわち、} 2^x = e^{\log 2 x}= (e^{x})^{\log 2 } \text{と見る。}
\textbf{【解説】}
\begin{aligned}
\displaystyle \int_{ \frac{1}{4}}^{ \frac{1}{2}} 2^x\,dx
&= \left[\displaystyle \frac{2^x}{\log 2}\right]_{x=\displaystyle \frac{1}{4}}^{x=\displaystyle \frac{1}{2}} \\
&= \displaystyle \frac{2^{ \frac{1}{2}}}{\log 2} - \displaystyle \frac{2^{ \frac{1}{4}}}{\log 2} \\
&= \displaystyle \frac{2^{ \frac{1}{2}} - 2^{ \frac{1}{4}}}{\log 2} \\
&= \displaystyle \frac{\sqrt{2} - 2^{ \frac{1}{4}}}{\log 2}
\end{aligned}
\textbf{【補足-合成関数として考えた公式導出】}
\begin{aligned}
(2^x)' &= \left((e^{\log 2})^x\right)'\\
&=  \left(e^{x \log 2}\right)'\\
&=  (e^{x \log 2}) \left(x \log 2\right)'\\
&=  2^x \log 2\\
&=  (\log 2) 2^x\\
\end{aligned}
\text{よって、}\left(\displaystyle \frac {2^x}{\log 2}\right)' = 2^x
\text{よって、}\displaystyle \int 2^x\,dx = \displaystyle \frac{2^x}{\log 2} + C

\textbf{【方針】}
t=\log x \,\textbf{ と置き、}
        x=e^{t},\,dx=e^{t}dt
\textbf{で指数関数に直したのち、部分積分を行う。}
\textbf{【ポイント】}
\textbf{【解説】}
\begin{aligned}
\displaystyle \int_{1}^{e}\displaystyle \frac{\log x}{x^{2}}\,dx
=&\displaystyle \int_{t=0}^{1} t\cdot e^{-2t}\cdot e^{t}\,dt\\
=&\displaystyle \int_{0}^{1} t\,e^{-t}\,dt.
\end{aligned}
\text{ここで部分積分を用いる}
\begin{aligned}
&\displaystyle \int_{0}^{1} t\,e^{-t}\,dt\\
=&\displaystyle \int_{0}^{1} t\,(-e^{-t})'\,dt\\
=&\left[-t\,e^{-t}\right]_{0}^{1}+\displaystyle \int_{0}^{1} e^{-t}\,dt\\
=&\left(-e^{-1}-0\right)+\left[-e^{-t}\right]_{0}^{1}\\
=&-\displaystyle \frac{1}{e}+\left(-e^{-1}+1\right)\\
=&1-\displaystyle \frac{2}{e}
\end{aligned}

