\textcolor{brown}{\large{【力学】}}
\text{• 力学においては、} mx^{\prime\prime}(t) + kx(t) = mg \text{ の形でよく登場する。これは重力下のばね-質量系の運動を表す。重力による平衡位置シフトが起きる。}
\text{【電磁気学】}
\text{• 電磁気学においては、} LQ^{\prime\prime}(t) + \displaystyle \frac{Q(t)}{C} = V \text{ の形でよく登場する。これは直流電圧が印加されたLC回路を表す。}
\text{• 定常電流：} CV \text{（定常状態でのコンデンサに蓄えられる電荷）}
\text{【問題の記号と力学における記号の対応】}
\text{重力下のばねの運動:} \ mx^{\prime\prime}(t) + kx(t) = mg
\text{• } f(t) \leftrightarrow x(t) \text{（位置）}
\text{• } f^{\prime}(t) \leftrightarrow v(t) \text{（速度）}
\text{• } f^{\prime\prime}(t) \leftrightarrow a(t) \text{（加速度）}
\text{• } \omega_0 \leftrightarrow \sqrt{\displaystyle \frac{k}{m}} \text{（固有角周波数）}
\text{• } G \leftrightarrow \displaystyle \frac{mg}{m} = g \text{（重力加速度）}
\text{• } \frac{G}{\omega_0^2} \leftrightarrow \displaystyle \frac{mg}{k} \text{（平衡点。振動中心。重力とばねの力がつり合う位置）}
\text{• } f(0)=f_0 \leftrightarrow x_0=f_0 \text{（初期位置）}
\text{• } f^{\prime}(0)=v_0 \leftrightarrow v_0=v_0 \text{（初期速度）}
\text{【問題の記号と電磁気学における記号の対応】}
\text{直流LC回路:} \ LQ^{\prime\prime}(t) + \displaystyle \frac{Q(t)}{C} = V
\text{• } f(t) \leftrightarrow Q(t) \text{コンデンサに蓄えられた電荷）}
\text{• } f^{\prime}(t) \leftrightarrow I(t) \text{（電流）}
\text{• } f^{\prime\prime}(t) \leftrightarrow I' \text{（電流変化率）}
\text{• } \omega_0 \leftrightarrow \displaystyle \frac{1}{\sqrt{LC}} \text{（固有角周波数）}
\text{• } G \leftrightarrow \displaystyle \frac{V}{L} \text{（電圧 ÷ インダクタンス）}
\text{• } f(0)=f_0 \leftrightarrow Q_0=f_0 \text{（コンデンサに蓄えられた初期電荷）}
\text{• } f^{\prime}(0)=v_0 \leftrightarrow I_0=v_0 \text{（初期電流）}
\textbf{【方針】}
\text{定数解を求めて平行移動し、外力がない場合の微分方程式の解の式を利用する。}
\textcolor{brown}{\large{【解法】}}
\textcolor{green}{右辺の定数項が無い(同次方程式)の場合の公式}
\text{微分方程式 } f^{\prime\prime}(t) = -\omega^2 f(t) \text{ に対する初期値問題}
f(0) = A_0,\quad f^{\prime}(0) = v_0
\text{の解は}
f(t) = A_0\cos(\omega t) + \displaystyle \frac{v_0}{\omega}\sin(\omega t)
\text{である。（問題6で導出済み）}
\textcolor{blue}{この公式を用いて、本問を解く。}
f^{\prime\prime}(t) = -\omega_0^2 f(t) + G
\textcolor{green}{1.\ } \textcolor{green}{定数解を探す}
\text{定数解}f_s\text{を求める。}f_s'' = 0\text{より}
0 = -\omega_0^2 f_s + G \quad \Leftrightarrow \quad f_s = \displaystyle \frac{G}{\omega_0^2}
\textcolor{green}{2.\ } \textcolor{green}{平行移動で新たな関数} \textcolor{green}{g} \textcolor{green}{を置いて同次化(バネのみの力による単振動の式にする)}
\text{平行移動：}g(t) = f(t) - f_s \text{ とおく。}
\begin{aligned}
      g^{\prime\prime}(t) &= f^{\prime\prime}(t) = -\omega_0^2 f(t) + G \\[5pt]
      &= -\omega_0^2(g(t) + f_s) + G \\[5pt]
      &= -\omega_0^2 g(t) - \omega_0^2 \cdot \displaystyle \frac{G}{\omega_0^2} + G \\[5pt]
      &= -\omega_0^2 g(t)
      \end{aligned}
\text{よって }g^{\prime\prime}(t) = -\omega_0^2 g(t) \text{（同次化完了）}
\textcolor{green}{3.\ } \textcolor{green}{g} \textcolor{green}{の初期条件を求める}
\begin{aligned}
      g(0) &= f(0) - f_s = f_0 - \displaystyle \frac{G}{\omega_0^2} \\[5pt]
      g^{\prime}(0) &= f^{\prime}(0) = v_0
      \end{aligned}
\textcolor{green}{4.\ } \textcolor{green}{公式を適用し} \textcolor{green}{g} \textcolor{green}{を求める}
g^{\prime\prime}(t) = -\omega_0^2 g(t) \text{で、}g(0) = f_0 - \displaystyle \frac{G}{\omega_0^2},\ g^{\prime}(0) = v_0
\text{公式より}
\begin{aligned}
      g(t) &= g(0)\cos(\omega_0 t) + \displaystyle \frac{g^{\prime}(0)}{\omega_0}\sin(\omega_0 t) \\[5pt]
      &= \Big(f_0 - \displaystyle \frac{G}{\omega_0^2}\Big)\cos(\omega_0 t) + \displaystyle \frac{v_0}{\omega_0}\sin(\omega_0 t)
      \end{aligned}
\textcolor{green}{5.\ } \textcolor{green}{g} \textcolor{green}{から} \textcolor{green}{f} \textcolor{green}{を求める}
f(t) = g(t) + f_s = \Big(f_0 - \displaystyle \frac{G}{\omega_0^2}\Big)\cos(\omega_0 t) + \displaystyle \frac{v_0}{\omega_0}\sin(\omega_0 t) + \displaystyle \frac{G}{\omega_0^2}
\quad = \displaystyle \frac{G}{\omega_0^2}+\Big(f_0-\displaystyle \frac{G}{\omega_0^2}\Big)\cos(\omega_0 t)+\displaystyle \frac{v_0}{\omega_0}\sin(\omega_0 t)

\textbf{【方針】}
\begin{aligned}
&\tan x=\dfrac{\sin x}{\cos x} \text{ と書き，} u=\cos x \text{ の置換で } \displaystyle \int \tan x\,dx \text{ を求める。}\\
&\text{得られた原始関数に } x=\displaystyle \frac{\pi}{6},\displaystyle \frac{\pi}{4} \text{ を代入して定積分を評価する。}
\end{aligned}
\textbf{【ポイント】}
\begin{aligned}
&u=\cos x , \ \ du=-\sin x\,dx \\[4pt]
&\displaystyle \int \tan x\,dx = \displaystyle \int \displaystyle \frac{\sin x}{\cos x}\,dx \\
&\phantom{\displaystyle \int \tan x\,dx } = \displaystyle \int \displaystyle \frac{-1}{u}\,du \\
&\phantom{\displaystyle \int \tan x\,dx } = -\displaystyle \int \displaystyle \frac{1}{u}\,du \\
&\phantom{\displaystyle \int \tan x\,dx } = -\log |u| + C \\
&\phantom{\displaystyle \int \tan x\,dx } = -\log |\cos x| + C \\[6pt]
&\cos \displaystyle \frac{\pi}{4} =\displaystyle \frac{\sqrt{2}}{2},\quad
\cos \displaystyle \frac{\pi}{6}=\displaystyle \frac{\sqrt{3}}{2} \\
&\text{区間 } \left[\displaystyle \frac{\pi}{6},\displaystyle \frac{\pi}{4}\right] \text{ では } \cos x>0 \text{ なので } |\cos x|=\cos x \text{ としてよい。}
\end{aligned}
\textbf{【解説】}
\begin{aligned}
\displaystyle \int_{ \frac{\pi}{6}}^{ \frac{\pi}{4}} \tan x\,dx
&= \Biggl[-\log |\cos x|\Biggr]_{x= \frac{\pi}{6}}^{x= \frac{\pi}{4}} \\
&= \Biggl[-\log \cos x \Biggr]_{x= \frac{\pi}{6}}^{x= \frac{\pi}{4}} \\
&= \left(-\log \cos\displaystyle \frac{\pi}{4}\right) - \left(-\log \cos\displaystyle \frac{\pi}{6}\right) \\
&= -\log\!\left(\displaystyle \frac{\sqrt{2}}{2}\right) + \log\!\left(\displaystyle \frac{\sqrt{3}}{2}\right) \\
&= \log\!\left(\displaystyle \frac{\displaystyle \frac{\sqrt{3}}{2}}{\displaystyle \frac{\sqrt{2}}{2}}\right) \\
&= \log\!\left(\displaystyle \frac{\sqrt{3}}{\sqrt{2}}\right) \\
&= \log\!\left(\sqrt{\displaystyle \frac{3}{2}}\right) \\
&= \displaystyle \frac{1}{2}\,\log\!\left(\displaystyle \frac{3}{2}\right)
\end{aligned}

\textcolor{brown}{\large{【力学】}}
\text{• 力学の空気抵抗のみを受ける質点の速度減衰は} v^{\prime}(t) + \displaystyle \frac{k}{m}v(t) = 0 \text{ でモデル化される。速度は指数関数的に減少する。}
\textcolor{brown}{\large{【電磁気学】}}
\text{• 電磁気学のRC放電回路においては、キルヒホッフの第二法則より、}
      RI(t) + \displaystyle \frac{Q(t)}{C} = 0 \text{が成り立ち、これを}R\text{で割って両辺微分すると、}
      I^{\prime}(t) + \displaystyle \frac{1}{RC}I(t) = 0 \text{ を得る。これはRC回路の放電過程の回路に流れる電流の時間変化を表す。電流は指数関数的に減少する。}
\textcolor{brown}{\large{【問題の記号と力学における記号の対応】}}
\text{空気抵抗下での質点の運動:} \ v^{\prime}(t) + \displaystyle \frac{k}{m}v(t) = 0
\text{• } f(t) \leftrightarrow v(t) \text{（速度）}
\text{• } a \leftrightarrow \displaystyle \frac{k}{m} \text{（抵抗係数 ÷ 質量）}
\text{• } f_0 \leftrightarrow v_0 \text{（初期速度）}
\textcolor{brown}{\large{【問題の記号と電磁気学における記号の対応】}}
\text{RC回路の放電:} \ I^{\prime}(t) + \displaystyle \frac{1}{RC}I(t) = 0
\text{• } f(t) \leftrightarrow I(t) \text{（電流）}
\text{• } a \leftrightarrow \displaystyle \frac{1}{RC} \text{（時定数の逆数）}
\text{• } f_0 \leftrightarrow I_0 \text{（初期電流）}
\textcolor{brown}{\large{【解法】}}
f^{\prime}(t)+a\,f(t) = 0
\text{両辺に}e^{at}\text{ を掛ける。(こうやるとうまくいく)}
\Leftrightarrow \ e^{at}f^{\prime}(t) + ae^{at}f(t) = 0
\text{積の微分より}
\Leftrightarrow (e^{at}f(t))' = 0
\text{両辺を }0 \text{ から }t \text{ まで定積分する。}
\begin{aligned}
&\Leftrightarrow \int_0^t (e^{as}f(s))'\,ds = \int_0^t 0\,ds\\[5pt]
&\Leftrightarrow [e^{as}f(s)]_{0}^{t} = 0\\[5pt]
&\Leftrightarrow \ e^{at}f(t) - e^0 f(0) = 0\\[5pt]
&\Leftrightarrow \ e^{at}f(t) = f(0)
\end{aligned}
\text{初期条件より} f(0) = f_0 \text{なので、}
\begin{aligned}
&\Leftrightarrow \ e^{at}f(t) = f_0\\[5pt]
&\Leftrightarrow \ f(t) = f_0e^{-at}
\end{aligned}
\text{この解は指数減衰関数で、減衰定数 }a\text{ で指数関数的に減少する。}

\textbf{【方針】}
\text{共役な数} \sqrt{n^{2}+n}+n \text{を分母分子に掛けて不定形を解消する。}
\textbf{【解答】}
\begin{aligned}
      \displaystyle & \sqrt{n^{2}+n}-n \\[6pt]
      =& \frac{\Bigl(\sqrt{n^{2}+n}-n\Bigr)\Bigl(\sqrt{n^{2}+n}+n\Bigr)}{\sqrt{n^{2}+n}+n} \\[6pt]
      =& \frac{n^{2} +n - n^2}{\sqrt{n^{2}+n}+n} \\[6pt]
      =& \frac{n}{\sqrt{n^{2}+n}+n} \\[6pt]
      =& \frac{1}{\sqrt{1+\frac{1}{n}}+1} \ \underset{n\to\infty}{\longrightarrow}\  \displaystyle \frac{1}{1 + 1} = \frac 1 2
    \end{aligned}

\textbf{【方針】}
\sin x + \cos x = t \text{ とおいて、} \sin x \cos x \text{ を } t \text{ で表し、2次方程式に帰着させる。}
\textbf{【ポイント】}
\begin{aligned}
(\sin x + \cos x)^2 &= \sin^2 x + 2\sin x \cos x + \cos^2 x \\
&= 1 + 2\sin x \cos x
\end{aligned}
\text{よって、} \sin x \cos x = \displaystyle\frac{t^2 - 1}{2} \text{ である。}
\textbf{【解説】}
\sin x + \cos x = t \text{ とおくと、}
\begin{aligned}
\sin x \cos x &= \displaystyle\frac{(\sin x + \cos x)^2 - 1}{2} \\
&= \displaystyle\frac{t^2 - 1}{2}
\end{aligned}
\text{元の方程式は、}
\begin{aligned}
&\ \ \ \ \ \sin x \cos x + \sqrt{2}(\sin x + \cos x) = \displaystyle\frac{1}{2} \\
&\Leftrightarrow \displaystyle\frac{t^2 - 1}{2} + \sqrt{2}t = \displaystyle\frac{1}{2} \\
&\Leftrightarrow t^2 - 1 + 2\sqrt{2}t = 1 \\
&\Leftrightarrow t^2 + 2\sqrt{2}t - 2 = 0
\end{aligned}
\text{2次方程式の解の公式より、}
\begin{aligned}
t &= \displaystyle\frac{-2\sqrt{2} \pm \sqrt{(2\sqrt{2})^2 - 4 \cdot 1 \cdot (-2)}}{2 \cdot 1} \\
&= \displaystyle\frac{-2\sqrt{2} \pm \sqrt{8 + 8}}{2} \\
&= \displaystyle\frac{-2\sqrt{2} \pm \sqrt{16}}{2} \\
&= \displaystyle\frac{-2\sqrt{2} \pm 4}{2} \\
&= -\sqrt{2} \pm 2
\end{aligned}
\text{すなわち、} t = 2 - \sqrt{2} \text{ または } t = -2 - \sqrt{2}
\textbf{【範囲の確認】}
\text{三角関数の合成より、}
\begin{aligned}
\sin x + \cos x &= \sqrt{2}\sin\left(x + \displaystyle\frac{\pi}{4}\right)
\end{aligned}
\text{よって、} |\sin x + \cos x| = |t| \leq \sqrt{2} \text{ である。}
\text{ここで、}
\begin{aligned}
|2 - \sqrt{2}| &\approx |2 - 1.414| = 0.586 < \sqrt{2} \\
|-2 - \sqrt{2}| &\approx |-2 - 1.414| = 3.414 > \sqrt{2}
\end{aligned}
\text{したがって、} t = 2 - \sqrt{2} \text{ のみが有効である。}
\textbf{【解の導出】}
\text{三角関数の合成より、}
\begin{aligned}
&\ \ \ \ \ \sin x + \cos x = 2 - \sqrt{2} \\
&\Leftrightarrow \sqrt{2}\sin\left(x + \displaystyle\frac{\pi}{4}\right) = 2 - \sqrt{2} \\
&\Leftrightarrow \sin\left(x + \displaystyle\frac{\pi}{4}\right) = \displaystyle\frac{2 - \sqrt{2}}{\sqrt{2}} = \sqrt{2} - 1
\end{aligned}
\text{ここで、} \theta = x + \displaystyle\frac{\pi}{4} \text{ とおくと、}
\begin{aligned}
&\ \ \ \ \ \sin\theta = \sqrt{2} - 1 \\
&\Leftrightarrow \begin{cases}
\theta = \arcsin(\sqrt{2} - 1) + 2n\pi \quad (n \text{ は整数}) \\[8pt]
\theta = \pi - \arcsin(\sqrt{2} - 1) + 2n\pi \quad (n \text{ は整数})
\end{cases}
\end{aligned}
\text{すなわち、}
\begin{aligned}
&\ \ \ \ \ x + \displaystyle\frac{\pi}{4} = \begin{cases}
\arcsin(\sqrt{2} - 1) + 2n\pi \\[8pt]
\pi - \arcsin(\sqrt{2} - 1) + 2n\pi
\end{cases} \quad (n \text{ は整数}) \\
&\Leftrightarrow \begin{cases}
x = \arcsin(\sqrt{2} - 1) - \displaystyle\frac{\pi}{4} + 2n\pi \\[8pt]
x = \pi - \arcsin(\sqrt{2} - 1) - \displaystyle\frac{\pi}{4} + 2n\pi
\end{cases} \quad (n \text{ は整数})
\end{aligned}
0 \leq x < 2\pi \text{ の範囲では、適切な } n \text{ を選んで、}
\text{解が得られる。}

\textbf{【方針】}
\text{半角置換 } \displaystyle t = \tan\left(\frac{x}{2}\right) \text{ を用いて三角関数を多項式の分数関数にする。}
\textbf{【ポイント】}
\begin{aligned}
&\textcolor{green}{\sin x = \frac{2t}{1+t^2}, \quad dx = \frac{2\,dt}{1+t^2}}\ \ \textcolor{green}{(補足参照)}\\[5pt]
&2 + \sin x = 2 + \frac{2t}{1+t^2} = \frac{2(1+t^2) + 2t}{1+t^2} = \frac{2(t^2+t+1)}{1+t^2}
\end{aligned}
\textbf{【解説】}
\begin{aligned}
x=0 &\Rightarrow t=\tan0=0,\\[5pt]
x=\frac{\pi}{2} &\Rightarrow t=\tan\frac{\pi}{4}=1.
\end{aligned}
\begin{aligned}
\int_{0}^{\frac{\pi}{2}}\frac{dx}{2+\sin x}
&= \int_{t=0}^{t=1} \frac{1}{\frac{2(t^2+t+1)}{1+t^2}}\cdot\frac{2\,dt}{1+t^2}\\[6pt]
&= \int_{0}^{1} \frac{2\,dt}{2(t^2+t+1)}\\[6pt]
&= \int_{0}^{1} \frac{dt}{t^2+t+1}\\[6pt]
&= \int_{0}^{1} \frac{dt} {\left(t+\frac{1}{2}\right)^2 + \frac{3}{4}}\\[6pt]
&=\textcolor{blue}{\int_{0}^{1} \frac{dt}{\left(t+\frac{1}{2}\right)^2 + \left(\frac{\sqrt{3}}{2}\right)^2}}
\end{aligned}
\text{ } t + \frac{1}{2} = \frac{\sqrt{3}}{2}\tan\theta \text{ とおくと、} dt = \frac{\sqrt{3}}{2}(1+\tan^2\theta) \, d\theta \text{ であり、}
\begin{aligned}
t = 0 &\Rightarrow t + \frac{1}{2} = \frac{1}{2} \Rightarrow \frac{\sqrt{3}}{2}\tan\theta = \frac{1}{2} \Rightarrow \tan\theta = \frac{1}{\sqrt{3}} \Rightarrow \theta = \frac{\pi}{6}\\[5pt]
t = 1 &\Rightarrow t + \frac{1}{2} = \frac{3}{2} \Rightarrow \frac{\sqrt{3}}{2}\tan\theta = \frac{3}{2} \Rightarrow \tan\theta = \sqrt{3} \Rightarrow \theta = \frac{\pi}{3}
\end{aligned}
\text{したがって、}
\begin{aligned}
&=\textcolor{blue}{\int_{0}^{1} \frac{dt}{\left(t+\frac{1}{2}\right)^2 + \left(\frac{\sqrt{3}}{2}\right)^2}}\\[5pt]
&=\int_{\theta=\frac{\pi}{6}}^{\theta=\frac{\pi}{3}} \frac{\frac{\sqrt{3}}{2}(1+\tan^2\theta) \, d\theta}{\left(\frac{\sqrt{3}}{2}\tan\theta\right)^2 + \left(\frac{\sqrt{3}}{2}\right)^2}\\[5pt]
&= \int_{\theta=\frac{\pi}{6}}^{\theta=\frac{\pi}{3}} \frac{\frac{\sqrt{3}}{2}(1+\tan^2\theta) \, d\theta}{\left(\frac{\sqrt{3}}{2}\tan\theta\right)^2 + \left(\frac{\sqrt{3}}{2}\right)^2}\\[5pt]
&= \int_{\frac{\pi}{6}}^{\frac{\pi}{3}} \frac{\frac{\sqrt{3}}{2}(1+\tan^2\theta) \, d\theta}{\frac{3}{4}(\tan^2\theta + 1)}\\[5pt]
&= \int_{\frac{\pi}{6}}^{\frac{\pi}{3}} \frac{\frac{\sqrt{3}}{2}(1+\tan^2\theta) \, d\theta}{\frac{3}{4}(1+\tan^2\theta)}\\[5pt]
&= \int_{\frac{\pi}{6}}^{\frac{\pi}{3}} \frac{2}{\sqrt{3}} \, d\theta\\[5pt]
&= \frac{2}{\sqrt{3}}\left[\theta\right]_{\frac{\pi}{6}}^{\frac{\pi}{3}}\\[5pt]
&= \frac{2}{\sqrt{3}}\left(\frac{\pi}{3} - \frac{\pi}{6}\right)\\[5pt]
&= \frac{\pi}{3\sqrt{3}}
\end{aligned}
\textbf{【補足】}
\text{半角置換 } t = \tan\left(\frac{x}{2}\right) \text{ により、三角関数が } t \text{ の有理式で表せる。}
\text{ } t = \tan\left(\frac{x}{2}\right) \text{ より、} \sin\left(\frac{x}{2}\right) = t\cos\left(\frac{x}{2}\right) \text{ である。}
\text{また、} \sin^2\left(\frac{x}{2}\right) + \cos^2\left(\frac{x}{2}\right) = 1 \text{ より、}
\begin{aligned}
&t^2\cos^2\left(\frac{x}{2}\right) + \cos^2\left(\frac{x}{2}\right) = 1\\[5pt]
&\cos^2\left(\frac{x}{2}\right)(1+t^2) = 1\\[5pt]
&\textcolor{green}{\cos\left(\frac{x}{2}\right) = \frac{1}{\sqrt{1+t^2}}}, \quad \textcolor{green}{\sin\left(\frac{x}{2}\right) = \frac{t}{\sqrt{1+t^2}}}
\end{aligned}
\text{倍角の公式より、}
\begin{aligned}
&\textcolor{green}{\sin x = 2\sin\left(\frac{x}{2}\right)\cos\left(\frac{x}{2}\right) = \frac{2t}{1+t^2}}
\end{aligned}
\text{また、} t = \tan\left(\frac{x}{2}\right) \text{ を } x \text{ で微分すると、}
\begin{aligned}
&t' = \left(\tan\left(\frac{x}{2}\right)\right)' = \frac{1}{\cos^2\left(\frac{x}{2}\right)} \cdot \frac{1}{2} = \frac{1+t^2}{2}\\[5pt]
&\textcolor{green}{dx = \frac{2}{1+t^2} \, dt}
\end{aligned}

\textbf{【ポイント】}
\text{対称式で、どの文字についても次数は同じなので、任意の文字を選んで降べきに整理する。}
\textbf{【途中式変形】}
\text{ } a \text{ について整理すると、}
\begin{aligned}
 &\ \ a(b^2+c^2) + b(c^2+a^2) + c(a^2+b^2) + 2abc \\
 &= ab^2 + ac^2 + bc^2 + ba^2 + ca^2 + cb^2 + 2abc \\
 &= a^2(b+c) + a(b^2 + c^2 + 2bc) + bc(b+c) \\
 &= a^2(b+c) + a(b+c)^2 + bc(b+c) \\
 &= (b+c)\bigl(a^2 + a(b+c) + bc\bigr) \\
 &= (b+c)(a+b)(a+c) \\
 &= (a+b)(b+c)(c+a)
 \end{aligned}

\textbf{【解説】}
\text{無限級数} \displaystyle \sum_{k=1}^{\infty} a_k= 2-2+2-2+2-2+\cdots \text{ の収束の定義より、まず部分和} S_n \text{を考えると、}
\begin{aligned}
        S_{2n} &= (2-2)+(2-2)+\cdots+(2-2) = 0 \\[6pt]
        S_{2n+1} &= (2-2)+(2-2)+\cdots+(2-2)+2 = 2
      \end{aligned}
\text{したがって、部分和の数列} S_n{は } (0,2,0,2,0,2,\cdots) \text{ となり、振動する。}
\text{よって、無限級数} \displaystyle \sum_{k=1}^{\infty} a_k= 2-2+2-2+2-2+\cdots \text{ の極限は存在しない(振動する)}

\textbf{【方針】}
\text{係数 }17,29\text{ の最大公約数は }1\text{ であり、このことにより任意の }z\text{ に対して，方程式 }17x+29y+61z=3\text{ の整数解 }x,y\text{ が存在する。よって適当に }z\text{ を定め、その値に対する全ての} (x,y) \text{を求めることで一般解を求める。}
\textbf{【解法】}
\text{今，適当に 整数}z \text{ を定め，それを }\ell\text{ とする。すなわち }z=\ell \text{ とおき，方程式を}17x+29y=3-61\ell\text{ として、}\ell \text{を一つ固定してそれについて解き、一般解は全ての整数}\ell\text{を集めたものとして表す。}
\textbf{【解を1つ見つける】}
\text{まず，}17x+29y=1\text{ の解を互除法を用いて求める。}
\text{互除法により、}
\begin{aligned}
29 &= 17 \cdot 1 + 12 \\
17 &= 12 \cdot 1 + 5 \\
12 &= 5 \cdot 2 + 2 \\
5 &= 2 \cdot 2 + 1 \\
2 &= 1 \cdot 2 + 0
\end{aligned}
\text{逆算すると、}
\begin{aligned}
1 &= 5 - 2 \cdot 2 \\
&= 5 - (12 - 5 \cdot 2) \cdot 2 \\
&= 5 \cdot 5 - 12 \cdot 2 \\
&= (17 - 12) \cdot 5 - 12 \cdot 2 \\
&= 17 \cdot 5 - 12 \cdot 7 \\
&= 17 \cdot 5 - (29 - 17) \cdot 7 \\
&= 17 \cdot 12 - 29 \cdot 7
\end{aligned}
\text{よって、 } 17 \cdot 12 + 29 \cdot (-7) = 1 \text{ であるから、}
\text{1つの解は } (x, y) = (12, -7) \text{ である。}
\text{したがって両辺を，} 3-61\ell \text{倍すると、} 17x+29y=3-61\ell \text{ の解}(x_0,y_0)=(12(3-61\ell),-7(3-61\ell))\text{ が見つかる。}
\text{すなわち、} 17 \cdot 12(3-61\ell) + 29 \cdot (-7)(3-61\ell) = 3-61\ell
\textbf{【一般解の構成】}
\text{ここで、式} 17x+29y=3-61\ell \text{から} 17 \cdot 12(3-61\ell) + 29 \cdot (-7)(3-61\ell) = 3-61\ell \text{を引くと、}
\begin{aligned}
    17x + 29y &= 3-61\ell \\
    17 \cdot 12(3-61\ell) + 29 \cdot (-7)(3-61\ell) &= 3-61\ell \\
    \hline
    17(x - 12(3-61\ell)) + 29(y - (-7)(3-61\ell)) &= 0 
    \end{aligned}
17,29 \text{は互いに素なので、}
    \begin{aligned}
    \begin{cases} 
    x-12(3-61\ell) = 29k \\
    y-(-7)(3-61\ell) = -17k
    \end{cases}
    \end{aligned}
    \text{となる整数} k \text{が存在する。よって、}
\begin{aligned}
    &\ \ \ \ \ 
    \begin{cases} 
    x - 12(3-61\ell) = 29k \\
    y-(-7)(3-61\ell) = -17k
    \end{cases}\\
    &\Leftrightarrow
    \begin{cases} 
    x = 12(3 - 61\ell) + 29k = 29k + 36 - 732\ell\\
    y = -7(3 - 61\ell) - 17k = -17k - 21 + 427\ell
    \end{cases}
    \end{aligned}
\text{が与えられた、}z = \ell \text{ に対する全ての解なので、問題の方程式} 17x+29y+61z=3 \text{ の一般解は}
    \begin{cases} 
    x = 29k + 36 - 732\ell,\\
    y = -17k - 21 + 427\ell\\
    z = \ell
    \end{cases}
    \text{である。ただし、} k,\ell \text{は任意の整数。}

\textbf{【方針】}
\sin 2x=2\sin x\cos x \text{より、} \sin^2 x\cos^2 x=\left(\displaystyle\frac{\sin 2x}{2}\right)^2 \text{を使い、2乗の形にしたら半角の公式}\sin^2 2x=\displaystyle\frac{1-\cos 4x}{2}\text{を使う。}
\textbf{【解説】}
\begin{aligned}\sin^2 x\cos^2 x
=& \left(\displaystyle\frac{\sin 2x}{2}\right)^2\\
=& \displaystyle\frac{1}{4}\sin^2 2x\\
=& \displaystyle\frac{1}{4}\cdot\displaystyle\frac{1-\cos 4x}{2}\\
=& \displaystyle\frac{1}{8}\left(1-\cos 4x\right).
\end{aligned}
\begin{aligned}
\displaystyle \int_0^{\frac{\pi}{3}} \sin^2 x\cos^2 x\,dx
=& \displaystyle\frac{1}{8}\displaystyle \int_0^{\frac{\pi}{3}} \left(1-\cos 4x\right)dx\\
=& \displaystyle\frac{1}{8}\left[x-\displaystyle\frac{\sin 4x}{4}\right]_0^{\frac{\pi}{3}}\\
=& \displaystyle\frac{1}{8}\left(\displaystyle\frac{\pi}{3}-\displaystyle\frac{\sin(4\pi/3)}{4}\right)-\displaystyle\frac{1}{8}\left(0-\displaystyle\frac{\sin 0}{4}\right)\\
=& \displaystyle\frac{1}{8}\left(\displaystyle\frac{\pi}{3}-\displaystyle\frac{\sin(4\pi/3)}{4}\right)\\
=& \displaystyle\frac{1}{8}\left(\displaystyle\frac{\pi}{3}-\displaystyle\frac{-\sqrt{3}/2}{4}\right)\\
=& \displaystyle\frac{1}{8}\left(\displaystyle\frac{\pi}{3}+\displaystyle\frac{\sqrt{3}}{8}\right)\\
=& \displaystyle\frac{\pi}{24}+\displaystyle\frac{\sqrt{3}}{64}
\end{aligned}
\text{ここで、} \sin\displaystyle\frac{4\pi}{3}=\sin\left(\pi+\displaystyle\frac{\pi}{3}\right)=-\sin\displaystyle\frac{\pi}{3}=-\displaystyle\frac{\sqrt{3}}{2} \text{ である。}

\textbf{【解説】}
