x = \displaystyle\frac{\pi}{6}, \displaystyle\frac{5\pi}{6}

\textbf{【途中式変形】}
\begin{aligned}
&\ \ \ \ \ 2^{x+1} - 2^{x-1} = 3 \\
&\Leftrightarrow 2 \cdot 2^x - \displaystyle\frac{1}{2} \cdot 2^x = 3 \\
