\textbf{【方針】}
\text{対数の性質 } \log a + \log b = \log ab \text{ を用いて左辺を1つの対数にまとめる。真数条件に注意する。}
\textbf{【真数条件】}
\begin{aligned}
x + 1 > 0 \quad &\Leftrightarrow \quad x > -1 \\
x - 1 > 0 \quad &\Leftrightarrow \quad x > 1
\end{aligned}
\text{よって、} x > 1 \text{ が必要。}
\textbf{【途中式変形】}
\begin{aligned}
&\ \ \ \ \ \log_2(x+1) + \log_2(x-1) &= 3 \\
&\Leftrightarrow \log_2((x+1)(x-1)) = 3 \\
&\Leftrightarrow \log_2(x^2 - 1) = 3 \\
&\Leftrightarrow x^2 - 1 = 2^3 \\
&\Leftrightarrow x^2 - 1 = 8 \\
&\Leftrightarrow x^2 = 9 \\
&\Leftrightarrow x = \pm 3
\end{aligned}
\text{真数条件 } x > 1 \text{ より、} x = 3
